        public static (double pain, double integrity, double bleeding, double energyLoss) GetModifiers(string damageType)
        {
            double pain = 1.0;
            double integrity = 1.0;
            double bleeding = 1.0;
            double energyLoss = 1.0;

            switch (damageType.ToLower())
            {

                //BE SO CAEFUL MODIFYING THESE VALUES YOU CAN MAKE STUFF OP AS HELL

                case "piercing":
                    pain = 1.0;
                    integrity = 2.0;
                    bleeding = 0.6;
                    energyLoss = 1.5;
                    break;
                case "slashing":
                    pain = 1.1;
                    integrity = 0.9;
                    bleeding = 1.2;
                    energyLoss = 1.3;
                    break;
                case "thrashing":
                    pain = 1.5;
                    integrity = 0.3;
                    bleeding = 1.5;
                    energyLoss = 0.3;
                    break;
                case "bashing":
                    pain = 1.4;
                    integrity = 1.8;
                    bleeding = 0.3;
                    energyLoss = 1.5;
                    break;
            }

            return (pain, integrity, bleeding, energyLoss);
        }

        public static Texture2D LoadAndUpscale(GraphicsDevice graphicsDevice, ContentManager content, string assetName, int scale)
        {
            Texture2D original = content.Load<Texture2D>(assetName);
            return ScaleTexture(graphicsDevice, original, scale);
        }

        public static Texture2D ScaleTexture(GraphicsDevice graphicsDevice, Texture2D source, int scaleFactor)
        {
            int width = source.Width * scaleFactor;
            int height = source.Height * scaleFactor;

            Texture2D scaledTexture = new Texture2D(graphicsDevice, width, height);

            Color[] sourceData = new Color[source.Width * source.Height];
            source.GetData(sourceData);

            Color[] scaledData = new Color[width * height];

            for (int y = 0; y < source.Height; y++)
            {
                for (int x = 0; x < source.Width; x++)
                {
                    Color pixel = sourceData[y * source.Width + x];
                    for (int dy = 0; dy < scaleFactor; dy++)
                    {
                        for (int dx = 0; dx < scaleFactor; dx++)
                        {
                            int sx = x * scaleFactor + dx;
                            int sy = y * scaleFactor + dy;
                            scaledData[sy * width + sx] = pixel;
                        }
                    }
                }
            }

            scaledTexture.SetData(scaledData);
            return scaledTexture;
        }

