        void PickUpItems(int count)
        {
            var container = (MostRecentPartyTurnArchitect.Room != null
                ? MostRecentPartyTurnArchitect.Room.Objects
                : MostRecentPartyTurnArchitect.Block.Objects);

            var matchingItems = container
                .Where(item =>
                    item.Type == MostRecentPartyTurnArchitect.TryPickUpItemType &&
                    item.Materials.SequenceEqual(MostRecentPartyTurnArchitect.TryPickUpMaterials))
                .ToList();

            int pickedUpCount = 0;
            int tooHeavyCount = 0;
            Object firstPickedUpItem = null;

            foreach (var item in matchingItems)
            {
                if (pickedUpCount >= count)
                    break;

                if (item.Weight > 6000)
                {
                    tooHeavyCount++;
                    continue;
                }

                // Remove from room/block
                container.Remove(item);

                // Clear references
                item.Room = null;
                item.Block = null;

                MostRecentPartyTurnArchitect.IDidSomethingBadSoScanForShockMines();

                // Add to inventory
                MostRecentPartyTurnArchitect.Inventory.Add(item);

                // Track first picked item
                if (firstPickedUpItem == null)
                    firstPickedUpItem = item;

                // Market debt relief if in a market
                if (MostRecentPartyTurnArchitect.Structure != null &&
                    MostRecentPartyTurnArchitect.Structure.Type == "market")
                {
                    MostRecentPartyTurnArchitect.Structure.MarketDebtToUs -= item.Value();
                }

                // Cooldown
                MostRecentPartyTurnArchitect.CooldownCycles += 1;

                pickedUpCount++;
            }

            if (pickedUpCount == 0 && tooHeavyCount == 0)
            {
                MakeObservation(
                    "There are no matching items to pick up.",
                    Color.Yellow,
                    new EntityList<Entity>());
                return;
            }

            // Play sound once
            if (firstPickedUpItem != null)
            {
                firstPickedUpItem.PlaySound();
            }

            // Do companion messages based on first picked-up item
            if (firstPickedUpItem != null)
            {
                if (firstPickedUpItem.Imbuements.Count > 0)
                    MostRecentPartyTurnArchitect.CompanionMessage("imbuements", "");
                else if (firstPickedUpItem.CompositionContent != null ||
            (Game1.LoadedHooks.Contains(firstPickedUpItem) && firstPickedUpItem.HookedObjective.RequiredInteraction == "read") ||
            firstPickedUpItem.Type == "skill scroll" ||
            firstPickedUpItem.LetterContent != null ||
            (firstPickedUpItem.Type == "book" && firstPickedUpItem.Name != null && firstPickedUpItem.Name.StartsWith("Chapter")))
                    MostRecentPartyTurnArchitect.CompanionMessage("reading", "");
                else if (firstPickedUpItem.IsWearable)
                    MostRecentPartyTurnArchitect.CompanionMessage("wear", "");
                else if (firstPickedUpItem.IsConsumable && firstPickedUpItem.Type != "fragment")
                    MostRecentPartyTurnArchitect.CompanionMessage("consume", "");
                else if (firstPickedUpItem.Type == "invocation crystal")
                    MostRecentPartyTurnArchitect.CompanionMessage("invocationcrystal", "");
            }

            // GUI Imbuement popup if only 1 item was picked up and qualifies
            if (pickedUpCount == 1 && firstPickedUpItem != null &&
                (firstPickedUpItem.Imbuements.Count > 0 || firstPickedUpItem.IsWeapon || firstPickedUpItem.AmuletGift != ""))
            {
                Game1.IsInGui = true;
                Game1.ItemPickupGuiLines.Clear();

                if (firstPickedUpItem.Name != null && firstPickedUpItem.Imbuements.Count > 0)
                {
                    Game1.ItemPickupGuiLines.Add(
                        Game1.Capitalize(firstPickedUpItem.Name) + ", " +
                        Game1.Capitalize(firstPickedUpItem.Materials[0].Name) + " " +
                        Game1.Capitalize(firstPickedUpItem.Type));
                }
                else
                {
                    Game1.ItemPickupGuiLines.Add(
                        Game1.Capitalize(firstPickedUpItem.Materials[0].Name) + " " +
                        Game1.Capitalize(firstPickedUpItem.Type));
                }



                if (firstPickedUpItem.Materials[0].Type == "metal")
                {
                    MostRecentPartyTurnArchitect.CompanionMessage("materials", "");
                }

                if (firstPickedUpItem.Imbuements.Count == 0)
                {
                    Game1.ItemPickupGuiLines.Add("This object has no imbuements.");
                }
                else
                {
                    Game1.ItemPickupGuiLines.Add("This object has some intriguing properties.");
                    foreach (Imbuement i in firstPickedUpItem.Imbuements)
                    {
                        Game1.ItemPickupGuiLines.Add(i.GetDescription());
                    }
                }

                if(firstPickedUpItem.AmuletGift != "")
                {
                    Game1.ItemPickupGuiLines.Add("This amulet provides a divine power.");
                    Game1.ItemPickupGuiLines.Add(firstPickedUpItem.Description);
                }

                Game1.PickupConfirm.InvisibleLock = false;
                MostRecentPartyTurnArchitect.TryComment("ontreasure", 25);
            }

            if (pickedUpCount > 0)
            {
                string itemType = Game1.Capitalize(MostRecentPartyTurnArchitect.TryPickUpItemType);
                bool isPlural = pickedUpCount != 1;

                string displayName = isPlural
                    ? itemType.ToLowerInvariant().Pluralize(true)
                    : itemType.ToLowerInvariant();

                string quantity = pickedUpCount == 1
                    ? $"{("aeiou".Contains(displayName.ToLower()[0]) ? "an" : "a")} {displayName}"
                    : $"{NumberToWordsExtension.ToWords(pickedUpCount)} {displayName}";

                string pronoun = pickedUpCount > 1 ? "them" : "it";

                MakeObservation(
                    $"You pick up {quantity} and put {pronoun} in your inventory.",
                    Color.Yellow,
                    new EntityList<Entity>());
            }

            if (tooHeavyCount > 0)
            {
                string countInWords = NumberToWordsExtension.ToWords(tooHeavyCount);
                string pluralSuffix = tooHeavyCount > 1 ? "s were" : " was";

                MakeObservation(
                    $"{countInWords} item{pluralSuffix} too heavy to pick up.",
                    Color.Yellow,
                    new EntityList<Entity>());
            }


            if (MostRecentPartyTurnArchitect.CooldownCycles > 0)
            {
                IncrementAndCycleWorld();
            }
        }

