        public static Object Clone(Object baseObject)
        {
            Object clone;

            // Step 1: Subclass-aware instantiation
            if (baseObject is Door door)
            {
                clone = new Door(); // Assumes parameterless constructor exists for cloning purposes
            }
            else if (baseObject is MultiObject multi)
            {
                var clonedBoundObjects = new EntityList<Object>(multi.BoundObjects.Select(Clone).ToList());
                clone = new MultiObject(multi.Creator as Architect, clonedBoundObjects);
            }
            else
            {
                clone = new Object();
            }

            // Step 2: Copy base Object fields
            clone.Type = baseObject.Type;
            clone.Materials = new EntityList<Material>(baseObject.Materials);
            clone.Description = baseObject.Description;
            clone.IsContainer = baseObject.IsContainer;
            clone.IfTrueUseInIfFalseUseOn = baseObject.IfTrueUseInIfFalseUseOn;
            clone.YLevelInFeet = baseObject.YLevelInFeet;
            clone.YVelocity = baseObject.YVelocity;
            clone.Weight = baseObject.Weight;
            clone.Block = baseObject.Block;
            clone.Room = baseObject.Room;
            clone.HeatInCelsius = baseObject.HeatInCelsius;
            clone.IsConsumable = baseObject.IsConsumable;
            clone.IsWearable = baseObject.IsWearable;
            clone.Rarity = baseObject.Rarity;
            clone.IsBodyPart = baseObject.IsBodyPart;
            clone.MajorArteryIsSevered = baseObject.MajorArteryIsSevered;
            clone.AirborneTarget = baseObject.AirborneTarget;
            clone.AirbornePower = baseObject.AirbornePower;
            clone.AirborneCyclesToHitTarget = baseObject.AirborneCyclesToHitTarget;
            clone.Creator = baseObject.Creator;
            clone.FireSeconds = baseObject.FireSeconds;
            clone.WetCycles = baseObject.WetCycles;
            clone.DestabilizedCycles = baseObject.DestabilizedCycles;
            clone.FractalCycles = baseObject.FractalCycles;
            clone.RematerializeLocation = baseObject.RematerializeLocation;
            clone.PlantCycles = baseObject.PlantCycles;
            clone.CoverageValues = new List<(string, int)>(baseObject.CoverageValues);
            clone.Coverage = baseObject.Coverage;
            clone.CoverageName = baseObject.CoverageName;
            clone.IsWeapon = baseObject.IsWeapon;
            clone.DamageType = baseObject.DamageType;
            clone.ProjectileAerodynamic = baseObject.ProjectileAerodynamic;
            clone.Strength = baseObject.Strength;
            clone.Dissipating = baseObject.Dissipating;
            clone.Integrity = baseObject.Integrity;
            clone.IsWritable = baseObject.IsWritable;
            clone.SpecialKnowledge = baseObject.SpecialKnowledge;
            clone.IsGeneralGood = baseObject.IsGeneralGood;
            clone.CompositionContent = baseObject.CompositionContent;
            clone.Thrower = baseObject.Thrower;
            clone.Owner = baseObject.Owner;

            // Recursively clone contained objects
            clone.ContainedObjects = new EntityList<Object>();
            foreach (var contained in baseObject.ContainedObjects)
            {
                clone.ContainedObjects.Add(Clone(contained));
            }

            // Deep clone Imbuements
            clone.Imbuements = new EntityList<Imbuement>(
                baseObject.Imbuements.Select(imb =>
                    new Imbuement(imb.IsTrigger, imb.ConditionOrTrigger, imb.BuffOrResult, imb.FirstPower, imb.SecondPower, clone)
                ).ToList()
            );

            // Additional fields
            clone.LetterContent = baseObject.LetterContent;
            clone.ClothingVisible = baseObject.ClothingVisible;
            clone.SpecialLooted = baseObject.SpecialLooted;
            clone.ConsoleOn = baseObject.ConsoleOn;
            clone.LatestUpdateCycle = baseObject.LatestUpdateCycle;
            clone.Tags = new List<string>(baseObject.Tags);
            clone.DyedColor = baseObject.DyedColor;
            clone.WeaponMaximumRange = baseObject.WeaponMaximumRange;
            clone.RealityAugmented = baseObject.RealityAugmented;
            clone.TemporaryStructureStorage = baseObject.TemporaryStructureStorage;
            clone.AwareArchitects = new EntityList<Architect>(baseObject.AwareArchitects);
            clone.CarvedSymbols = new EntityList<Entity>(baseObject.CarvedSymbols);
            clone.Polished = baseObject.Polished;
            clone.Cleaned = baseObject.Cleaned;
            clone.Exposure = baseObject.Exposure;

            // Randomized fields
            clone.Rotation = Game1.r.NextDouble() * 2 * Math.PI;
            clone.Distance = Game1.FurnitureItems.Contains(clone.Type) ? Game1.r.Next(400, 500) : Game1.r.Next(200, 400);

            // Step 3: Copy subclass-specific fields

            if (clone is Door clonedDoor && baseObject is Door originalDoor)
            {
                clonedDoor.Direction = originalDoor.Direction;
                clonedDoor.Number = originalDoor.Number;
                clonedDoor.SourceRoom = originalDoor.SourceRoom;
                clonedDoor.DestinationRoom = originalDoor.DestinationRoom;
                clonedDoor.IsQuickestExit = originalDoor.IsQuickestExit;
            }

            return clone;
        }


