        private static string GetDisplayName(Entity entity)
        {
            if (entity is Object obj &&
                obj.IsBodyPart &&
                MostRecentPartyTurnArchitect.BodyParts.Contains(obj) &&
                (entity.ReferredToNames[0] == $"{MostRecentPartyTurnArchitect.Name}'s {obj.Type}" ||
                 entity.ReferredToNames[0] == $"{MostRecentPartyTurnArchitect.Name}' {obj.Type}"))
            {
                return obj.Type;
            }
            else if (entity is Structure s && s.Type.Contains("house"))
            {
                return s.Name + " (house " + s.HouseIndex.ToString() + ")";
            }
            else if (RecognizedCommands[SelectedCommand].Item2[CurrentSubjectIndex] == "entity" &&
                     !string.IsNullOrWhiteSpace(entity.Name))
            {
                return entity.Name;
            }
            else
            {
                return entity.ReferredToNames[0];
            }
        }

        public static void UpdateSubjects()
        {
            EntityList<Architect> NearbyArchitects = MostRecentPartyTurnArchitect.Room != null ? MostRecentPartyTurnArchitect.Room.Architects : MostRecentPartyTurnArchitect.Block.Architects;
            EntityList<Object> NearbyObjects = MostRecentPartyTurnArchitect.Room != null ? MostRecentPartyTurnArchitect.Room.Objects : MostRecentPartyTurnArchitect.Block.Objects;

            RelevantEntities.Clear();

            SetUpRelevantEntities(RecognizedCommands[SelectedCommand].Item2[CurrentSubjectIndex], SelectedEntities.Count > 0 ? SelectedEntities.Last() : null);

            RelevantEntities = RelevantEntities.OrderBy(e => CalculateProximityScore(e, MostRecentPartyTurnArchitect, NearbyArchitects, NearbyObjects, true)).ToList();
            MaxCommandBuilderPage = (int)Math.Ceiling((decimal)RelevantEntities.Count() / 20);
            CurrentCommandBuilderPage = 0;

            RelevantEntities.RemoveAll(e => !GetDisplayName(e).ToLower().Contains(SubjectPrompt.ToLower()));

        }

        void TakeItems(int count)
        {
            var architect = MostRecentPartyTurnArchitect;
            var container = architect.SelectedContainer;

            List<Object> itemsToTake;

            if (container.Type == "shadow fountain")
            {
                // Shadow Storage logic
                itemsToTake = architect.ShadowStorage
                    .Where(item =>
                        item.Type == architect.TryTakeItemType &&
                        item.Materials.SequenceEqual(architect.TryTakeMaterials))
                    .Take(count)
                    .ToList();
            }
            else
            {
                // Standard container logic
                itemsToTake = container.ContainedObjects
                    .Where(item =>
                        item.Type == architect.TryTakeItemType &&
                        item.Materials.SequenceEqual(architect.TryTakeMaterials))
                    .Take(count)
                    .ToList();
            }

            int countActuallyTaken = itemsToTake.Count;
            if (countActuallyTaken == 0)
            {
                MakeObservation("There are no matching items to take.", Color.Yellow, new EntityList<Entity>());
                return;
            }

            bool PlayedSound = false;

            foreach (var item in itemsToTake)
            {
                if (container.Type == "shadow fountain")
                {
                    architect.ShadowStorage.Remove(item);
                }
                else
                {
                    container.ContainedObjects.Remove(item);
                }

                if (architect.MainHeldObject == null)
                {
                    architect.MainHeldObject = item;
                }
                else if (architect.OffHeldObject == null)
                {
                    architect.OffHeldObject = item;
                }
                else
                {
                    architect.Inventory.Add(item);
                }

                if (!PlayedSound)
                {

                    item.PlaySound();
                    PlayedSound = true;
                }

                if (architect.Structure != null && architect.Structure.Type == "market")
                {
                    architect.Structure.MarketDebtToUs -= item.Value();
                }

                architect.IDidSomethingBadSoScanForShockMines();
            }

            string itemType = Game1.Capitalize(architect.TryTakeItemType);
            bool isPlural = countActuallyTaken != 1;
            string displayName = isPlural ? itemType.ToLowerInvariant().Pluralize(true) : itemType.ToLowerInvariant();

            MakeObservation($"You take {countActuallyTaken} {displayName} from the {container.ReferredToNames[0]}.", Color.Green, new EntityList<Entity>());

            // Clear selection state
            architect.TryTakeItemType = "";
            architect.TryTakeMaterials = new EntityList<Material>();
            GameState = "otherturn";
        }

        void DropItems(int count)
        {
            // 1. Gather all matching items in a List
            var itemsToDrop = MostRecentPartyTurnArchitect.Inventory
                .Where(item =>
                    item.Type == MostRecentPartyTurnArchitect.TryDropItemType &&
                    item.Materials.SequenceEqual(MostRecentPartyTurnArchitect.TryDropMaterials))
                .Take(count)
                .ToList();

            int countActuallyDropped = itemsToDrop.Count;
            if (countActuallyDropped == 0)
            {
                MakeObservation(
                    "You have no matching items to drop.",
                    Color.Yellow,
                    new EntityList<Entity>());
                return;
            }

            bool Market = false;

            // 2. Remove from inventory and place into room/block
            foreach (var item in itemsToDrop)
            {
                MostRecentPartyTurnArchitect.Inventory.Remove(item);

                if (MostRecentPartyTurnArchitect.Room != null)
                {
                    MostRecentPartyTurnArchitect.Room.Objects.Add(item);
                    item.Room = MostRecentPartyTurnArchitect.Room;
                    item.Block = MostRecentPartyTurnArchitect.Block;
                }
                else
                {
                    MostRecentPartyTurnArchitect.Block.Objects.Add(item);
                    item.Block = MostRecentPartyTurnArchitect.Block;
                }

                // Market debt if in a market
                if (MostRecentPartyTurnArchitect.Structure != null
                    && MostRecentPartyTurnArchitect.Structure.Type == "market")
                {
                    MostRecentPartyTurnArchitect.Structure.MarketDebtToUs += item.Value();
                    Market = true;

                }

                // Add some cooldown for each item
                MostRecentPartyTurnArchitect.CooldownCycles += 1;
            }

            string itemType = Game1.Capitalize(MostRecentPartyTurnArchitect.TryDropItemType);

            if (Market)
                MostRecentPartyTurnArchitect.TryComment("exchange", 20);

            // Use the count to determine whether to pluralize the itemType
            bool isPlural = countActuallyDropped != 1;

            // Pluralize the item type based on the count
            string displayName = isPlural
                ? itemType.ToLowerInvariant().Pluralize(true)
                : itemType.ToLowerInvariant();

            MakeObservation(
                $"You drop {Humanizer.NumberToWordsExtension.ToWords(countActuallyDropped)} {displayName}.",
                Color.Yellow,
                new EntityList<Entity>()
            );

        }

