        public Rectangle GetStructureHitbox(Structure s)
        {
            // Ensure the structure has a draw index and the position mapping exists
            if (s.DrawIndex < 0 || !DrawPositions.ContainsKey(s.DrawIndex))
                return Rectangle.Empty;

            var pos = DrawPositions[s.DrawIndex];

            // Determine the structure key
            string structType = s.Type == "prism" ? "monument" : s.Type;
            string fallbackKey = structType + s.Variant.ToString();
            string layoutKey = s.Block.District.Location.Layout;

            // Attempt to get the correct source rectangle
            Rectangle rect;
            if (!StructureRects.TryGetValue(structType, out rect) &&
                !StructureRects.TryGetValue(fallbackKey, out rect) &&
                !StructureRects.TryGetValue(layoutKey, out rect))
            {
                throw new Exception($"Missing structure rectangle for: '{structType}', fallback: '{fallbackKey}', layout: '{layoutKey}'");
            }

            // Create and return the hitbox based on the source rectangle size
            return new Rectangle(pos.X, pos.Y, rect.Width, rect.Height);
        }


        public Rectangle GetEntityHitbox(Entity entity)
        {
            // These match your snippet's \"global\" values/logic:
            bool isInRoom = (MostRecentPartyTurnArchitect.Room != null);

            float maxRadius = 300.0f; // For clamping & scaling Architect distance

            // The same "stretch" logic used for rooms vs. outside:
            float stretchX = isInRoom ? StretchScaleRoomX : StretchScaleOutsideX;
            float stretchY = isInRoom ? StretchScaleRoomY : StretchScaleOutsideY;

            // Helper function exactly as in your snippet:
            int RoundToNearest4(int value) => (value + 2) / 4 * 4;

            // --------------------------
            // 1) If the entity is an Architect
            // --------------------------
            if (entity is Architect arch)
            {

                if (arch.OnTopOfStructure != null)
                {
                    Rectangle structureHitbox = GetStructureHitbox(arch.OnTopOfStructure);
                    if (structureHitbox == Rectangle.Empty)
                        return Rectangle.Empty;

                    float scale = 0.2f;
                    int scaledWidth = (int)(300 * scale);  // 60
                    int scaledHeight = (int)(1000 * scale); // 200

                    int cenx = structureHitbox.Center.X;
                    int ceny = structureHitbox.Center.Y;

                    // Step 1: Find other architects on this structure
                    var allOnThisStructure = arch.Block.Architects
                        .Where(a => a.OnTopOfStructure == arch.OnTopOfStructure)
                        .ToList();

                    // Step 2: Determine draw index for offsetting
                    int myIndex = allOnThisStructure.IndexOf(arch); // 0 = center, 1 = +100/-100, 2 = +200/-200, etc.

                    // Step 3: Determine side (left/right) from DrawPositions
                    int drawIndex = arch.OnTopOfStructure.DrawIndex;
                    bool isRightSide = DrawPositions.TryGetValue(drawIndex, out var drawPos) && drawPos.Inverted;

                    // Step 4: Apply offset
                    int offsetX = myIndex * 70 * (isRightSide ? 1 : -1);
                    int x = cenx + offsetX - (scaledWidth / 2);
                    int y = ceny - (scaledHeight / 2);

                    return new Rectangle(x, y + HeightAboveStructure, scaledWidth, scaledHeight);
                }





                // CASE A: The "player" architect
                if (arch == MostRecentPartyTurnArchitect)
                {
                    // In your snippet, the player is always drawn at (centerX+15, centerY) with scale=0.2
                    int x = DrawCenterX + 15;
                    int y = DrawCenterY;
                    float scale = 0.2f;

                    int scaledWidth = (int)(300 * scale); // 300×0.2 = 60
                    int scaledHeight = (int)(1000 * scale); // 1000×0.2 = 200

                    // This matches the "ChosenRect = new Rectangle(x, y, scaledWidth, scaledHeight)"
                    return new Rectangle(x, y, scaledWidth, scaledHeight);
                }

                // CASE B: Any other architect
                else
                {
                    // We replicate the same distance/rotation approach that the snippet
                    // uses for non-player architects:

                    // 1) Find them in the \"_architects\" list, get their distance & rotation
                    int idx = MostRecentPartyTurnArchitect._architects.IndexOf(arch);
                    if (idx < 0)
                    {
                        // Fallback if not found. You could return an empty rectangle or throw:
                        return Rectangle.Empty;
                    }

                    float distance = MostRecentPartyTurnArchitect._distances[idx] + 1.0f;
                    float rotation = MostRecentPartyTurnArchitect._rotations[idx];

                    // 2) Clamp distance up to 6, map to maxRadius
                    distance = MathF.Min(distance, 6.0f);
                    float distancePixelLength = (distance / 6.0f) * maxRadius;

                    // 3) Apply stretch, then offset from (centerX, centerY)
                    float offsetX = distancePixelLength * MathF.Cos(rotation) * stretchX;
                    float offsetY = distancePixelLength * MathF.Sin(rotation) * stretchY;

                    if(MostRecentPartyTurnArchitect.Room != null)
                    {
                        offsetY /= 2;
                    }

                    float architectX = DrawCenterX + offsetX;
                    float architectY = DrawCenterY + offsetY;

                    // 4) Same final scale=0.2 in your snippet
                    float scale = 0.2f;
                    int scaledWidth = (int)(300 * scale); // 60
                    int scaledHeight = (int)(1000 * scale); // 200

                    // So final Rectangle is:
                    return new Rectangle(
                        (int)architectX,
                        (int)architectY,
                        scaledWidth,
                        scaledHeight
                    );
                }
            }

            // --------------------------
            // 2) If the entity is an Object
            // --------------------------
            else if (entity is Object obj)
            {
                // The snippet has 2 major cases: (a) Doors/exit door, (b) everything else

                // Check if it's a Door or "exit door" in the same way:
                bool isFancyDoor =
                    (obj is Door door && door.Direction != "down" && door.Direction != "up")
                    || obj.Type == "exit door";

                if (isFancyDoor)
                {
                    int direction = obj.Type == "exit door"
        ? obj.ID % 4
        : (obj as Door)?.Direction?.ToLower() switch
        {
            "north" => 0,
            "east" => 1,
            "south" => 2,
            "west" => 3,
            _ => 0 // Default to North
        };

                    // The 4 corners of the "fancy line"
                    (int NWx, int NWy) = (808, 1040);
                    (int NEx, int NEy) = (1278, 869);
                    (int SEx, int SEy) = (1749, 1040);
                    (int SWx, int SWy) = (1277, 1206);

                    // Pick which line to use for door placement
                    (int x1, int y1, int x2, int y2) selectedLine = direction switch
                    {
                        0 => (NWx, NWy, NEx, NEy), // North: NW → NE
                        1 => (NEx, NEy, SEx, SEy), // East:  NE → SE
                        2 => (SEx, SEy, SWx, SWy), // South: SE → SW
                        3 => (SWx, SWy, NWx, NWy), // West:  SW → NW
                        _ => (NWx, NWy, NEx, NEy)  // Default to North
                    };

                    // Convert obj.Rotation to fraction t in [0..1]
                    float t = (float)((obj.Rotation % (2 * Math.PI)) / (2 * Math.PI));

                    // Interpolate position along the selected wall line
                    float posX = selectedLine.x1 + (selectedLine.x2 - selectedLine.x1) * t;
                    float posY = selectedLine.y1 + (selectedLine.y2 - selectedLine.y1) * t;

                    //PointsToDraw.Add(new Rectangle((int)posX - 2, (int)posY - 2, 5, 5));  // Debug: Draw a small red dot at the calculated door position

                    // Door size
                    const int DoorWidth = 192;
                    const int DoorHeight = 192;

                    // Correct placement based on **inversion rule**
                    (int offsetX, int offsetY) = direction switch
                    {
                        0 => (150, 145),  // North → Regular
                        1 => (40, 145),   // East  → Inverted
                        2 => (150, 145),  // South → Regular
                        3 => (40, 145),   // West  → Inverted
                        _ => (150, 145)   // Default to Regular
                    };

                    // Final bottom-left corner
                    int hitboxX = (int)Math.Round(posX) - offsetX;
                    int hitboxY = (int)Math.Round(posY) - offsetY;

                    hitboxY += RoomAndObjectOffset;
                    hitboxY += roomHeightAdj;

                    int finalX = RoundToNearest4(hitboxX);
                    int finalY = RoundToNearest4(hitboxY);



                    // Return the correct door hitbox
                    return new Rectangle(finalX, finalY, DoorWidth, DoorHeight);
                }



                else
                {
                    //-------------------------------------------------
                    // Normal objects
                    //-------------------------------------------------
                    // 1) Possibly adjust distance if it's furniture or if in a room
                    double objectDistance = obj.Distance;
                    double objectRotation = obj.Rotation;

                    if (FurnitureRects.ContainsKey(obj.Type))
                    {
                        // The snippet adds 100
                        objectDistance += 100;
                    }
                    if (isInRoom)
                    {
                        // The snippet divides distance by 1.5
                        objectDistance /= 1.5;
                    }

                    // 2) Convert distance + rotation to pixel offset
                    float distancePixelLength = (float)objectDistance;
                    float offsetX = distancePixelLength * MathF.Cos((float)objectRotation) * stretchX;
                    float offsetY = distancePixelLength * MathF.Sin((float)objectRotation) * stretchY;

                    // The snippet does offsetY *= 0.5f for "room stuff"
                    offsetY *= 0.5f;


                    // 3) final on-screen position is (OBJCenterX + offsetX, OBJCenterY + offsetY)
                    float objectX = OBJCenterX + offsetX;
                    float objectY = (OBJCenterY + OBJRoomOffsetY) + offsetY;

                    // 4) The snippet picks drawSize=64 for items or 192 for furniture, else default 64
                    int drawSize;
                    if (ItemIndex.ContainsKey(obj.Type))
                        drawSize = 64;
                    else if (FurnitureRects.ContainsKey(obj.Type) || obj.Type == "staircase")
                    {
                        drawSize = 192;
                        if (obj.Type != "exit door" && !(obj is Door))
                        {
                            objectY += FurnitureYAdj;
                        }
                    }
                    else
                        drawSize = 64; // fallback

                    // 5) The top-left corner is (objectX - drawSize/2, objectY - drawSize/2)
                    int topLeftX = RoundToNearest4((int)Math.Round(objectX) - drawSize / 2);
                    int topLeftY = RoundToNearest4((int)Math.Round(objectY) - drawSize / 2);

                    // So the final rectangle is:
                    return new Rectangle(topLeftX, topLeftY, drawSize, drawSize);
                }
            }

            // If somehow it's neither an Architect nor an Object, just return an empty rect
            return Rectangle.Empty;
        }

