        List<string> GetAvailableDyes()
        {
            HashSet<string> dyesFound = new HashSet<string>();

            // Check dyes in direct inventory
            foreach (var item in MostRecentPartyTurnArchitect.Inventory)
            {
                if (item.Type == "dye")
                {
                    foreach (var material in item.Materials)
                    {
                        dyesFound.Add(material.Color);
                    }
                }
            }

            // Check dyes inside containers
            foreach (var container in MostRecentPartyTurnArchitect.Inventory.Where(item => item.ContainedObjects != null))
            {
                foreach (var containedItem in container.ContainedObjects)
                {
                    if (containedItem.Type == "dye")
                    {
                        foreach (var material in containedItem.Materials)
                        {
                            dyesFound.Add(material.Color);
                        }
                    }
                }
            }

            return dyesFound.ToList();
        }


