        bool HasDyeInInventory(string color)
        {
            // Check if the dye exists directly in the player's inventory
            if (MostRecentPartyTurnArchitect.Inventory.Any(item =>
                item.Type == "dye" &&
                item.Materials.Any(mat => mat.Color == color)))
            {
                return true;
            }

            // Check within containers
            foreach (var container in MostRecentPartyTurnArchitect.Inventory.Where(item => item.ContainedObjects != null))
            {
                // Iterate through the actual objects inside the container
                foreach (var containedItem in container.ContainedObjects)
                {
                    if (containedItem.Type == "dye" && containedItem.Materials.Any(mat => mat.Color == color))
                    {
                        return true; // Found dye in a container
                    }
                }
            }

            return false; // No dye found
        }




