                        costCooldown = $"Energy, {Math.Max(0, 15 - caster.PathOfHeatLevel)}   Cooldown, {Math.Round(15 / caster.Speed, 2)}";

                        Architect target = Game1.LensedArchitect;
                        int targetDex = target?.Dexterity ?? 4;
                        int dodgeChance = 30 + targetDex * 5;
                        string s = target != null
                            ? "(for lensed architect, lens new w/ alt click)"
                            : "(average, lens architect w/ alt click for better data)";

                        effects += $"   Launches a flaming projectile at a random body part. ";
                        effects += $"Damage: r(2 x Dexterity + Throwing Proficiency), {dodgeChance}% chance to be dodged {s}. ";

                        // Compute FireSeconds range
                        int minFire = 0;
                        int maxFire = 3;

                        if (caster.PathOfHeatLevel >= 6)
                        {
                            minFire = 2;
                            maxFire = 5;

                            if (caster.PathOfHeatLevel >= 8 && caster.FireSeconds > 0)
                            {
                                maxFire += caster.FireSeconds;
                            }
                        }

                        effects += $"On hit, applies burning: r({minFire}-{maxFire}) FireSeconds (w/ path level and self-burn).";
                    }
                    break;

                case "starstrike":
                    {
                        int energy = Math.Max(0, 12 - caster.PathOfStarsLevel);
                        double cooldown = Math.Round(15 / caster.Speed, 2);
                        costCooldown = $"Energy, {energy}   Cooldown, {cooldown}";

                        int attackerFocus = caster.Focus;
                        int attackerStrength = caster.Strength;
                        int attackerDex = caster.Dexterity;

                        Architect target = Game1.LensedArchitect;
                        int targetDex = target?.Dexterity ?? 4;
                        string s = target != null
                            ? "(for lensed architect, lens new w/ alt click)"
                            : "(average, lens architect w/ alt click for better data)";
                        int dodgeChance = 30 + targetDex * 5;

                        // Halved values
                        int integrityMin = (int)Math.Floor(10 / 2.0);  // 5
                        int integrityMax = (int)Math.Floor((20 + attackerFocus * 2) / 2.0);
                        int energyLossMin = (int)Math.Floor(10 / 2.0); // 5
                        int energyLossMax = (int)Math.Floor((20 + attackerFocus * 2) / 2.0);
                        int painEst = (int)Math.Floor((10 + attackerStrength) / 2.0);
                        int bleedingEst = (int)Math.Floor((4 + attackerDex / 2.0) / 2.0);

                        effects += $" Throws 2-3 blazing stars at target. Each star has a {dodgeChance}% chance to be dodged {s}. ";
                        effects += $"Per star: r({integrityMin}-{integrityMax}) integrity damage, ~{painEst} pain, ~{bleedingEst} bleeding, ";
                        effects += $"and reduces energy by r({energyLossMin}-{energyLossMax}). ";

                        if (caster.PathOfStarsLevel >= 4)
                        {
                            effects += $"Applies r(10-30) DestabilizedCycles on hit.";
                        }
                    }
                    break;


                case "fire spectral bolt":
                    {
                        costCooldown = $"Energy, {Math.Max(0, 15 - caster.PathOfDeathLevel)}   Cooldown, {Math.Round(15 / caster.Speed, 2)}";

                        Architect target = Game1.LensedArchitect;
                        int targetDex = target?.Dexterity ?? 4;
                        int dodgeChance = 30 + targetDex * 5;
                        string s = target != null
                            ? "(for lensed architect, lens new w/ alt click)"
                            : "(average, lens architect w/ alt click for better data)";

                        effects += $"   {dodgeChance}% chance to be dodged {s}, ";
                        effects += $"-{10 + (caster.Focus * 2)} Energy, ";
                        effects += $"Converts target to undead if energy reaches 0.";
                    }
                    break;

                case "water bolt":
                    costCooldown = $"Energy, {energyCost}   Cooldown, {Math.Round(15 / caster.Speed, 2)}";
                    effects += $"   -r(3-{5 + caster.Focus}) Energy," +
                               $"   +r(0-100) DestabilizedCycles," +
                               $"   +r(50-100) WetCycles," +
                               $"   +r(20-{40 + caster.Focus * 5}) BlindCycles," +
                               $"   -2 Integrity to all BodyParts";
                    break;


                case "chaos flare":
                    costCooldown = $"Energy, {energyCost}   Cooldown, {Math.Round(20 / caster.Speed, 2)}";
                    effects += $"   +r(2-4) FireSeconds," +
                               $"   -r(4-{7 + caster.Focus * 2}) Energy," +
                               $"   +r(0-49) DestabilizedCycles," +
                               $"   -r({10 + caster.Focus * 2}) Integrity to some BodyParts (50% chance each)";
                    break;


                case "ice shock":
                    costCooldown = $"Energy, {energyCost}   Cooldown, {Math.Round(18 / caster.Speed, 2)}";
                    effects += $"   +r(0-{100 + caster.Focus * 10}) WetCycles," +
                               $"   +r(0-{100 + caster.Focus * 10}) DestabilizedCycles," +
                               $"   -r({10 + caster.Focus}) Integrity to half of BodyParts";
                    break;


                case "starsmite":
                    costCooldown = $"Energy, {Math.Max(0, 25 - caster.PathOfStarsLevel)}   Cooldown, {Math.Round(15 / caster.Speed, 2)}";
                    effects += $"   Deals r(10-{15 + caster.PathOfStarsLevel}) Integrity damage to each body part," +
                               $"   +r(2-{2 + caster.PathOfStarsLevel}) Bleeding," +
                               $"   -r(4-{8 + caster.PathOfStarsLevel}) Energy,";
                    break;

                case "evoke strike":
                    costCooldown = $"Energy, {Math.Max(0, 10 - caster.PathOfLightLevel)}   Cooldown, {Math.Round(15 / caster.Speed, 2)}";
                    effects += $"   Requires spark to evoke, deals r(10-{caster.PathOfLightLevel * 5}) Integrity damage to a random body part," +
                               $"   +r(5-{5 + caster.PathOfLightLevel}) Bleeding," +
                               $"   +r(5-{5 + caster.PathOfLightLevel}) Pain.";
                    break;

                case "flash flame":
                    costCooldown = $"Energy, {energyCost}   Cooldown, {Math.Round(12 / caster.Speed, 2)}";
                    effects += "   +r(3-6) FireSeconds";
                    break;


                default:
                    return ("n/", "/a");
            }

            return (costCooldown, effects);
        }


        public static Rectangle DrawCenteredTextAtPosition(SpriteBatch spriteBatch, string text, float centerX, float centerY, SpriteFont font, Color c)
        {
            // Measure the size of the text using the provided font
            Vector2 textSize = font.MeasureString(text);

            // Calculate the position to start drawing the text so that it is centered on (centerX, centerY)
            float xPosition = centerX - (textSize.X / 2);
            float yPosition = centerY - (textSize.Y / 2);

            // Create a Vector2 for the adjusted position
            Vector2 position = new Vector2(xPosition, yPosition);

            // Draw the text at the calculated position with the specified font and color
            spriteBatch.DrawString(font, text, position, c);

            // Return the rectangle that represents the drawn text area
            return new Rectangle((int)xPosition, (int)yPosition, (int)textSize.X, (int)textSize.Y);
        }


