        public void StepSound(int Count)
        {
            int AlreadySteps = Game1.SFX.Where(s => Game1.StepSounds.Contains(s)).Count();

            if (AlreadySteps < 2)
            {
                for (int i = 0; i < Count; i++)
                {
                    Game1.SFX.Add(Game1.StepSounds[Game1.r.Next(4)]);
                }
            }
        }

