        public static void UpdateTravelButtons()
        {
            // Lock all buttons by default
            StopAndGather.InvisibleLock = true;
            VisitThisLocation.InvisibleLock = true;
            HuntUnknownLocations.InvisibleLock = true;
            ApproachDisturbance.InvisibleLock = true;
            DistrictSwitchU.InvisibleLock = true;
            DistrictSwitchD.InvisibleLock = true;
            ZoomOut.InvisibleLock = true;
            AssembleRaft.InvisibleLock = true;
            WaitOneWeek.InvisibleLock = true;
            WaitOneMonth.InvisibleLock = true;
            WaitForPlanActive.InvisibleLock = true;
            SaveAndExitTravel.InvisibleLock = true; // <<< Don't forget to lock this too

            int currentY = 400; // Starting Y position
            int buttonSpacing = 70; // Space between buttons

            // Toggle Zoom is always visible
            ZoomOut.InvisibleLock = false;
            ZoomOut.Hitbox.Y = currentY;
            currentY += buttonSpacing;

            // Assemble Raft always visible
            AssembleRaft.InvisibleLock = false;
            AssembleRaft.Hitbox.Y = currentY;
            currentY += buttonSpacing;

            // Always show WaitOneWeek
            WaitOneWeek.InvisibleLock = false;
            WaitOneWeek.Hitbox.Y = currentY;
            currentY += buttonSpacing;

            // Always show WaitOneMonth
            WaitOneMonth.InvisibleLock = false;
            WaitOneMonth.Hitbox.Y = currentY;
            currentY += buttonSpacing;

            // Get current region
            Region r = GameWorld.WorldMap[
                GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX +
                GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width
            ];

            // If location exists and explored
            if (r.Location != null && r.Location.Explored == true)
            {
                VisitThisLocation.InvisibleLock = false;
                VisitThisLocation.Hitbox.Y = currentY;
                VisitThisLocation.Text = "Visit " + r.Location.Name;
                currentY += buttonSpacing;

                if (r.Location.Districts.Count > 1)
                {
                    DistrictSwitchU.InvisibleLock = false;
                    DistrictSwitchD.InvisibleLock = false;
                    VisitThisLocation.Text += (", " + r.Location.Districts[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorDistrict].Name);
                }

                // Check if there's an INACTIVE plan at this location
                bool foundInactivePlan = false;

                foreach (Faction f in Game1.GameWorld.AllFactions)
                {
                    if (f.CurrentPlan != null &&
                        f.CurrentPlan.PlanLocation == r.Location &&
                        (r.Location.Explored || (GameState != "travelmenu" && GameState != "ascendant")))
                    {
                        bool active = false;
                        foreach (District d in r.Location.Districts)
                        {
                            if (d.DistrictArchitects.Any(a => f.CurrentPlan.PlanInitiators.Contains(a)))
                            {
                                active = true;
                                break;
                            }
                        }

                        if (!active)
                        {
                            foundInactivePlan = true;
                            break;
                        }
                    }
                }

                if (foundInactivePlan)
                {
                    WaitForPlanActive.InvisibleLock = false;
                    WaitForPlanActive.Hitbox.Y = currentY;
                    currentY += buttonSpacing;
                }

            }
            else
            {
                // No location, so hunt or gather
                if (biomeGatheringOptions.ContainsKey(r.Biome))
                {
                    List<string> resources = biomeGatheringOptions[r.Biome];
                    string resourceText = string.Join(", ", resources);
                    StopAndGather.Text = $"Stop and gather {resourceText}";
                    StopAndGather.InvisibleLock = false;
                    StopAndGather.Hitbox.Y = currentY;
                    currentY += buttonSpacing;
                }

                HuntUnknownLocations.InvisibleLock = false;
                HuntUnknownLocations.Hitbox.Y = currentY;
                currentY += buttonSpacing;
            }

            // Event disturbance
            if (StoredEvent != null)
            {
                ApproachDisturbance.InvisibleLock = false;
                ApproachDisturbance.Hitbox.Y = currentY;
                currentY += buttonSpacing;
            }

            // <<< New Part: Add Save and Exit Button at the end >>>
            currentY += buttonSpacing; // Add extra space before Save button
            SaveAndExitTravel.InvisibleLock = false;
            SaveAndExitTravel.Hitbox.Y = currentY;
        }

