        public static void SaveGame(World world, bool endgame)
        {
            // Reset global state
            AnnouncementScrollValue = 0;
            LastTravelActMsg = "";

            string name = (world.GamePlayerAssociation != null && world.GamePlayerAssociation.ActiveParty != null)
                ? $"Legacy of {world.GamePlayerAssociation.ActiveParty.originalLeader.Name}, leader of {world.GamePlayerAssociation.ActiveParty.Name} in {char.ToLower(world.Name[0]) + world.Name.Substring(1)}"
                : world.Name;

            string basePath = Path.Combine(DocumentsFolderPath, ".LightrealmData");
            string finalPath = Path.Combine(basePath, name);
            string incompletePath = finalPath + "_incomplete";
            string backupPath = finalPath + "_backup";

            try
            {
                Directory.CreateDirectory(basePath);

                // Delete previous backup if it exists
                if (Directory.Exists(backupPath))
                    Directory.Delete(backupPath, true);

                // Backup current save if it exists
                if (Directory.Exists(finalPath))
                    Directory.Move(finalPath, backupPath);

                // Clean up any leftover incomplete saves
                if (Directory.Exists(incompletePath))
                    Directory.Delete(incompletePath, true);

                // Create the incomplete save directory
                Directory.CreateDirectory(incompletePath);

                // Get GameWorld ID and optionally remove from ledger
                int gameWorldId = GameWorld.EntityLedger.FirstOrDefault(x => x.Value == GameWorld).Key;
                if (endgame)
                    GameWorld.EntityLedger.Remove(gameWorldId);

                // Save data into incompletePath
                File.WriteAllText(Path.Combine(incompletePath, "ExtraData.txt"), gameWorldId.ToString());

                SerializeObjectToBinaryFile(Path.Combine(incompletePath, $"{world.Name}.bin"), world);

                File.WriteAllLines(Path.Combine(incompletePath, "version.txt"), new[]
                {
            Version,
            "Modification of the above line may lead to world corruption."
        });

                List<string> historyContent = new()
        {
            $"Historical Events of {world.Name}",
            "To find events related to a certain subject, try typing in their name.",
            ""
        };

                foreach (var evt in world.HistoricalEvents)
                {
                    int regionIndex = evt.Region != null ? GameWorld.HyperRegions.IndexOf(evt.Region.Hyperregion) : 11;
                    int significantFlag = evt.Significant ? 1 : 0;
                    historyContent.Add($"[{regionIndex}/{significantFlag}]{evt.EventData}");
                }

                File.WriteAllLines(Path.Combine(incompletePath, "history.txt"), historyContent);

                if (GameWorld.rnd != null)
                {
                    string json = JsonConvert.SerializeObject(GameWorld.rnd);
                    File.WriteAllText(Path.Combine(incompletePath, "GameRandom.json"), json);
                }

                File.WriteAllText(Path.Combine(incompletePath, "gamemode.txt"), Game1.GameWorld.GameMode);

                // Promote incomplete to final
                Directory.Move(incompletePath, finalPath);

                // Delete backup after successful promotion
                if (Directory.Exists(backupPath))
                    Directory.Delete(backupPath, true);
            }
            catch (Exception ex)
            {
                // Cleanup on failure
                if (Directory.Exists(incompletePath))
                    Directory.Delete(incompletePath, true);

                Console.WriteLine("Failed to save game: " + ex.Message);
                return;
            }

            // Final cleanup if endgame
            if (endgame)
            {
                Announcements.Clear();
                Inventory.Text = "Open Menu";
                Inventory.Hitbox.X = 400;
                Inventory.Hitbox.Y = 212;
            }

            CompanionMessages.Clear();
            AlreadyTriedASearch = false;
        }
        private static void SerializeObjectToBinaryFile(string filePath, object obj)
        {
            using (FileStream fileStream = new FileStream(filePath, FileMode.Create))
            {
                BinaryFormatter binaryFormatter = new BinaryFormatter();
                binaryFormatter.Serialize(fileStream, obj);
            }
        }

        private static T DeserializeObjectFromBinaryFile<T>(string filePath)
        {
            using (FileStream fileStream = new FileStream(filePath, FileMode.Open))
            {
                BinaryFormatter binaryFormatter = new BinaryFormatter();
                return (T)binaryFormatter.Deserialize(fileStream);
            }
        }


