        public static string ConvertArchitectToDescription(Architect a)
        {
            string TaskDescription = "";

            if (!a.IsAlive)
            {
                TaskDescription = "dead";
            }
            else if (a.UnconsciousCycles > 0)
            {
                TaskDescription = ("unconscious");
            }
            else if (a.Task == "")
            {
                TaskDescription = ("idle");
            }
            else if (a.Target != (null, null, null, null) && (a.Target.Item1 != a.Location || a.Target.Item2 != a.District || a.Target.Item3 != a.Block || a.Target.Item4 != a.Room))
            {
                if (a.CurrentlyMovingPlace == "north")
                {
                    TaskDescription = ("north-moving");
                }
                else if (a.CurrentlyMovingPlace == "east")
                {
                    TaskDescription = ("east-moving");
                }
                else if (a.CurrentlyMovingPlace == "south")
                {
                    TaskDescription = ("south-moving");
                }
                else if (a.CurrentlyMovingPlace == "west")
                {
                    TaskDescription = ("west-moving");
                }
                else if (a.CurrentlyMovingPlace == "outside")
                {
                    TaskDescription = ("structure-leaving");
                }
                else
                {
                    TaskDescription = ("deliberating");
                    //though it is also possible that below a structure is selected
                }

                foreach (Structure s in a.Block.Structures)
                {
                    if (s.GUID == a.CurrentlyMovingPlace)
                    {
                        TaskDescription = (s.Name + "-entering");
                    }
                }

                if (TaskDescription == "")
                {
                    TaskDescription = ("area-leaving");
                }
            }
            else if (a.CyclesLeftInTask > 0)
            {
                TaskDescription = (ConvertTaskToArchitectPrefix(a.Task, a));
            }
            else
            {
                TaskDescription = "";
            }


            Party p = Game1.GameWorld.GamePlayerAssociation.ActiveParty;

            if (TaskDescription != "")
            {
                if (a.ReferredToNames.Count() > 0)
                {
                    if (p.Architects.Contains(a))
                        return (a.ReferredToNames[0]);
                    else
                        return (a.ReferredToNames[0] + ", " + TaskDescription);
                }
                else
                {
                    return ("");
                }
            }
            else
            {
                return ("");
            }
        }

        private void SaveSettings()
{
    // Define the new settings file path
    string documentsPath = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), ".LightrealmData");
    string optionsFilePath = Path.Combine(documentsPath, "options.txt");

    // Ensure the directory exists
    if (!Directory.Exists(documentsPath))
        Directory.CreateDirectory(documentsPath);

    // Prepare settings content
    string[] settings =
    {
        $"MusicVolume:{MusicVolume}",
        $"SoundVolume:{SoundVolume}",
        $"Resolution:{CommonResolutions[CurrentResolutionIndex].Width}x{CommonResolutions[CurrentResolutionIndex].Height}",
        $"WindowMode:{CurrentWindowModeIndex}",
        $"AutosvOnLocationLeave:{MaxAutosaveAge}"
    };

    // Write settings to the file
    File.WriteAllLines(optionsFilePath, settings);
}


        protected override void Initialize()
        {
            //settings nonsense
            ContentPath = Path.GetFullPath("Content");

            // Default values
            CurrentResolutionIndex = 0;
            CurrentWindowModeIndex = 0;
            MusicVolume = 50;
            SoundVolume = 50;
            MaxAutosaveAge = 200;



            string documentsRoot = Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments);
            string oldFolderPath = Path.Combine(documentsRoot, "LightrealmData");
            string newFolderPath = Path.Combine(documentsRoot, ".LightrealmData");

            // Rename "LightrealmData" to ".LightrealmData" if needed
            if (Directory.Exists(oldFolderPath) && !Directory.Exists(newFolderPath))
            {
                try
                {
                    Directory.Move(oldFolderPath, newFolderPath);
                }
                catch (IOException ex)
                {
                    Console.WriteLine($"Error renaming folder: {ex.Message}");
                    // Optional: handle the error
                }
            }

            // Ensure the new folder exists
            if (!Directory.Exists(newFolderPath))
            {
                Directory.CreateDirectory(newFolderPath);
            }

            // OPTIONAL: Make the folder hidden (Windows only)
            DirectoryInfo dirInfo = new DirectoryInfo(newFolderPath);
            if ((dirInfo.Attributes & FileAttributes.Hidden) == 0)
            {
                dirInfo.Attributes |= FileAttributes.Hidden;
            }

            // Now define the options file path using the correct folder
            string optionsFilePath = Path.Combine(newFolderPath, "options.txt");


            // If no settings file exists, create one with defaults
            if (!File.Exists(optionsFilePath))
            {
                int dw = GraphicsAdapter.DefaultAdapter.CurrentDisplayMode.Width;
                int dh = GraphicsAdapter.DefaultAdapter.CurrentDisplayMode.Height;

                string[] defaults =
                {
        "MusicVolume:100",
        "SoundVolume:100",
        $"Resolution:{dw}x{dh}",
        "WindowMode:1",
        "AutosvOnLocationLeave:200"
    };

                File.WriteAllLines(optionsFilePath, defaults);
            }

            // Read settings from file
            var lines = File.ReadAllLines(optionsFilePath);
            int fileMusicVolume = MusicVolume;
            int fileSoundVolume = SoundVolume;
            int fileWM = CurrentWindowModeIndex;
            int fileAS = MaxAutosaveAge;
            string fileResStr = null;

            foreach (var line in lines)
            {
                if (string.IsNullOrWhiteSpace(line)) continue;
                var parts = line.Split(':');
                if (parts.Length < 2) continue;

                string key = parts[0].Trim(), val = parts[1].Trim();
                switch (key)
                {
                    case "MusicVolume": if (int.TryParse(val, out int mv)) fileMusicVolume = mv; break;
                    case "SoundVolume": if (int.TryParse(val, out int sv)) fileSoundVolume = sv; break;
                    case "Resolution": fileResStr = val; break;
                    case "WindowMode": if (int.TryParse(val, out int wm)) fileWM = wm; break;
                    case "AutosvOnLocationLeave": if (int.TryParse(val, out int aso)) fileAS = aso; break;
                }
            }

            // Apply simple settings
            MusicVolume = fileMusicVolume;
            SoundVolume = fileSoundVolume;
            MaxAutosaveAge = fileAS;
            CurrentWindowModeIndex = fileWM;
            // Update the button text
            MaxAutosaveAgeButton.Text = MaxAutosaveAge switch
            {
                0 => "Maximum Autosave Age: Never Autosave",
                99999 => "Maximum Autosave Age: Always Autosave",
                _ => $"Maximum Autosave Age: {MaxAutosaveAge}"
            };
            // Handle resolution string
            int parsedW = GraphicsAdapter.DefaultAdapter.CurrentDisplayMode.Width;
            int parsedH = GraphicsAdapter.DefaultAdapter.CurrentDisplayMode.Height;

            if (!string.IsNullOrEmpty(fileResStr))
            {
                var resParts = fileResStr.Split('x');
                if (resParts.Length == 2 &&
                    int.TryParse(resParts[0], out int w) &&
                    int.TryParse(resParts[1], out int h))
                {
                    parsedW = w;
                    parsedH = h;
                }
            }

            // Find closest matching resolution from list
            var matched = CommonResolutions
                .OrderBy(r => Math.Abs(r.Width - parsedW) + Math.Abs(r.Height - parsedH))
                .First();

            CurrentResolutionIndex = CommonResolutions.IndexOf(matched);
            TempPBBW = matched.Width;
            TempPBBH = matched.Height;
            ResolutionButton.Text = $"Change Resolution (Current: {matched.Width}x{matched.Height})";

            // Apply window mode setting
            var windowModes = new List<string> { "Windowed", "Borderless Window", "Fullscreen" };
            if (CurrentWindowModeIndex < 0 || CurrentWindowModeIndex >= windowModes.Count)
                CurrentWindowModeIndex = 0;

            WindowModeButton.Text = $"Toggle Window Mode (Current: {windowModes[CurrentWindowModeIndex]})";

            // Apply graphics settings
            PreferredBackBufferWidth = matched.Width;
            PreferredBackBufferHeight = matched.Height;
            _graphics.PreferredBackBufferWidth = PreferredBackBufferWidth;
            _graphics.PreferredBackBufferHeight = PreferredBackBufferHeight;

            switch (CurrentWindowModeIndex)
            {
                case 0:
                    _graphics.IsFullScreen = false;
                    _graphics.HardwareModeSwitch = true;
                    Window.IsBorderless = false;
                    break;
                case 1:
                    _graphics.IsFullScreen = false;
                    _graphics.HardwareModeSwitch = false;
                    Window.IsBorderless = true;
                    break;
                case 2:
                    _graphics.IsFullScreen = true;
                    _graphics.HardwareModeSwitch = true;
                    break;
            }
            _graphics.ApplyChanges();


            const int VIRTUAL_WIDTH = 2560;
            int centerX = (VIRTUAL_WIDTH - 64) / 2;

            MusicSlider = new Button("", centerX, 112, 64, new List<string> { "optionsmenu" });
            SoundSlider = new Button("", centerX, 240, 64, new List<string> { "optionsmenu" });

            IsMouseVisible = false;

            PickupConfirm.InvisibleLock = true;



            // Define the original corners based on the new data
            Vector2[] originalCorners = new Vector2[]
            {
                new Vector2(266, 1274), new Vector2(311, 1318), // NW
                new Vector2(320, 1273), new Vector2(357, 1318), // N
                new Vector2(366, 1274), new Vector2(403, 1318), // NE
