        private void DisplayResult(string result)
        {
            var jsonResult = JObject.Parse(result);
            var text = jsonResult["text"]?.ToString() ?? string.Empty;

            // Check if the prompt is empty and the text starts with "I " or "i "
            if (string.IsNullOrEmpty(MostRecentPartyTurnArchitect.Prompt) &&
                (text.StartsWith("I ") || text.StartsWith("i ")))
            {
                // Trim "I " or "i " from the start of the text
                text = text.Substring(2);
            }

            if(text != "")
            {
                // Append text to your prompt or handle it accordingly
                MostRecentPartyTurnArchitect.Prompt += text + " "; //adding a space seems to be the best approach, because we take it off at the end anyway
            }
        }

        protected override void LoadContent()
        {
            const int Scale = 20;
            const int FrameSize = 50 * Scale;

            _spriteBatch = new SpriteBatch(GraphicsDevice);
            ContentRoot = Content.RootDirectory;

            string dataPath = string.Concat(ContentPath, "/data/");

            FirstNames = File.ReadAllLines(string.Concat(dataPath, "names.txt")).ToList();
            LastNames = File.ReadAllLines(string.Concat(dataPath, "last-names.txt")).ToList();
            Words = File.ReadAllLines(string.Concat(dataPath, "words.txt")).ToList();
            Syllables = File.ReadAllLines(string.Concat(dataPath, "syllables.txt")).ToList();
            NameSuffixes = File.ReadAllLines(string.Concat(dataPath, "namesuffixes.txt")).ToList();

            DistrictTileMap = Content.Load<Texture2D>("distmap/tiles_32");
            ImbuementNode = Content.Load<Texture2D>("gui/imbuementnode");
            CharacterSheetOther = ScaleTexture(GraphicsDevice, Content.Load<Texture2D>("character art/characters_sheet_other"), Scale);


            Texture2D GenerateVariant(Texture2D source, List<int> indices, Func<int, int> brightnessFunc)
            {
                int tileSize = 50;
                int tilesPerRow = source.Width / tileSize;

                Color[] pixels = new Color[source.Width * source.Height];
                source.GetData(pixels);

                foreach (int index in indices)
                {
                    int tileX = (index % tilesPerRow) * tileSize;
                    int tileY = (index / tilesPerRow) * tileSize;

                    for (int y = 0; y < tileSize; y++)
                    {
                        for (int x = 0; x < tileSize; x++)
                        {
                            int px = (tileY + y) * source.Width + (tileX + x);
                            Color original = pixels[px];
                            int gray = (original.R + original.G + original.B) / 3;
                            int adjusted = brightnessFunc(gray);
                            pixels[px] = new Color(adjusted, adjusted, adjusted, original.A);
                        }
                    }
                }

                Texture2D result = new Texture2D(source.GraphicsDevice, source.Width, source.Height);
                result.SetData(pixels);
                return result;
            }

            List<int> targetIndices = Enumerable.Range(3, 17).Append(20).ToList();
            int ArchaixFromLuminarchFunc(int gray)
            {
                double normalized = gray / 255.0;
                double adjusted = 0.64 * Math.Pow(normalized, 1.02);
                return (int)Math.Clamp(adjusted * 255.0, 0, 255);
            }
            int LuminarchToNightfellFunc(int gray)
            {
                double normalized = gray / 255.0;
                double adjusted = 0.313 * Math.Pow(normalized, 1.026) + 0.227;
                return (int)Math.Clamp(adjusted * 255.0, 0, 255);
            }

            Texture2D baseSheet = Content.Load<Texture2D>("character art/idle");
            CharacterSheetIdle = new Dictionary<string, Texture2D>();
            CharacterSheetIdle["luminarch"] = ScaleTexture(GraphicsDevice, baseSheet, Scale);
            CharacterSheetIdle["archaix"] = GenerateVariant(ScaleTexture(GraphicsDevice, baseSheet, Scale), targetIndices, ArchaixFromLuminarchFunc);
            CharacterSheetIdle["nightfell"] = GenerateVariant(ScaleTexture(GraphicsDevice, baseSheet, Scale), targetIndices, LuminarchToNightfellFunc);

            Desert = ScaleTexture(GraphicsDevice, Content.Load<Texture2D>("background/desert"), Scale);
