            string filePath = Path.Combine(dataPath, "recipes.txt");

            // Check if the file exists
            if (File.Exists(filePath))
            {
                // Read all lines from the file
                string[] lines = File.ReadAllLines(filePath);

                // Initialize a list to store the parsed data, assuming 'Recipes' is already defined
                Recipes = new List<(string, List<string>)>();

                // Loop through each line
                foreach (string line in lines)
                {
                    // Split the line into parts based on commas
                    string[] parts = line.Split(',');

                    // Check if there are any parts to process
                    if (parts.Length > 0)
                    {
                        string id = parts[0].Trim();  // Trim spaces around the ID
                        List<string> materials = new List<string>();

                        // Loop through each part after the ID to get materials
                        for (int i = 1; i < parts.Length; i++)
                        {
                            materials.Add(parts[i].Trim()); // Trim spaces around each material
                        }

                        // Add the ID and materials to the list of recipes
                        Recipes.Add((id, materials));
                    }
                }
            }
            else
            {
                // Handle the case where the file does not exist
                Console.WriteLine("Recipes file not found.");
            }
        }

        public static void IncrementAndCycleWorld()
        {
            ArchitectIndex++;

            if (GameWorld == null)
                return;

            if (ArchitectIndex >= LoadedArchitects.Count())
            {
                ArchitectIndex = 0;

                foreach (Architect a in LoadedArchitectsToRemove)
                {
                    LoadedArchitects.Remove(a);
                }
                LoadedArchitectsToRemove = new List<Architect>();

                TicksSinceLoad++; // Increment the game cycle count
                GameWorld.Cycle++; // Increment the world cycle
                UpdateNonPlayerWorld(); // Update the non-player world
            }

            if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.All(architect => !architect.IsAlive) && GameState != "dead")
            {
                GameState = "dead";
                MostRecentPartyTurnArchitect.CompanionMessage("alldeath", "");
                RestoreBlindAnnouncements();
            }
            
            if (LoadedArchitects.Count() == 1)
            {
                ArchitectIndex = 0;

                foreach (Architect a in LoadedArchitectsToRemove)
                {
                    LoadedArchitects.Remove(a);
                }
                LoadedArchitectsToRemove = new List<Architect>();

                TicksSinceLoad++; // Increment the game cycle count
                GameWorld.Cycle++; // Increment the world cycle
                UpdateNonPlayerWorld(); // Update the non-player world
            }
        }

        public static void HandleThrownObjects(EntityList<Object> objects, EntityList<Architect> architects, Block b, Room r)
        {
            EntityList<Object> objectsToRemove = new EntityList<Object>();

            foreach (Object o in objects)
            {
                if (o.AirborneTarget != null)
                {
                    if (o.AirborneCyclesToHitTarget > 0)
                    {
                        o.AirborneCyclesToHitTarget--;
                        continue;
                    }
                    else
                    {
                        Architect targetArchitect = null;

                        if (o.AirborneTarget is Architect a)
                            targetArchitect = a;
                        else if (o.AirborneTarget is Object obj && obj.IsBodyPart && obj.Creator is Architect creator)
                            targetArchitect = creator;

                        bool InSameArea = false;
                        
                         
                        if(r != null)
                        {
                            if(targetArchitect != null)
                            {
                                if (targetArchitect.Room == r)
                                {
                                    InSameArea = true;
                                }
                            }
                            else
                            {
                                Object O = o.AirborneTarget as Object;

                                if (r.Objects.Contains(O))
                                    InSameArea = true;
                            }
                        }
                        if (b != null)
                        {
                            if (targetArchitect != null)
                            {
                                if (targetArchitect.Block == b)
                                {
                                    InSameArea = true;
                                }
                            }
                            else
                            {
                                Object O = o.AirborneTarget as Object;

                                if (b.Objects.Contains(O))
                                    InSameArea = true;
                            }
                        }

                        if (InSameArea)
                        {
                            if (targetArchitect != null)
                            {
                                if (Game1.r.Next(100) < (30 + targetArchitect.Dexterity * 5))
                                {
                                    targetArchitect.AnnounceToParty(
                                        targetArchitect.ReferredToNames[0] + " avoids the " + o.ReferredToNames[0] + ".",
                                        Color.Gray,
                                        new EntityList<Entity>() { targetArchitect, o }
                                    );
                                    targetArchitect.ChangeOpinion(o.Thrower, -75);
                                }
                                else
                                {
                                    if (o.Materials.Contains(GameWorld.Spectre))
                                    {
                                        targetArchitect.Energy -= (((Architect)(o.Creator)).Focus * 2) + 15;
                                        targetArchitect.AnnounceToParty(
                                            targetArchitect.ReferredToNames[0] + " is enveloped in souls!",
                                            Color.OrangeRed,
                                            new EntityList<Entity>() { targetArchitect }
                                        );

                                        if (targetArchitect.Energy <= 0)
                                        {
                                            targetArchitect.IsAlive = false;
                                            targetArchitect.RaiseFromTheDead((Architect)o.Creator, targetArchitect.ReferredToNames[0], ((Architect)o.Creator).PathOfDeathLevel, 2);

                                            if (targetArchitect.IsAlive && !Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects.Contains(targetArchitect))
                                            {
                                                Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects.Add(targetArchitect);
                                            }
                                        }
                                    }
                                    else
                                    {
                                        HandlePhysicalCollision(targetArchitect, o);
                                    }
                                }
                            }
                            else // Non-Architect airborne targets handling
                            {
                                HandleObjectCollision(o, Game1.r);
                            }
                        }
                        else 
                        {
                            o.Thrower.AnnounceToParty("The " + o.ReferredToNames[0] + "'s target escaped.", Color.Yellow, new EntityList<Entity>() { o });
                        }

                        o.AirborneTarget = null;

                        if (o.Type.Contains("grenade") || o.Materials.Contains(GameWorld.Spectre))
                        {
                            o.Dissipating = true;
                        }

                        // Grenade effects
                        objectsToRemove.AddRange(HandleGrenadeEffects(o, architects, objects));

                        // Check if the object should dissipate instead of dropping on the ground
                        if ((o.Materials[0].Type == "metaphysic" || o.Dissipating) && o.Type != "spark")
                        {
                            objectsToRemove.Add(o);
                        }
                    }
                }

                if (objects.Count == 0)
                {
                    break;
                }
            }

            foreach (var obj in objectsToRemove)
            {
                objects.Remove(obj);
                Game1.ObjectsToDeleteOnUnload.Add(obj);
            }
        }

        public static List<Object> HandleGrenadeEffects(Object o, EntityList<Architect> architects, EntityList<Object> objects)
        {
            List<Object> ObjectsToDelete = new List<Object>();

            if (o.Type == "spatial grenade")
            {
                MakeObservation("The grenade explodes into a massive violet vortex, pulling everything in!", Color.Purple, new EntityList<Entity>());

                List<Architect> architectsToRemove = new List<Architect>();

                foreach (Architect a in architects)
                {
                    a.IsAlive = false;
                    if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Contains(a))
                    {
                        architectsToRemove.Add(a);

                        if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Count() == 0 && GameState != "dead")
                        {
                            GameState = "dead";
                            Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects[0].CompanionMessage("alldeath", "");
                            RestoreBlindAnnouncements();
                        }
                    }
                    MakeObservation(a.ReferredToNames[0] + " has been consumed by the portal.", Color.Purple, new EntityList<Entity>() { a });
                }

                // Remove the architects after the loop
                foreach (Architect a in architectsToRemove)
                {
                    GameWorld.GamePlayerAssociation.ActiveParty.Architects.Remove(a);
                }

                ObjectsToDelete.AddRange(objects.Where(o => !(o is Door || o.Type == "exit door")));
                architects.Clear();
            }

            else if (o.Type == "lightning grenade")
            {
                MakeObservation("The grenade explodes into a swarm of lightning, striking everything around!", Color.Cyan, new EntityList<Entity>());
                foreach (Architect a in architects)
                {
                    a.UnconsciousCycles = 1000;
                    if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Contains(a))
                    {
                        if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Count() == 0 && GameState != "dead")
                        {
                            GameState = "dead";
                            Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects[0].CompanionMessage("alldeath", "");
                            RestoreBlindAnnouncements();
                        }
                    }
                    MakeObservation(a.ReferredToNames[0] + " goes completely unconscious.", Color.Purple, new EntityList<Entity>() { a });
                }
            }

            return ObjectsToDelete;
        }

        public static void HandlePhysicalCollision(Architect target, Object o)
        {
            if (!o.Materials.Contains(GameWorld.Spectre))
            {
                target.CombatCycles = 100;
                ((Architect)(o.Thrower)).CombatCycles = 100;
                target.ChangeOpinion(o.Thrower, -75);

                Object ArchitectBodyPart = target.BodyParts[Game1.r.Next(target.BodyParts.Count())];

                int InitialStagnantObjectIntegrity = ArchitectBodyPart.Integrity;
                int InitialThrowingObjectIntegrity = o.Integrity;

                List<TextStorage> ListText = ArchitectBodyPart.TakeDamageFromObject(o, 2 * (o.Thrower.Dexterity + o.Thrower.GetProficiency("throwing")), null, "");

                foreach (TextStorage t in ListText)
                {
                    target.AnnounceToParty(t.Data, t.Color, t.Entities);
                }

                if (o.Type == "star" && ((Architect)(o.Creator)).PathOfStarsLevel >= 4)
                {
                    target.AnnounceToParty(ArchitectBodyPart.ReferredToNames[0] + " is destabilized!", Color.Orange, new EntityList<Entity>() { ArchitectBodyPart });
                    target.DestabilizedCycles += Game1.r.Next(10, 30);
                }
                else if (o.Materials.Contains(GameWorld.Flame))
                {
                    target.AnnounceToParty(ArchitectBodyPart.ReferredToNames[0] + " bursts into flames!", Color.Orange, new EntityList<Entity>() { ArchitectBodyPart });
                    if (((Architect)(o.Creator)).PathOfHeatLevel >= 8 && ((Architect)(o.Creator)).FireSeconds > 0)
                    {
                        target.FireSeconds += Game1.r.Next(2, 5 + (((Architect)(o.Creator)).FireSeconds));
                    }
                    else if (((Architect)(o.Creator)).PathOfHeatLevel >= 6)
                    {
                        target.FireSeconds += Game1.r.Next(3, 6);
                    }
                    else
                    {
                        target.FireSeconds += Game1.r.Next(2, 5);
                    }
                }

                if (o.Integrity < 0 && InitialThrowingObjectIntegrity > 0)
                {
                    target.AnnounceToParty("The " + o.ReferredToNames[0] + " has been destroyed!", Color.Orange, new EntityList<Entity>() { o });
                }
                if (ArchitectBodyPart.Integrity < 0 && InitialStagnantObjectIntegrity > 0)
                {
                    target.AnnounceToParty("The " + ArchitectBodyPart.ReferredToNames[0] + " has been destroyed!", Color.Orange, new EntityList<Entity>() { ArchitectBodyPart });
                }
            }
        }

        public static void HandleObjectCollision(Object o, Random r)
        {
            if (o.AirborneTarget is Object targetObject)
            {
                int InitialStagnantObjectIntegrity = targetObject.Integrity;
                int InitialThrowingObjectIntegrity = o.Integrity;

                o.Integrity = InitialThrowingObjectIntegrity - InitialStagnantObjectIntegrity;
                targetObject.Integrity = InitialThrowingObjectIntegrity - InitialStagnantObjectIntegrity;

                o.Thrower.AnnounceToParty("The " + o.ReferredToNames[0] + " has collided into " + targetObject.ReferredToNames[0] + "!", Color.Orange, new EntityList<Entity>() { o, targetObject });

                List<TextStorage> T = targetObject.TakeDamageFromObject(o, o.Thrower.GetProficiency("throwing") + 3, null, ""); // Simulating damage application

                foreach (TextStorage t in T)
                {
                    o.Thrower.AnnounceToParty(t.Data, t.Color, t.Entities);
                }


                if(targetObject.Type == "shock mine")
                {
                    o.Thrower.Shock(targetObject);
                    o.Thrower.Shock(targetObject);
                }

                if (o.Integrity < 0 && InitialThrowingObjectIntegrity > 0)
                {
                    o.Thrower.AnnounceToParty("The " + o.ReferredToNames[0] + " has been destroyed!", Color.Orange, new EntityList<Entity>() { o });
                }
                if (targetObject.Integrity < 0 && InitialStagnantObjectIntegrity > 0)
                {
                    o.Thrower.AnnounceToParty("The " + targetObject.ReferredToNames[0] + " has been destroyed!", Color.Orange, new EntityList<Entity>() { targetObject });
                }

                if (targetObject.IsBodyPart && targetObject.Owner != null)
                {
                    ((Architect)(targetObject.Owner)).CombatCycles = 100;
                    ((Architect)(o.Thrower)).CombatCycles = 100;
                    ((Architect)(targetObject.Owner)).ChangeOpinion(o.Thrower, -75);
                }
            }
        }


        public static void UpdateNonPlayerWorld()
        {
            bool Correction = false;

            if (ArchitectIndex > LoadedArchitects.Count() - 1)
            {
                ArchitectIndex = 0;
            }
            if (LoadedArchitects.Count() == 0)
            {
                return;
            }

            EntityList<Block> BlocksThatHaveImportant = GameWorld.GamePlayerAssociation.ActiveParty.Architects.Select(a => a.Block);
            EntityList<Room> RoomsThatHaveImportant = GameWorld.GamePlayerAssociation.ActiveParty.Architects.Select(a => a.Room);


            // Iterate through blocks
            for (int x = 0; x < 7; x++)
            {
                for (int z = 0; z < 7; z++)
                {
                    var block = LoadedArchitects[ArchitectIndex].District.DistrictMap[x + z * 7];
                    HandleThrownObjects(block.Objects, block.Architects, block, null);


                    if(BlocksThatHaveImportant.Contains(block))
                    {
                        foreach (Object o in block.Objects)
                        {
                            o.UpdateSelfActionsAndSuch(null, true);
                        }
                    }
                    else
                    {
                        foreach (Object o in block.Objects)
                        {
                            o.UpdateSelfActionsAndSuch(null, false);
                        }
                    }



                    //destroy objects

                    foreach(Object o in block.Objects)
                    {
                        if(o.Integrity <= 0 && o.Type != "exit door" && !(o is Door))
                        {
                            block.ObjectsToRemove.Add(o);
                            o.AnnounceToParty(o.ReferredToNames[0] + " is destroyed!", Color.Orange, new EntityList<Entity>() { o });
                        }
                    }



                    foreach (Object o in block.ObjectsToRemove)
                    {
                        block.Objects.Remove(o);
                    }
                    foreach (Object o in block.ObjectsToAdd)
                    {
                        block.Objects.Add(o);
                    }
                    foreach (Architect a in block.ArchitectsToRemove)
                    {
                        block.Architects.Remove(a);
                    }
                    block.ObjectsToRemove.Clear();
                    block.ObjectsToAdd.Clear();



                    //correction stuff

                    if(Correction)
                    {
                        foreach (Architect a in block.Architects)
                        {
                            a.Block = block;
                            a.Room = null;
                        }
                    }
                }
            }

            // Iterate through rooms in structures
            foreach (var block in LoadedArchitects[ArchitectIndex].District.DistrictMap)
            {
                foreach (var structure in block.Structures)
                {
                    foreach (var room in structure.Rooms)
                    {
                        HandleThrownObjects(room.Objects, room.Architects, null, room);


                        if(RoomsThatHaveImportant.Contains(room))
                        {
                            foreach (Object o in room.Objects)
                            {
                                o.UpdateSelfActionsAndSuch(null, true);
                            }
                        }
                        else
                        {
                            foreach (Object o in room.Objects)
                            {
                                o.UpdateSelfActionsAndSuch(null, false);
                            }
                        }

                        foreach (Object o in room.ObjectsToRemove)
                        {
                            room.Objects.Remove(o);
                        }
                        room.ObjectsToRemove.Clear();
                        foreach (Object o in room.ObjectsToAdd)
                        {
                            room.Objects.Add(o);
                        }
                        room.ObjectsToAdd.Clear();


                        //correction stuff

                        foreach (Architect a in room.Architects)
                        {
                            if(Correction)
                                a.Room = room;
                        }
                    }
                }
            }


            //return fractal objects to reality/update them

            EntityList<Object> FractalObjectsToRemove = new EntityList<Object>();

            foreach (Object o in GameWorld.FractalObjects)
            {
                o.FractalCycles--;
                if (o.FractalCycles < 1 && o.RematerializeLocation.Item2.IsLoaded)
                {
                    o.Block = o.RematerializeLocation.Item3;
                    o.Room = o.RematerializeLocation.Item5;

                    if (o.Room != null)
                    {
                        o.Room.Objects.Add(o);
                    }
                    else
                    {
                        o.Block.Objects.Add(o);
                    }

                    if (LoadedArchitects[ArchitectIndex].Room == o.Room && LoadedArchitects[ArchitectIndex].Block == o.Block)
                    {
                        MakeObservation(o.ReferredToNames[0] + " has rematerialized!", Color.LightBlue, new EntityList<Entity>() { o });
                    }

                    FractalObjectsToRemove.Add(o);
                }
            }
            foreach (Object o in FractalObjectsToRemove)
            {
                GameWorld.FractalObjects.Remove(o);
            }

            EntityList<Architect> FractalArchitectsToRemove = new EntityList<Architect>();
            foreach (Architect a in GameWorld.FractalArchitects)
            {
                a.FractalCycles--;

                if (a.FractalCycles < 1 && a.RematerializeLocation.Item2.IsLoaded)
                {
                    if (a.RematerializeLocation.Item2.IsLoaded)
                    {
                        a.Location = a.RematerializeLocation.Item1;
                        a.District = a.RematerializeLocation.Item2;
                        a.Block = a.RematerializeLocation.Item3;
                        a.Room = a.RematerializeLocation.Item5;

                        if (a.RematerializeLocation.Item5 != null)
                        {
                            a.Room.Architects.Add(a);
                        }
                        else
                        {
                            a.Block.Architects.Add(a);
                        }

                        FractalArchitectsToRemove.Add(a);

                        if (LoadedArchitects[ArchitectIndex].Room == a.Room && LoadedArchitects[ArchitectIndex].Block == a.Block)
                        {
                            MakeObservation(a.ReferredToNames[0] + " has rematerialized!", Color.LightBlue, new EntityList<Entity>() { a });
                        }
                    }
                    else
                    {
                        a.Location = a.RematerializeLocation.Item1;
                        a.District = a.RematerializeLocation.Item2;
                        a.District.DistrictArchitects.Add(a);
                    }

                    if (!LoadedArchitects.Contains(a))
                    {
                        LoadedArchitects.Add(a);
                    }
                }
            }
            foreach (Architect a in FractalArchitectsToRemove)
            {
                GameWorld.FractalArchitects.Remove(a);
            }

            //change the random int
            Game1.GameWorld.ReactionModifierInt = Game1.r.Next(0, 100000);

            //update quest objectives

            if (((ulong)Math.Round(Game1.GameWorld.Cycle)) % 5 == 0)
            {
                foreach (Objective o in GameWorld.GamePlayerAssociation.ActiveParty.ActiveObjectives)
                {
                    foreach (Architect a in GameWorld.GamePlayerAssociation.ActiveParty.Architects)
                    {
                        if (o.IsActiveObjective && o.Completed(a) && !o.MarkedAsComplete && a.Block != null)
                        {
                            o.MarkedAsComplete = true;

                            //initiate appearance:

                            if (o.AppearsOnEdgeIfTrue)
                            {
                                if(a.Room != null)
                                    Game1.Announcements.Add(new TextStorage("You hear something appear outside.", Color.Magenta, new EntityList<Entity>()));
                                else
                                    Game1.Announcements.Add(new TextStorage("You hear something appear.", Color.Magenta, new EntityList<Entity>()));

                                List<int> outskirtsBlockIndexes = new List<int>
                                    {
                                        // Top row and bottom row
                                        0, 1, 2, 3, 4, 5, 6, 42, 43, 44, 45, 46, 47, 48,
                                        // Left column and right column, excluding corners already included
                                        7, 14, 21, 28, 35, 13, 20, 27, 34, 41
                                    };

                                int Index = outskirtsBlockIndexes[Game1.GameWorld.rnd.Next(outskirtsBlockIndexes.Count)];

                                Block b = MostRecentPartyTurnArchitect.District.DistrictMap[Index];

                                if (o.AppearingEntity is Architect A)
                                {
                                    if (!LoadedArchitects.Contains(A))
                                    {
                                        b.Architects.Add(A);
                                        A.Block = b;
                                        LoadedArchitects.Add(A);
                                    }
                                    LoadedFinalPointers.Add(A);
                                    A.PopulateSelf(true);
                                    A.HookedObjective = o;
                                }
                                else if (o.AppearingEntity is Object O)
                                {
                                    //test if the object already exists...

                                    bool AlreadyExists = false;
                                    foreach (Block B in MostRecentPartyTurnArchitect.District.DistrictMap)
                                    {
                                        if (B.Objects.Contains(O) || B.Architects.Any(a => a.MainHeldObject == O || a.OffHeldObject == O || a.Inventory.Contains(O) || a.Clothing.Contains(O)))
                                            AlreadyExists = true;
                                        else
                                        {
                                            foreach (Structure s in B.Structures)
                                            {
                                                foreach (Room r in s.Rooms)
                                                {
                                                    if (r.Objects.Contains(O) || r.Architects.Any(a => a.MainHeldObject == O || a.OffHeldObject == O || a.Inventory.Contains(O) || a.Clothing.Contains(O)))
                                                        AlreadyExists = true;
                                                }
                                            }
                                        }
                                    }

                                    if (!AlreadyExists)
                                    {
                                        b.Objects.Add(O);
                                    }
                                    LoadedFinalPointers.Add(O);
                                    O.HookedObjective = o;
                                }

                            }
                            else
                            {
                                bool AlreadyExists = false;

                                if (o.AppearingEntity is Object obj)
                                {
                                    // Check if object already exists anywhere in the district
                                    foreach (Block B in MostRecentPartyTurnArchitect.District.DistrictMap)
                                    {
                                        if (B.Objects.Contains(obj))
                                        {
                                            AlreadyExists = true;
                                            break;
                                        }
                                        foreach (Structure s in B.Structures)
                                        {
                                            foreach (Room r in s.Rooms)
                                            {
                                                if (r.Objects.Contains(obj))
                                                {
                                                    AlreadyExists = true;
                                                    break;
                                                }
                                            }
                                            if (AlreadyExists) break;
                                        }
                                        if (AlreadyExists) break;
                                    }

                                    // Only add the object if it does not already exist



                                    //also check nearby block people

                                    foreach(Architect AAA in a.Room != null ? a.Room.Architects : a.Block.Architects)
                                    {
                                        if (AAA.Inventory.Contains(obj) || AAA.OffHeldObject == obj || a.MainHeldObject == obj)
                                        {
                                            AlreadyExists = true;
                                            break;
                                        }
                                    }

                                    if (!AlreadyExists)
                                    {
                                        if (a.Room != null)
                                            a.Room.Objects.Add(obj);
                                        else
                                            a.Block.Objects.Add(obj);

                                        Game1.Announcements.Add(new TextStorage("Something appears.", Color.Magenta, new EntityList<Entity>()));
                                    }



                                }
                                else if (o.AppearingEntity is Architect arch)
                                {
                                    // Check if architect already exists
                                    if (!LoadedArchitects.Contains(arch))
                                    {
                                        if (a.Room != null)
                                            a.Room.Architects.Add(arch);
                                        else
                                            a.Block.Architects.Add(arch);

                                        LoadedArchitects.Add(arch);
                                    }
                                    arch.PopulateSelf(true);
                                }

                                LoadedFinalPointers.Add(o.AppearingEntity);
                                o.AppearingEntity.HookedObjective = o;
                            }



                            //summon a group to kill the player lmaoooo

                            List<Group> HireableGroups = Game1.GameWorld.AllFactions.SelectMany(f => f.SatelliteGroups).ToList();
                            HireableGroups.AddRange(Game1.GameWorld.Groups.Where(f => f.Type == "mercenary" || f.Type == "adventure"));

                            // Always remove groups with 1 or fewer architects
                            HireableGroups.RemoveAll(g => g.Architects.Count <= 1);

                            // Try with minimum size 4
                            List<Group> filteredGroups = HireableGroups.Where(g => g.Architects.Count >= 4).ToList();

                            // If none, try with minimum size 3
                            if (filteredGroups.Count == 0)
                                filteredGroups = HireableGroups.Where(g => g.Architects.Count >= 3).ToList();

                            // If still none, try with minimum size 2
                            if (filteredGroups.Count == 0)
                                filteredGroups = HireableGroups.Where(g => g.Architects.Count >= 2).ToList();

                            if (filteredGroups.Count > 0)
                            {
                                Group randomGroup = null;
                                if (o.ActualTask == "prevent plan x from succeeding" && (o.InflictUponEntityX as Plan).StoredGroup != null) //if a plan was supposed to be executed by someone, load them lmaoooo
                                {
                                    randomGroup = (o.InflictUponEntityX as Plan).StoredGroup;
                                }

                                if(randomGroup == null)
                                {
                                    randomGroup = filteredGroups[Game1.GameWorld.rnd.Next(filteredGroups.Count)];
                                }



                                switch (o.ActualTask)
                                {
                                    case "prevent plan x from succeeding":
                                        a.AnnounceToParty("You hear some noises outside, the plan executors have arrived and they don't seem too pleased.", Color.Red, new EntityList<Entity>());
                                        break;
                                    case "free x from bondage":
                                        a.AnnounceToParty("You hear some very loud noises from outside... is someone coming?", Color.Red, new EntityList<Entity>());
                                        break;
                                    case "eliminate all life from x":
                                        a.AnnounceToParty("All of a sudden though, the quiet fades...", Color.Red, new EntityList<Entity>());
                                        break;
                                    case "deliver y to x":
                                        a.AnnounceToParty(o.InflictUponEntityX.ReferredToNames[0] + ": Do you hear that noise? That can't be good...", Color.Red, new EntityList<Entity>());
                                        break;
                                    case "reactivate x":
                                        var emptyStringsA = new string[] { "The console flashes a warning indicator, something is incoming...", "The glow of the console illuminates something in the distance..." };
                                        a.AnnounceToParty(emptyStringsA[Game1.r.Next(2)], Color.Red, new EntityList<Entity>());
                                        break;
                                    case "steal x":
                                        a.AnnounceToParty("You hear the sounds of someone approaching. Maybe this object is in high demand...", Color.Red, new EntityList<Entity>());
                                        break;
                                    case "intercept x and kill them":
                                        a.AnnounceToParty("You hear loud footsteps. Might not want to figure out where they came from.", Color.Red, new EntityList<Entity>());
                                        break;
                                    case "capture x":
                                        var emptyStringsB = new string[] { o.InflictUponEntityX + " seems abnormally calm. It isn't until you hear the footsteps that you understand why.", o.InflictUponEntityX + " seems more worried about something else. It isn't until you hear the footsteps you understand why." };

                                        a.AnnounceToParty(emptyStringsB[Game1.r.Next(2)], Color.Red, new EntityList<Entity>());
                                        break;
                                    case "deactivate x":
                                        var emptyStringsC = new string[] { "You see someone ominous in the reflection of the tablet...", "Within the stillness of the quiet, you hear some swift foosteps approach..." };
                                        a.AnnounceToParty(emptyStringsC[Game1.r.Next(2)], Color.Red, new EntityList<Entity>());
                                        break;
                                    default:
                                        a.AnnounceToParty("", Color.Red, new EntityList<Entity>());
                                        break;
                                }


                                List<Architect> Attackers = randomGroup.Architects.Take(3).Distinct().ToList();

                                foreach (Architect Attacker in Attackers)
                                {
                                    //totaally possible some of them are already here (especially when plan foiling) so might double check
                                    Game1.LoadedAttackers.Add(Attacker);

                                    Attacker.PopulateSelf(true);

                                    Attacker.Task = "killtarget";
                                    Attacker.TargetArchitect = a;
                                    Attacker.Target = (MostRecentPartyTurnArchitect.Location, MostRecentPartyTurnArchitect.District, MostRecentPartyTurnArchitect.Block, MostRecentPartyTurnArchitect.Room);
                                    Attacker.CyclesLeftInTask = 10000;

                                    Attacker.BoostedCycles = 200;

                                    if (!Game1.LoadedArchitects.Contains(Attacker))
                                    {
                                        //this logic if they weren't there already

                                        Game1.LoadedArchitects.Add(Attacker);

                                        List<int> outskirtsBlockIndexes = new List<int>
                                                {
                                                    0, 1, 2, 3, 4, 5, 6, 42, 43, 44, 45, 46, 47, 48,
                                                    7, 14, 21, 28, 35, 13, 20, 27, 34, 41
                                                };

                                        Block b = MostRecentPartyTurnArchitect.District.DistrictMap[outskirtsBlockIndexes[r.Next(outskirtsBlockIndexes.Count)]];

                                        b.Architects.Add(Attacker);
                                        Attacker.Block = b;

                                        if(Attacker.District != null)
                                            Attacker.District.DistrictArchitects.Remove(Attacker);

                                        Attacker.Location = MostRecentPartyTurnArchitect.Location;
                                        Attacker.District = MostRecentPartyTurnArchitect.District;

                                        if (Attacker.HasBeenKitted == false)
                                        {
                                            Attacker.KitOutArchitect($"generic{Math.Max(MostRecentPartyTurnArchitect.Level-2, 1)}");
                                        }

                                        if(Attacker.Level < MostRecentPartyTurnArchitect.Level + 1)
                                        {
                                            Attacker.Level = MostRecentPartyTurnArchitect.Level + 1;
                                        }
                                    }
                                }
                            }


                            o.IsActiveObjective = false;
                            if(o.NextObjective != null)
                            {
                                o.NextObjective.IsActiveObjective = true;
                            }

                            Game1.GameWorld.GamePlayerAssociation.ActiveParty.RoomsUnsearched.Clear();

                            foreach(Architect AA in Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects)
                            {
                                AA.SearchRoom = null;
                            }

                            break;
                        }
                    }
                }


                //check for approach triggers

                List<Entity> LoadedPointersToRemove = new List<Entity>();

                foreach (Entity e in LoadedFinalPointers)
                {
                    if (e.HookedObjective.RequiredInteractionForLast == "approach")
                    {
                        foreach (Architect a in GameWorld.GamePlayerAssociation.ActiveParty.Architects)
                        {
                            if (
                                    a.Block.Objects.Contains(e) ||
                                    a.Block.Architects.Contains(e) ||
                                    (a.Room != null &&
                                        (a.Room.Objects.Contains(e) ||
                                         a.Room.Architects.Contains(e)))
                                )
                            {
                                MakeObservation(e.IAmAFinalPointerThatFollowsAfterThisObjective.FinalMessage.Data, e.IAmAFinalPointerThatFollowsAfterThisObjective.FinalMessage.Color, e.IAmAFinalPointerThatFollowsAfterThisObjective.FinalMessage.Entities);
                                GameWorld.GamePlayerAssociation.ActiveParty.Intrigue.Add(new TextStorage(e.IAmAFinalPointerThatFollowsAfterThisObjective.FinalIntrigue, Color.Magenta, new EntityList<Entity>()));

                                foreach (Party p in GameWorld.GamePlayerAssociation.Parties)
                                    p.ActiveObjectives.Remove(e.IAmAFinalPointerThatFollowsAfterThisObjective);

                                LoadedPointersToRemove.Add(e);
                            }
                        }
                    }
                }

                foreach (Entity e in LoadedPointersToRemove)
                {
                    LoadedFinalPointers.Remove(e);
                }
            }

            if (((ulong)Math.Round(Game1.GameWorld.Cycle)) % 50 == 0)
            {
                foreach(Objective o in GameWorld.GamePlayerAssociation.ActiveParty.ActiveObjectives)
                {
                    var obsoleteInfo = o.ParentQuest.Obsolete();
                    if (obsoleteInfo.Item1)
                    {
                        o.ParentQuest.Dissolve(obsoleteInfo.Item2);
                    }
                }
            }
        }

        protected override void Update(GameTime gameTime)
        {
            currentMouseState = Mouse.GetState();

            HairPhase++;
            if(HairPhase > 59)
            {
                HairPhase = 0;
            }

            if (LastStoredGameStateForMenu == "travelmenu")
            {
                SaveAndExitInMenu.InvisibleLock = false;
            }
            else
            {
                SaveAndExitInMenu.InvisibleLock = true;
            }


            if (SFX.Count > 10)
            {
                SFX.RemoveRange(10, SFX.Count - 10);
            }

            if (AnnouncementsLastTick < Announcements.Count)
            {
                for (int i = AnnouncementsLastTick; i < Announcements.Count; i++)
                {
                    var announcement = Announcements[i];

                    // Only store announcements made during blindness
                    if (MostRecentPartyTurnArchitect.BlindCycles > 0)
                    {
                        BlindAnnouncements.Add((i, announcement));
                    }
                }

                if (MostRecentPartyTurnArchitect.BlindCycles > 0)
                {
                    // Clear newly added announcements
                    Announcements.RemoveRange(AnnouncementsLastTick, Announcements.Count - AnnouncementsLastTick);
                }
                else
                {
                    AnnouncementScrollValue = 0;
                    AnnouncementsLastTick = Announcements.Count;
                }
            }

            //clean up old announcements.
            if (Announcements.Count > 400)
            {
                Announcements.RemoveRange(0, Announcements.Count - 300);
            }


            // Virtual resolution
            const int VIRTUAL_WIDTH = 2560;
            const int VIRTUAL_HEIGHT = 1440;

            // Get the actual window size (client bounds)
            Rectangle windowBounds = Window.ClientBounds;
            int windowWidth = windowBounds.Width;
            int windowHeight = windowBounds.Height;

            // Calculate non-uniform scale
            float ScaleX = (float)windowWidth / VIRTUAL_WIDTH;
            float ScaleY = (float)windowHeight / VIRTUAL_HEIGHT;

            // Calculate black bar offset for each axis
            int offsetX = (int)((windowWidth - (VIRTUAL_WIDTH * ScaleX)) / 2f);
            int offsetY = (int)((windowHeight - (VIRTUAL_HEIGHT * ScaleY)) / 2f);

            // Get mouse position relative to the window client area
            MouseState mouseState = Mouse.GetState();
            int msX = mouseState.X;
            int msY = mouseState.Y;

            // Convert to virtual resolution using non-uniform scale
            int virtualX = (int)((msX - offsetX) / ScaleX);
            int virtualY = (int)((msY - offsetY) / ScaleY);

            // Clamp to virtual bounds
            virtualX = Math.Clamp(virtualX, 0, VIRTUAL_WIDTH);
            virtualY = Math.Clamp(virtualY, 0, VIRTUAL_HEIGHT);

            Point scaledMousePosition = new Point(virtualX, virtualY);




            if ((KeysNewlyPressed.Contains(Keys.Escape) || SettingsButton.Clicked()) &&
    GameState != "optionsmenu" &&
    StateToSwitchTo != "optionsmenu" &&
    GameState != "crafting")
            {
                LastStoredGameStateForMenu = GameState;
                SwitchState("optionsmenu", true);

                // Use fixed virtual resolution (2560x1440)
                int screenCenterX = VIRTUAL_WIDTH / 2;
                int sliderRange = 400; // Slider movement range in virtual space

                int minX = screenCenterX - (sliderRange / 2);
                int maxX = screenCenterX + (sliderRange / 2);

                int CalculateSliderX(int volume)
                {
                    float normalized = volume / 100f; // Convert to 0.0 - 1.0
                    int sliderX = minX + (int)(normalized * (maxX - minX));

                    // Center the button around the slider position
                    return sliderX - (MusicSlider.Hitbox.Width / 2);
                }

                // Set sliders' X positions in virtual space
                MusicSlider.Hitbox.X = CalculateSliderX(MusicVolume);
                SoundSlider.Hitbox.X = CalculateSliderX(SoundVolume);
            }





            if (Fade > 0)
            {
                Fade--;
                Fade--;
            }

            if (MoveTicks > 0)
            {
                MoveTicks--;
            }

            if (GameStateSwitchTicks != 250)
            {
                GameStateSwitchTicks += 25;

                if (GameStateSwitchTicks == 0)
                {
                    GameState = StateToSwitchTo;
                    StateToSwitchTo = "";
                }
            }


            if (GameInput != null && FrameCounter != null)
            {
                GameInput.Update();

                if (GameInput.WasKeyPressed(FrameCounter.Key))
                {
                    FrameCounter.RenderFps = !FrameCounter.RenderFps;
                }
                FrameCounter.Update(gameTime);

            }

            if (!AllEnteredGameStates.Contains(GameState))
            {
                AllEnteredGameStates.Add(GameState);
            }
            if (Keyboard.GetState().IsKeyDown(Keys.F9))
            {
                AllEnteredGameStates.Clear();
            }


            FlashTick++;
            if (FlashTick > 99)
            {
                FlashTick = 0;
            }


            ColorTick++;
            if (ColorTick > 360)
            {
                ColorTick = 0;
            }


            //sounds


            /*

            if (currentSoundInstance != null)
            {
                // If the sound is still playing, exit the method to prevent overlap
                if (!(currentSoundInstance.State == SoundState.Playing))
                {
                    // Dispose of the finished sound and reset the instance
                    currentSoundInstance.Dispose();
                    currentSoundInstance = null;
                }

            }
            else if(SFX.Count > 0)
            {
                // Get the first sound effect in the list
                var soundEffect = SFX[0];

                // Create an instance and play the sound
                currentSoundInstance = soundEffect.CreateInstance();
                currentSoundInstance.Play();

                // Remove the sound effect from the list
                SFX.RemoveAt(0);
            }
            */
            
            //clear old intrigue



            int firstDoorIndex = SFX.FindIndex(s => DoorSounds.Contains(s));
            if (firstDoorIndex != -1)
            {
                for (int i = SFX.Count - 1; i >= 0; i--)
                {
                    if (i != firstDoorIndex && DoorSounds.Contains(SFX[i]))
                    {
                        SFX.RemoveAt(i);
                    }
                }
            }

            if ((PlayFrame == 20 && SFX.Count > 0) || (soundTimer <= 0 && SFX.Count > 0))
            {
                SFX[0].Play(volume: 1.0f * (SoundVolume / 100f), pitch: 0.0f, pan: 0.0f);
                soundTimer = (float)SFX[0].Duration.Milliseconds; // Set timer to sound duration.
                SFX.RemoveAt(0);
                PlayFrame = 0;
            }
            else
            {
                PlayFrame++;
                if (soundTimer > 0)
                    soundTimer -= (float)gameTime.ElapsedGameTime.TotalMilliseconds; // Decrement timer.
            }





            KeysNewlyPressed = Keyboard.GetState().GetPressedKeys().ToList();
            List<Keys> KeysToRemove = new();
            foreach (Keys key in KeysNewlyPressed)
            {
                if (previousState.IsKeyDown(key))
                    KeysToRemove.Add(key);
            }
            foreach (Keys key in KeysToRemove)
            {
                KeysNewlyPressed.Remove(key);
            }

            // Define max volume per song
            Dictionary<Song, float> MaxVolume = new()
{
    { Introspection, 1.0f }, { SeaGlass, 0.8f }, { OrangeGlass, 0.2f },
    { SlateBlueGlass, 0.4f }, { WhiteGlass, 0.7f },
    { LightrealmMainTheme, 1.0f }
};

            // Track song play time for auto-fade-out
            if (MediaPlayer.State == MediaState.Playing)
            {
                SongPlayTimer += gameTime.ElapsedGameTime;

                bool NearEnd = SongDuration - SongPlayTimer <= FadeOutThreshold;

                if (NearEnd && !AutoFadeOutTriggered && !IsFadingOut && !IsFadingIn)
                {
                    AutoFadeOutTriggered = true;
                    IsFadingOut = true;
                    IsFadingIn = false;
                    NextSong = MediaPlayer.Queue.ActiveSong; // Restart same song after fade
                }
            }

            bool ShutUp = false;

            // Determine the next song based on game state
            if (MediaPlayer.Queue.ActiveSong != Introspection)
            {
                var stateSongs = new Dictionary<string, Song>
    {
        { "dead", SeaGlass }, { "deadsave", SeaGlass },
        { "optionsmenu", OrangeGlass }, { "exposition", SlateBlueGlass },
        { "savegame", WhiteGlass }, { "savinggame", WhiteGlass },
        { "loadinggame", WhiteGlass }, { "savinggamemenu", WhiteGlass },
        { "loadinggamemenu", WhiteGlass }, { "viewhistory", WhiteGlass },
        { "mainscreen", LightrealmMainTheme }, { "generatingworld", LightrealmMainTheme },
        { "tutorialask", LightrealmMainTheme }, { "findarchitect", LightrealmMainTheme },
        { "credits", LightrealmMainTheme }, { "worldgenscreen", LightrealmMainTheme },
        { "placecivilizations", LightrealmMainTheme }, { "choosegamemode", LightrealmMainTheme },
        { "intermediate", LightrealmMainTheme }, { "generatehistory", LightrealmMainTheme },
        { "choosepreferences", LightrealmMainTheme }, { "findstartlocation", LightrealmMainTheme },
        { "architectfound", LightrealmMainTheme }, { "pickstatpreferences", LightrealmMainTheme },
        { "pickinspirations", LightrealmMainTheme }, { "decidecompanion", LightrealmMainTheme }
    };

                if (stateSongs.TryGetValue(GameState, out var targetSong) &&
                    (targetSong != MediaPlayer.Queue.ActiveSong || MediaPlayer.State == MediaState.Stopped))
                {
                    if (GameState != "exposition" || !StructureExposition)
                    {
                        NextSong = targetSong;
                    }
                }
                else if (!stateSongs.TryGetValue(GameState, out _)) // If no song matches, fade out
                {
                    NextSong = null;
                    ShutUp = true;
                }
            }

            // Handle volume changes
            if (MediaPlayer.Queue.ActiveSong != null)
            {
                bool isSwitchingSongs = NextSong != null &&
                    (MediaPlayer.Queue.ActiveSong != NextSong || MediaPlayer.State == MediaState.Stopped);
                bool hasValidSong = MaxVolume.ContainsKey(MediaPlayer.Queue.ActiveSong);

                float targetVolume = isSwitchingSongs || ShutUp
                    ? 0.0f
                    : (hasValidSong ? MaxVolume[MediaPlayer.Queue.ActiveSong] * (MusicVolume / 100.0f) : 0.0f);

                if (isSwitchingSongs && !IsFadingOut)
                {
                    IsFadingOut = true;
                    IsFadingIn = false;
                }

                if (IsFadingOut)
                {
                    CurrentFadeVolume = Math.Max(CurrentFadeVolume - FadeSpeed, 0.0f);

                    if (CurrentFadeVolume <= 0.0f)
                    {
                        MediaPlayer.Stop();
                        if (NextSong != null)
                        {
                            MediaPlayer.Play(NextSong);

                            // Reset song timer and duration
                            SongPlayTimer = TimeSpan.Zero;
                            SongDuration = NextSong.Duration;
                            AutoFadeOutTriggered = false;
                        }

                        NextSong = null;
                        IsFadingOut = false;
                        IsFadingIn = true;
                        CurrentFadeVolume = 0.0f;
                    }
                }
                else if (IsFadingIn)
                {
                    CurrentFadeVolume = Math.Min(CurrentFadeVolume + (FadeSpeed / 2.0f), targetVolume);
                    if (CurrentFadeVolume >= targetVolume)
                    {
                        IsFadingIn = false;
                    }
                }
                else
                {
                    CurrentFadeVolume = targetVolume;
                }

                MediaPlayer.Volume = CurrentFadeVolume;
            }
            else if (NextSong != null)
            {
                MediaPlayer.Play(NextSong);
                SongPlayTimer = TimeSpan.Zero;
                SongDuration = NextSong.Duration;
                AutoFadeOutTriggered = false;

                NextSong = null;
                IsFadingIn = true;
                IsFadingOut = false;
                CurrentFadeVolume = 0.0f;
            }
            if (OKCompanion.Clicked() && CompanionMessages.Count > 0)
            {
                CompanionMessages.RemoveAt(0);
            }



            KeyboardState ShiftTestState = Keyboard.GetState();

