            {
                CommandBuilderStage = "none";
                SelectedCategory = "";
                SelectedCommand = "";
                CurrentSubjectIndex = 0;
                RelevantEntities.Clear();
                SelectedEntities.Clear();
            }

            //everything else lul

            if (WaitingTicks > 0)
            {
                WaitingTicks = WaitingTicks - 1;
            }
            else
            {
                if (WaitingTicks == 0)
                {
