                    else if (GameState == "optionsmenu")
                    {
                        // Define slider min and max bounds (for the CENTER of the button)
                        int centerX = 2560 / 2; // Center of the screen in original resolution
                        int minX = centerX - 200; // Minimum bound for CENTER of the slider
                        int maxX = centerX + 200; // Maximum bound for CENTER of the slider

                        // Check if the left mouse button is pressed
                        bool mousePressed = currentMouseState.LeftButton == ButtonState.Pressed;

                        // Function to calculate volume from slider center position
                        int CalculateVolume(int sliderCenterX)
                        {
                            float normalized = (sliderCenterX - minX) / (float)(maxX - minX); // Normalize to 0-1 range
                            return (int)(normalized * 100); // Scale to 0-100
                        }

                        Point virtMousePos = scaledMousePosition;

                        bool musicClicked = MusicSlider.Pressed();
                        bool soundClicked = SoundSlider.Pressed();

                        // If user clicked on music slider and we are not already locked on the sound slider
                        if (musicClicked && !SoundLockedToX)
                        {
                            // Switch to music
                            MusicLockedToX = true;
                            SoundLockedToX = false;
                        }
                        else if (soundClicked && !MusicLockedToX)
                        {
                            // Switch to sound
                            SoundLockedToX = true;
                            MusicLockedToX = false;
                        }

                        // Now handle whichever is locked:
                        if (MusicLockedToX)
                        {
                            if (mousePressed)
                            {
                                int sliderCenterX = Math.Clamp(virtMousePos.X, minX, maxX);
                                MusicSlider.Hitbox.X = sliderCenterX - (MusicSlider.Hitbox.Width / 2);

                                MusicVolume = CalculateVolume(sliderCenterX);
                            }
                            else
                            {
                                // Mouse released
                                MusicLockedToX = false;
                            }
                        }

                        if (SoundLockedToX)
                        {
                            if (mousePressed)
                            {
                                int sliderCenterX = Math.Clamp(virtMousePos.X, minX, maxX);
                                SoundSlider.Hitbox.X = sliderCenterX - (SoundSlider.Hitbox.Width / 2);

                                SoundVolume = CalculateVolume(sliderCenterX);
                            }
                            else
                            {
                                // Mouse released
                                SoundLockedToX = false;
                            }
                        }

                        if (MaxAutosaveAgeButton.Clicked())
