                                // Get the monitor's current display mode
                                int dw = GraphicsAdapter.DefaultAdapter.CurrentDisplayMode.Width;
                                int dh = GraphicsAdapter.DefaultAdapter.CurrentDisplayMode.Height;

                                // Force the resolution to the default / native
                                TempPBBW = dw;
                                TempPBBH = dh;
                            }

                            // 2) Apply the temporary resolution
                            PreferredBackBufferWidth = TempPBBW;
                            PreferredBackBufferHeight = TempPBBH;

                            _graphics.PreferredBackBufferWidth = PreferredBackBufferWidth;
