                            // 3) Apply the window mode
                            switch (WindowTypes[CurrentWindowModeIndex])
                            {
                                case "Windowed":
                                    _graphics.IsFullScreen = false;
                                    _graphics.HardwareModeSwitch = true;  // Normal window switching
