                                            Material m = Game1.GameWorld.Materials.FirstOrDefault(mat => mat.Key == materialName).Value;

                                            if (m != null)
                                            {
                                                EntityList<Material> materials = new EntityList<Material> { m };

                                                if (itemName == "armor")
