                                                    foreach (var armorPart in armorParts)
                                                    {
                                                        // Remove any existing item of this type, regardless of material
                                                        CraftingArchitect.Clothing.RemoveAll(obj => obj.Type == armorPart);

                                                        // Add new one
                                                        CraftingArchitect.Clothing.Add(new Object(null, armorPart, materials, null));
                                                    }
                                                }
                                                else if (WearableItems.Contains(itemName))
                                                {
                                                    // Remove any existing item of the same type (even if different material)
                                                    CraftingArchitect.Clothing.RemoveAll(obj => obj.Type == itemName);

                                                    // Add the new clothing item
                                                    CraftingArchitect.Clothing.Add(new Object(null, itemName, materials, null));
