                                        string inside = input.Substring(1, input.Length - 2); // Remove brackets
                                        string[] values = inside.Split('/');

                                        if (values.Length == 7 && values.All(v => int.TryParse(v, out _)))
                                        {
                                            int[] stats = values.Select(int.Parse).ToArray();

