                                GameWorld = null;
                                MostRecentPartyTurnArchitect = null;
                            }

                            SwitchState(StateToSwitchToAfterSave, false);
                        }
                    }
                    else if (GameState == "loadinggamemenu")
                    {
                        var saveDirectories = Directory.GetDirectories(DocumentsFolderPath + "/.LightrealmData");
                        int SavesCount = saveDirectories.Count();

                        if (SavesCount > 0)
                        {
                            // Constants for text layout
                            int startingY = 350; // Matches the text layout starting Y position
                            int boxHeight = 30;  // Matches the line height used in the text layout
                            int boxWidth = 2000; // Arbitrary width, large enough to encompass the text rendering area
                            int startX = 200;    // Matches the horizontal starting position of the text

                            int visibleIndex = 0; // Track only valid save entries

                            string[] validSaveDirectories = saveDirectories
                                .Where(d => !d.EndsWith("crashreports", StringComparison.OrdinalIgnoreCase))
                                .ToArray(); // Exclude "crashreports" directory

                            for (int i = 0; i < saveDirectories.Length; i++)
                            {
                                if (saveDirectories[i].EndsWith("crashreports", StringComparison.OrdinalIgnoreCase))
                                    continue; // Skip crashreports

                                // Define the logical rectangle for each save game based on pre-scaled text positions
                                Rectangle saveBox = new Rectangle(startX, startingY + visibleIndex * boxHeight, boxWidth, boxHeight);

                                // Check if the scaled mouse position is within the logical rectangle
                                if (saveBox.Contains(scaledMousePosition) && currentMouseState.LeftButton == ButtonState.Pressed)
                                {
                                    LoadGameCursor = visibleIndex; // Set the cursor to the selected valid save game index
                                    SelectedDirectory = validSaveDirectories[LoadGameCursor]; // Update directory reference
                                }

                                visibleIndex++; // Increment only for valid saves
                            }

                            if (validSaveDirectories.Length > 0)
                            {
                                if(LoadGameCursor >= validSaveDirectories.Count())
                                {
                                    LoadGameCursor = validSaveDirectories.Count() - 1;
                                }

                                var versionFilePath = Path.Combine(validSaveDirectories[LoadGameCursor], "version.txt");
                                if (File.Exists(versionFilePath))
                                {
                                    // Check for Enter key press to load the selected save game
                                    if (PlayButton.Clicked())
                                    {
                                        GameState = SpeechToText ? "loadinglibraries" : "loadinggame";
                                        SeenTips = true;
                                        GoToLoadingGameAfterLibrariesAreInstalled = true;
                                        SelectedDirectory = validSaveDirectories[LoadGameCursor];
                                    }

                                    // Check for H key press to view history of the selected save game
                                    if (ViewHistoryButton.Clicked())
                                    {
                                        var lines = File.ReadAllLines(Path.Combine(validSaveDirectories[LoadGameCursor], "history.txt"));

                                        // Initialize CurrentlyViewingHistory with (line, false)
                                        CurrentlyViewingHistory = lines.Select(line => (line, false)).ToList();

                                        SwitchState("viewhistory", false);

                                        HistoricalScrollValue = 0;
                                        OtherPrompt = "";
                                        MaxRegionIndex = CurrentlyViewingHistory
                                            .Select(entry =>
                                            {
                                                int regionIndex;
                                                string[] parts = entry.Item1.Trim('[', ']').Split('/');
                                                if (parts.Length > 0 && int.TryParse(parts[0], out regionIndex) && regionIndex != 11)
                                                {
                                                    return regionIndex;
                                                }
                                                return 0;
                                            })
                                            .Max();
                                    }
                                }

                                // Check for Delete key press to delete the selected save game
                                if (DeleteButton.Clicked())
                                {
                                    SwitchState("deletinggame", false);
                                    SelectedDirectory = validSaveDirectories[LoadGameCursor];
                                }
                            }
                        }

                        // Handle ESC key to return to the main screen
                        if (KeysNewlyPressed.Contains(Keys.Escape) || ReturnToTitleFromLoad.Clicked())
                        {
                            SwitchState("mainscreen", false);
                        }
                    }


                    else if (GameState == "viewhistory")
                    {
                        if (currentMouseState.ScrollWheelValue < previousMouseState.ScrollWheelValue)
                        {
                            if (Keyboard.GetState().IsKeyDown(Keys.LeftControl))
                            {
                                HistoricalScrollValue += 10;
                            }
                            else
                            {
                                HistoricalScrollValue += 1;
                            }
                        }
                        else if (currentMouseState.ScrollWheelValue > previousMouseState.ScrollWheelValue)
                        {
                            if (Keyboard.GetState().IsKeyDown(Keys.LeftControl))
                            {
                                HistoricalScrollValue -= 10;
                            }
                            else
                            {
                                HistoricalScrollValue -= 1;
                            }

                            if (HistoricalScrollValue < 0)
                            {
                                HistoricalScrollValue = 0;
                            }
                        }


                        if (currentMouseState.LeftButton == ButtonState.Pressed && previousMouseState.LeftButton == ButtonState.Released)
                        {
                            foreach (var (hitbox, originalIndex) in HistoricalHitboxes)
                            {
                                if (hitbox.Contains(scaledMousePosition))
                                {
                                    // Center the clicked event
                                    HistoricalScrollValue = Math.Max(0, originalIndex - 25);

                                    // Clear the search prompt
                                    OtherPrompt = "";

                                    if (originalIndex >= 0 && originalIndex < CurrentlyViewingHistory.Count)
                                    {
                                        var (text, isSpecial) = CurrentlyViewingHistory[originalIndex];
                                        CurrentlyViewingHistory[originalIndex] = (text, !isSpecial);
                                    }
                                    break; // Only handle the first hitbox clicked
                                }
                            }
                        }




                        if (KeysNewlyPressed.Contains(Keys.Escape) || ReturnToTitleFromHistory.Clicked())
                        {
                            SwitchState("loadinggamemenu", false);
                        }

                        foreach (Keys k in KeysNewlyPressed)
                        {
                            if (KeyAtlas.ContainsKey(k) && !Keyboard.GetState().IsKeyDown(Keys.LeftControl))
                            {
                                OtherPrompt += KeyAtlas[k];
                                HistoricalScrollValue = 0;
                            }
                            else if (k == Keys.Back && OtherPrompt.Length > 0)
                            {
                                OtherPrompt = OtherPrompt.Substring(0, OtherPrompt.Length - 1);
                                HistoricalScrollValue = 0;
                            }
                            else if (k == Keys.X)
                            {
                                // Set to 0 if '0' is pressed
                                CurrentlySelectingRegionIndexOr100 = 100;
                                HistoricalScrollValue = 0;
                            }
                            else if (k >= Keys.D1 && k <= Keys.D9)
                            {
                                int selectedRegionIndex = k - Keys.D1 + 1;
                                if (selectedRegionIndex <= MaxRegionIndex)
                                {
                                    CurrentlySelectingRegionIndexOr100 = selectedRegionIndex;
                                    HistoricalScrollValue = 0;
                                }
                            }
                            else if (k >= Keys.NumPad1 && k <= Keys.NumPad9)
                            {
                                int selectedRegionIndex = k - Keys.NumPad1 + 1;
                                if (selectedRegionIndex <= MaxRegionIndex)
                                {
                                    CurrentlySelectingRegionIndexOr100 = selectedRegionIndex;
                                    HistoricalScrollValue = 0;
                                }
                            }
                            else if (k == Keys.S)
                            {
                                ShowSignificant = !ShowSignificant;
                                HistoricalScrollValue = 0;
                            }
                        }
                    }

                    else if (GameState == "deletinggame")
                    {
                        if (KeysNewlyPressed.Contains(Keys.Y) && (Keyboard.GetState().IsKeyDown(Keys.LeftControl) || Keyboard.GetState().IsKeyDown(Keys.RightControl)))
                        {
                            string[] files = Directory.GetFiles(SelectedDirectory);

