                                GameWorld.InitialCivCount = GameWorld.InitialCivCount - 1;
                            }
                            else
                            {
                                TotalCivTries++;
                                if (TotalCivTries > 300)
                                {
                                    throw new Exception("Couldnt place civs? Is the whole world ocean?");
