                                        Announcements.Add(new TextStorage("Your status as autocrat has granted you additional associates and resources.", Color.AliceBlue, new EntityList<Entity>() { }));

                                        int people = Game1.r.Next(6, 9);

                                        var validArchitects = c.Capitol.Districts[0].DistrictArchitects
                                            .Where(a => a.IsAlive && !a.Bound)
                                            .ToList();

                                        for (int i = 0; i != people && validArchitects.Count > 0; i++)
                                        {
                                            Architect a = validArchitects[Game1.GameWorld.rnd.Next(validArchitects.Count)];
                                            validArchitects.Remove(a); // Prevent duplicates

                                            if (!GameWorld.GamePlayerAssociation.Associates.Contains(a))
                                            {
                                                GameWorld.GamePlayerAssociation.Associates.Add(a);
                                                a.PopulateSelf(true);
                                            }
                                        }

                                        SupplyAssociation();
                                    }
                                    else if (CurrentlySelectingStarterValue == 2)
                                    {
                                        Announcements.Add(new TextStorage("Your status as monarch has granted you many additional associates and resources.", Color.AliceBlue, new EntityList<Entity>() { }));

                                        int people = Game1.r.Next(15, 30);

                                        var validCitizens = c.Citizens
                                            .Where(a => a.IsAlive && !a.Bound)
                                            .ToList();

                                        for (int i = 0; i != people && validCitizens.Count > 0; i++)
                                        {
                                            Architect a = validCitizens[Game1.GameWorld.rnd.Next(validCitizens.Count)];
                                            validCitizens.Remove(a); // Prevent duplicates

                                            if (!GameWorld.GamePlayerAssociation.Associates.Contains(a))
                                            {
                                                GameWorld.GamePlayerAssociation.Associates.Add(a);
                                                a.PopulateSelf(true);
                                            }
                                        }

                                        SupplyAssociation();
                                        SupplyAssociation();
                                        SupplyAssociation();
