                                    // Determine the number of architects
                                    int totalArchitects = GameWorld.GamePlayerAssociation.Associates.Count;

                                    // Calculate the number of parties needed (each party having 3-5 members)
                                    int minPerParty = 3;
                                    int maxPerParty = 5;
                                    int numParties = (int)Math.Ceiling((double)totalArchitects / maxPerParty);

                                    // Shuffle architects randomly to distribute them more organically
                                    var shuffledArchitects = GameWorld.GamePlayerAssociation.Associates.ToList();
                                    Shuffle(shuffledArchitects);  // Assuming you have a shuffle function

                                    // Distribute architects among parties
                                    List<Party> newParties = new List<Party>();
                                    for (int i = 0; i < numParties; i++)
                                    {
                                        int remaining = shuffledArchitects.Count;
                                        int membersInThisParty = Math.Min(remaining, Game1.r.Next(minPerParty, maxPerParty + 1));

                                        if (membersInThisParty <= 0) break;

                                        EntityList<Architect> partyArchitects = new EntityList<Architect>();
                                        for (int j = 0; j < membersInThisParty; j++)
                                        {
                                            partyArchitects.Add(shuffledArchitects[0]);
                                            shuffledArchitects.RemoveAt(0);
                                        }

                                        // Select the first Architect as the leader (or choose based on other criteria)
                                        Architect leader = partyArchitects[0];

                                        // Create a new party and add it to the Association
                                        Party newParty = new Party(partyArchitects, "political", leader, GameWorld.GamePlayerAssociation.Parties[0].Base);
                                        newParties.Add(newParty);
                                    }

                                    // Replace the single-party system with the new party list
