                                            string Date = "(" + Month + "/" + Year + ")";
                                            Game1.GameWorld.HistoricalEvents.Add(new Event(Date + " " + a.Name + " migrated to " + c.Capitol.Name + " for the declaration of " + c.Alpha.Name + ".", c.Capitol.Region, new EntityList<Entity>() { a, c.Capitol, c.Alpha }));

