                            StoragePage = StorageCursor / ItemsPerPage;

                            // Function to find the containing object (container) above the selected entry
                            Object GetContainingObject(int index)
                            {
                                int selectedIndent = StructuredStorageList[index].IndentationLevel;

                                for (int i = index - 1; i >= 0; i--)
                                {
                                    if (StructuredStorageList[i].IndentationLevel < selectedIndent)
                                        return StructuredStorageList[i].Obj;
                                }

                                return null;
