                            Object GetContainingObject(int index, List<(string Description, int Count, int IndentationLevel, Color TextColor, Object Obj)> list)
                            {
                                int selectedIndent = list[index].IndentationLevel;
                                for (int i = index - 1; i >= 0; i--)
                                {
                                    if (list[i].IndentationLevel < selectedIndent)
                                        return list[i].Obj;
                                }
                                return null;
