                                string type = selectedEntry.Obj.Type;
                                var materials = selectedEntry.Obj.Materials;
                                int count = takeStack ? selectedEntry.Count : 1;

                                EntityList<Object> source;

                                if (selectedEntry.IndentationLevel > 0)
                                {
                                    // Take from the container directly
                                    var container = GetContainingObject(ArchitectItemCursor, StructuredArchitectItemList);
                                    source = container.ContainedObjects;
                                }
                                else
                                {
                                    // Flatten from architect's inventory/clothing
                                    source = new EntityList<Object>();
                                    source.AddRange(selectedArchitect.Clothing);
                                    source.AddRange(selectedArchitect.Inventory);
                                    if (selectedArchitect.MainHeldObject != null)
                                        source.Add(selectedArchitect.MainHeldObject);
                                    if (selectedArchitect.OffHeldObject != null)
                                        source.Add(selectedArchitect.OffHeldObject);
                                }

                                var toTransfer = source
                                    .Where(o => o.Type == type && o.Materials.SequenceEqual(materials))
                                    .Take(count)
                                    .ToList();

                                foreach (var obj in toTransfer)
                                {
                                    if (selectedEntry.IndentationLevel > 0)
                                    {
                                        // Container removal
                                        var container = GetContainingObject(ArchitectItemCursor, StructuredArchitectItemList);
                                        container?.ContainedObjects.Remove(obj);
                                    }
                                    else
                                    {
                                        // Normal removal
                                        if (selectedArchitect.Clothing.Contains(obj))
                                            selectedArchitect.Clothing.Remove(obj);
                                        else if (selectedArchitect.Inventory.Contains(obj))
                                            selectedArchitect.Inventory.Remove(obj);
                                        else if (selectedArchitect.MainHeldObject == obj)
