                                        else if (selectedArchitect.OffHeldObject == obj)
                                            selectedArchitect.OffHeldObject = null;
                                    }

                                    GameWorld.GamePlayerAssociation.Resources.Add(obj);
                                }

                                // Rebuild list
                                var updatedItems = selectedArchitect.Clothing.Union(selectedArchitect.Inventory).ToList();
                                if (selectedArchitect.MainHeldObject != null)
                                    updatedItems.Add(selectedArchitect.MainHeldObject);
                                if (selectedArchitect.OffHeldObject != null)
                                    updatedItems.Add(selectedArchitect.OffHeldObject);

                                StructuredArchitectItemList = CondenseAndStructureList(updatedItems, false);
                                if (ArchitectItemCursor >= StructuredArchitectItemList.Count)
                                    ArchitectItemCursor = StructuredArchitectItemList.Count - 1;
                            }
