                                int count = items.Count;
                                if (count == 0)
                                {
                                    return "";
                                }
                                else if (count == 1)
                                {
                                    return items[0];
                                }
                                else if (count == 2)
                                {
                                    return $"{items[0]} and {items[1]}"; // No comma for two items
                                }
                                else
                                {
                                    string lastItem = items[count - 1];
                                    string otherItems = string.Join(", ", items.GetRange(0, count - 1));
                                    return $"{otherItems}, and {lastItem}";
                                }
