                                var combatants = LoadedArchitects
                                    .Where(a => !string.IsNullOrEmpty(a.CombatTag))
                                    .ToList();

                                for (int i = 0; i < combatants.Count; i += 2)
                                {
                                    if (i + 1 >= combatants.Count)
                                        break;

                                    var a1 = combatants[i];
                                    var a2 = combatants[i + 1];

                                    // Extract weapon types from CombatTag
                                    string[] parts1 = a1.CombatTag.Split(' ');
                                    string[] parts2 = a2.CombatTag.Split(' ');

                                    if (parts1.Length < 2 || parts2.Length < 2)
                                        continue;

                                    // Use sorted order for consistency
                                    string weapon1 = string.Compare(parts1[0], parts1[1]) < 0 ? parts1[0] : parts1[1];
                                    string weapon2 = string.Compare(parts1[0], parts1[1]) < 0 ? parts1[1] : parts1[0];
                                    string key = weapon1 + " vs " + weapon2;

                                    if (!duelResults.ContainsKey(key))
                                        duelResults[key] = (weapon1, weapon2, 0, 0);

                                    if (a1.IsAlive && !a2.IsAlive)
                                    {
                                        if (parts1[0] == weapon1)
                                            duelResults[key] = (weapon1, weapon2, duelResults[key].winsA + 1, duelResults[key].winsB);
                                        else
                                            duelResults[key] = (weapon1, weapon2, duelResults[key].winsA, duelResults[key].winsB + 1);
