                                            string ConvertToFullDirection(string shortDirection)
                                            {
                                                switch (shortDirection)
                                                {
                                                    case "N":
                                                        return "north";
                                                    case "NE":
                                                        return "northeast";
                                                    case "E":
                                                        return "east";
                                                    case "SE":
