                        }

                        if (ReturnFromImbuements.Clicked())
                        {
                            SwitchState("partyturn", false);
                        }
                    }
                    else if (GameState == "partymanagement")
                    {
                        bool TryingToExpunge = Keyboard.GetState().IsKeyDown(Keys.LeftShift) && Keyboard.GetState().IsKeyDown(Keys.LeftControl);

                        foreach ((Rectangle rect, Architect architect, Color color) in ArchitectRects)
                        {
                            if (rect.Contains(scaledMousePosition) &&
                                currentMouseState.LeftButton == ButtonState.Pressed &&
                                previousMouseState.LeftButton == ButtonState.Released)
                            {
                                if (TryingToExpunge && Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects.Count() > 1)
                                {
                                    if (Game1.GameWorld.HumanoidRaces.Contains(architect.Race))
                                        architect.AnnounceToParty(architect.Name.Split()[0] + ": See you around.", Color.LimeGreen, new EntityList<Entity>() { architect });

                                    Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects.Remove(architect);
                                    Game1.GameWorld.GamePlayerAssociation.Associates.Remove(architect);

                                }
                                else
                                {

                                    int activeCount = Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects.Count(a => a.PartyActive);

                                    if (architect.PartyActive && activeCount > 1)
                                    {
                                        // Deactivate architect if there's more than one active
                                        architect.PartyActive = false;
                                        Game1.TurnPage.Play(volume: 0.2f * (SoundVolume / 100f), pitch: 0.0f, pan: 0.0f);
                                    }
                                    else if (!architect.PartyActive)
                                    {
                                        // Activate the architect
                                        architect.PartyActive = true;
                                        Game1.TurnPage.Play(volume: 0.2f * (SoundVolume / 100f), pitch: 0.0f, pan: 0.0f);
                                    }
                                    // else: Do nothing if trying to deactivate the last active architect
                                }
                            }
                        }

                        if (ReturnFromPartyManage.Clicked())
                        {
                            SwitchState("partyturn", false);
                        }
                    }

                    else if (GameState == "deadsave")
                    {
                        if(LastLoadedDistrict != null && LastLoadedDistrict.IsLoaded)
                            LastLoadedDistrict.Unload();

                        LastLoadedDistrict = null;

                        string originalSaveName = (GameWorld.GamePlayerAssociation != null && GameWorld.GamePlayerAssociation.ActiveParty != null)
                            ? "Legacy of " + GameWorld.GamePlayerAssociation.ActiveParty.originalLeader.Name +
                              ", leader of " + GameWorld.GamePlayerAssociation.ActiveParty.Name +
                              " in " + GameWorld.Name.First().ToString().ToLower() + GameWorld.Name.Substring(1)
                            : GameWorld.Name;

                        string originalSavePath = Path.Combine(DocumentsFolderPath, ".LightrealmData", originalSaveName);

                        // Delete the old save directory if it exists
                        if (Directory.Exists(originalSavePath))
                        {
                            Directory.Delete(originalSavePath, true); // true => recursive delete
                        }



                        GameWorld.GamePlayerAssociation = null;

                        foreach (Region r in GameWorld.WorldMap)
                        {
                            r.Explored = false;
                            r.DeepExplored = false;
                            if (r.Location != null)
                            {
                                r.Location.Explored = false;
                            }
                        }

                        GameWorld.GameMode = "unknown";

                        SaveGame(GameWorld, true);

                        Announcements = new List<TextStorage>();

                        if (RestartGame)
                        {
                            GameState = "choosegamemode";
                        }
                        else
                        {
                            GameState = "mainscreen";
                            GameWorld = null;
                        }

                        MostRecentPartyTurnArchitect = null;

                        MediaPlayer.Stop();
                        MediaPlayer.Play(LightrealmMainTheme);
                    }
                    else if (GameState == "otherturn")
                    {
                        StoredAttack = null;

                        if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Count() == 0 || !(GameWorld.GamePlayerAssociation.ActiveParty.Architects.Any(a => a.IsAlive == true)))
                        {
                            if (StateToSwitchTo != "dead" && GameState != "dead")
                            {
                                MostRecentPartyTurnArchitect.CompanionMessage("alldeath", "");
                                RestoreBlindAnnouncements();
                            }
                            SwitchState("dead", false);
                            
                        }
                        else
                        {
                            // We initialize a loop that continues until we find a party member or trigger a reaction state
                            while (true)
                            {
                                // Ensure the ArchitectIndex wraps around if it exceeds the number of loaded architects
                                ArchitectIndex %= LoadedArchitects.Count();
                                Architect currentArchitect = LoadedArchitects[ArchitectIndex];

                                Attack attack = currentArchitect.UpdateSelfActionsAndSuch();

                                if (attack != null)
                                {
                                    if (attack.Attacker.IsAlive == false)
                                    {
                                        continue;
                                    }

                                    if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Any(a => a.BodyParts.Contains(attack.Target)))
                                    {
                                        StoredAttack = attack;
                                        MostRecentPartyTurnArchitect = (Architect)(attack.Target.Owner);
                                        GameState = "reaction";
                                        MostRecentPartyTurnArchitect.CompanionMessage("reactions", "");
                                    }
                                    else
                                    {
                                        CalculateAttack(attack.Verb, attack.Attacker, attack.Target, "decideforme", attack.Weapon);
                                    }
                                }

                                if (GameState == "reaction")
                                {
                                    InInventory = false;
                                    Inventory.Hitbox.X = 400;
                                    break; // If reaction state is triggered, exit early
                                }
                                // If the architect is a party member, switch to party turn and break
                                if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Contains(currentArchitect) && !currentArchitect.TemporarilyIncapacitated() && currentArchitect.PartyActive)
                                {
                                    if (currentArchitect.RuptureMode == true)
                                    {
                                        SwitchState("triggerrupture", false);
                                        InInventory = false;
                                        Inventory.Hitbox.X = 400;
                                    }
                                    else if (currentArchitect.TryPickUpItemType != "")
                                    {
                                        GameState = "trypickup";
                                        InInventory = false;
                                        Inventory.Hitbox.X = 400;
                                    }
                                    else if (currentArchitect.TryDropItemType != "")
                                    {
                                        GameState = "trydrop";
                                        InInventory = false;
                                        Inventory.Hitbox.X = 400;
                                    }
                                    else if (currentArchitect.TryTakeItemType != "")
                                    {
                                        GameState = "trytake"; // Redirect to item selection when taking from a container
                                        InInventory = false;
                                        Inventory.Hitbox.X = 400;
                                    }
                                    else if (currentArchitect.TryPlaceItemType != "")
                                    {
                                        GameState = "tryplace"; // Redirect to item selection when placing into a container
                                        InInventory = false;
                                        Inventory.Hitbox.X = 400;
                                    }
                                    else if (currentArchitect.MessagesNotRespondedTo.Count() > 0)
                                    {
                                        GameState = "messagereply";
                                        MostRecentPartyTurnArchitect = currentArchitect;
                                        InInventory = false;
                                        Inventory.Hitbox.X = 400;

                                        MostRecentPartyTurnArchitect.CompanionMessage("messagetoyou", "");
                                    }
                                    else
                                    {
                                        GameState = "partyturn";
                                    }

                                    break; // Break from the while loop to switch to party turn
                                }

                                IncrementAndCycleWorld();
                                if (GameState != "otherturn")
                                {
                                    break;
                                }
                            }
                        }
                    }

                    else if (GameState == "triggerrupture")
                    {
                        if (KeysNewlyPressed.Contains(Keys.R) || KeysNewlyPressed.Contains(Keys.T) || KeysNewlyPressed.Contains(Keys.D) || KeysNewlyPressed.Contains(Keys.G) || KeysNewlyPressed.Contains(Keys.C) || KeysNewlyPressed.Contains(Keys.V) || KeysNewlyPressed.Contains(Keys.NumPad7) || KeysNewlyPressed.Contains(Keys.NumPad9) || KeysNewlyPressed.Contains(Keys.NumPad4) || KeysNewlyPressed.Contains(Keys.NumPad6) || KeysNewlyPressed.Contains(Keys.NumPad1) || KeysNewlyPressed.Contains(Keys.NumPad3))
                        {
                            int DeltaX = 0;
                            int DeltaZ = 0;

                            if (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ % 2 == 0)
                            {
                                //every other row starting with the top one

                                if (KeysNewlyPressed.Contains(Keys.R) || KeysNewlyPressed.Contains(Keys.NumPad7))
                                {
                                    DeltaX = -1;
                                    DeltaZ = -1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.T) || KeysNewlyPressed.Contains(Keys.NumPad9))
                                {
                                    DeltaZ = -1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.D) || KeysNewlyPressed.Contains(Keys.NumPad4))
                                {
                                    DeltaX = -1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.G) || KeysNewlyPressed.Contains(Keys.NumPad6))
                                {
                                    DeltaX = 1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.C) || KeysNewlyPressed.Contains(Keys.NumPad1))
                                {
                                    DeltaX = -1;
                                    DeltaZ = 1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.V) || KeysNewlyPressed.Contains(Keys.NumPad3))
                                {
                                    DeltaZ = 1;
                                }
                            }
                            else
                            {
                                //every other row starting with the second-to-top one

                                if (KeysNewlyPressed.Contains(Keys.R) || KeysNewlyPressed.Contains(Keys.NumPad7))
                                {
                                    DeltaZ = -1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.T) || KeysNewlyPressed.Contains(Keys.NumPad9))
                                {
                                    DeltaZ = -1;
                                    DeltaX = 1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.D) || KeysNewlyPressed.Contains(Keys.NumPad4))
                                {
                                    DeltaX = -1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.G) || KeysNewlyPressed.Contains(Keys.NumPad6))
                                {
                                    DeltaX = 1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.C) || KeysNewlyPressed.Contains(Keys.NumPad1))
                                {
                                    DeltaZ = 1;
                                }
                                else if (KeysNewlyPressed.Contains(Keys.V) || KeysNewlyPressed.Contains(Keys.NumPad3))
                                {
                                    DeltaZ = 1;
                                    DeltaX = 1;
                                }
                            }

                            if (!(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX > GameWorld.Width || GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX < 0 || GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ > GameWorld.Length || GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ < 0))
                            {
                                GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX += DeltaX;
                                GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ += DeltaZ;

                            }

                        }


                        if (KeysNewlyPressed.Contains(Keys.Enter))
                        {
                            GameWorld.TriggerRupture(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX, GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ, MostRecentPartyTurnArchitect, 10);

                            MostRecentPartyTurnArchitect.RuptureMode = false;

                            if (MostRecentPartyTurnArchitect.Location.Region.Biome == "ethereal")
                            {
                                MakeObservation(MostRecentPartyTurnArchitect.Name + " successfully killed themselves in the fractal rift. How embarrassing...", Color.Magenta, new EntityList<Entity>() { LoadedArchitects[ArchitectIndex] });
                                MostRecentPartyTurnArchitect.IsAlive = false;
                                if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Contains(MostRecentPartyTurnArchitect))
                                {
                                    GameWorld.GamePlayerAssociation.ActiveParty.Architects.Remove(MostRecentPartyTurnArchitect);

                                    if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Count() == 0)
                                    {
                                        if (StateToSwitchTo != "dead" && GameState != "dead")
                                        {
                                            Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects[0].CompanionMessage("alldeath", "");
                                            RestoreBlindAnnouncements();
                                        }
                                        SwitchState("dead", false);

                                    }
                                }
                            }
                            else
                            {

                                if (MostRecentPartyTurnArchitect.CooldownCycles > 0)
                                {
                                    IncrementAndCycleWorld();
                                }
                                if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Contains(MostRecentPartyTurnArchitect))
                                {
                                    GameState = "partyturn";
                                }
                                else
                                {
                                    GameState = "otherturn";
                                }

                            }
                        }
                    }
                    else if (GameState == "charedit")
                    {
                        void ConsumeDye(string color)
                        {
                            // Try removing dye from direct inventory first
                            var dyeItem = MostRecentPartyTurnArchitect.Inventory.FirstOrDefault(item =>
                                item.Type == "dye" && item.Materials.Any(mat => mat.Color == color));

                            if (dyeItem != null)
                            {
                                MostRecentPartyTurnArchitect.Inventory.Remove(dyeItem);
                                return;
                            }

                            // If not found, check containers
                            foreach (var container in MostRecentPartyTurnArchitect.Inventory.Where(item => item.ContainedObjects != null))
                            {
                                foreach (var containedItem in container.ContainedObjects.ToList()) // Copy list to avoid modifying during iteration
                                {
                                    if (containedItem.Type == "dye" && containedItem.Materials.Any(mat => mat.Color == color))
                                    {
                                        container.ContainedObjects.Remove(containedItem); // Remove one dye
                                        return; // Stop after consuming one
                                    }
                                }
                            }
                        }



                        if (currentMouseState.LeftButton == ButtonState.Pressed && previousMouseState.LeftButton == ButtonState.Released)
                        {
                            foreach (var (clothingItem, hideButton, dyeButtons) in StoredClothingButtons)
                            {

                                // Check if the flashing transparent button was clicked
                                if (hideButton.Contains(scaledMousePosition))
                                {
                                    // Gather a list of all vitalium fragments in the inventory
                                    var vitaliumFragments = MostRecentPartyTurnArchitect.Inventory
                                        .Where(item => item.Type == "fragment" && item.Materials.Count > 0 && item.Materials[0].Name == "vitalium")
                                        .ToList(); // Convert to list to avoid modifying the collection during iteration

                                    if (vitaliumFragments.Count >= 10) // Ensure the player has at least 10 fragments
                                    {
                                        IceShock.Play((SoundVolume / 2) / 100f, 0.0f, 0.0f);
                                        clothingItem.ClothingVisible = !clothingItem.ClothingVisible; // Toggle visibility

                                        // Remove exactly 10 fragments
                                        for (int i = 0; i < 10; i++)
                                        {
                                            MostRecentPartyTurnArchitect.Inventory.Remove(vitaliumFragments[i]);
                                        }

                                        MostRecentPartyTurnArchitect.RunFragmentCheck();
                                    }
                                    else
                                    {
                                        // Play a sound or show a message indicating insufficient fragments
                                        MenuSelect.Play(SoundVolume / 100f, 0.0f, 0.0f);
                                    }
                                }


                                // Check if any color button was clicked
                                for (int i = 0; i < dyeButtons.Count; i++)
                                {
                                    if (dyeButtons[i].Contains(scaledMousePosition))
                                    {
                                        string selectedColor = ColorConverter.Keys.ElementAt(i);

                                        // Check if the player has the correct dye
                                        if (HasDyeInInventory(selectedColor))
                                        {
                                            // Play sound effect and apply the dye
                                            MenuSelect.Play(SoundVolume / 100f, 0.0f, 0.0f);
                                            clothingItem.DyedColor = selectedColor;

                                            // Consume the dye
                                            ConsumeDye(selectedColor);
                                        }
                                    }
                                }
                            }
                        }


                        if (ReturnFromClothingThing.Clicked() || KeysNewlyPressed.Contains(Keys.Escape))
                        {
                            SwitchState("partyturn", false);
                        }
                    }
                    else if (GameState == "partymanagement")
                    {

                    }
                    else if (GameState == "reaction")
                    {
                        // Get the current and previous mouse states
                        bool mousePressed = currentMouseState.LeftButton == ButtonState.Pressed;
                        bool previousMousePressed = previousMouseState.LeftButton == ButtonState.Pressed;

                        // Check if the target's creator has HoldCycles or UnconsciousCycles
                        if (StoredAttack != null &&
                            ((Architect)(StoredAttack.Target.Creator)).HoldCycles > 0 || ((Architect)(StoredAttack.Target.Creator)).UnconsciousCycles > 0)
                        {
                            CalculateAttack(StoredAttack.Verb, StoredAttack.Attacker, StoredAttack.Target, "sustain", StoredAttack.Weapon);
                            StoredAttack = null;
                        }
                        else
                        {
                            string Action = "";

                            // Check key presses
                            Keys pressedKey = KeysNewlyPressed.FirstOrDefault();
                            if (pressedKey != Keys.None)
                            {
                                switch (pressedKey)
                                {
                                    case Keys.S:
                                        Action = "sustain";
                                        break;
                                    case Keys.D:
                                        Action = "duck";
                                        break;
                                    case Keys.J:
                                        Action = "jump";
                                        break;
                                    case Keys.R:
                                        Action = "roll";
                                        break;
                                    case Keys.N:
                                        Action = "disarm";
                                        break;
                                    case Keys.C:
                                        if (CanRedirect()) Action = "redirect";
                                        break;
                                    case Keys.P:
                                        if (CanParry()) Action = "parry";
                                        break;
                                    case Keys.B:
                                        if (CanBlock()) Action = "block";
                                        break;
                                    default:
                                        break;
                                }
                            }

                            


                            // Check mouse interactions
                            // Check mouse interactions
                            if (currentMouseState.LeftButton == ButtonState.Pressed && previousMouseState.LeftButton == ButtonState.Released)
                            {
                                if (SustainR.Contains(scaledMousePosition)) Action = "sustain";
                                else if (DuckR.Contains(scaledMousePosition)) Action = "duck";
                                else if (JumpR.Contains(scaledMousePosition)) Action = "jump";
                                else if (RollR.Contains(scaledMousePosition)) Action = "roll";
                                else if (DisarmR.Contains(scaledMousePosition)) Action = "disarm";
                                else if (RedirectR.Contains(scaledMousePosition) && CanRedirect()) Action = "redirect";
                                else if (ParryR.Contains(scaledMousePosition) && CanParry()) Action = "parry";
                                else if (BlockR.Contains(scaledMousePosition) && CanBlock()) Action = "block";

                                // Play sound if any action is set
                                if (!string.IsNullOrEmpty(Action))
                                {
                                    Game1.TurnPage.Play(volume: 0.2f * (SoundVolume / 100f), pitch: 0.0f, pan: 0.0f);
                                }
                            }


                            // Perform the action if valid
                            if (!string.IsNullOrEmpty(Action))
                            {
                                CalculateAttack(StoredAttack.Verb, StoredAttack.Attacker, StoredAttack.Target, Action, StoredAttack.Weapon);
                                StoredAttack = null;
                                ProgressTutorial(27);
                            }
                        }

                        // Check if the action has been resolved
                        if (StoredAttack == null)
                        {

                            if (MostRecentPartyTurnArchitect.CooldownCycles > 0)
                            {
                                IncrementAndCycleWorld();
                            }
                            GameState = "otherturn";
                        }

                        // Helper Methods for Conditions
                        bool CanRedirect()
                        {
                            return true;
                        }

                        bool CanParry()
                        {
                            return (MostRecentPartyTurnArchitect.OffHeldObject != null && MostRecentPartyTurnArchitect.OffHeldObject.IsWeapon) ||
                                   (MostRecentPartyTurnArchitect.MainHeldObject != null && MostRecentPartyTurnArchitect.MainHeldObject.IsWeapon);
                        }

                        bool CanBlock()
                        {
                            return (MostRecentPartyTurnArchitect.MainHeldObject != null && MostRecentPartyTurnArchitect.MainHeldObject.Type == "shield") ||
                                   (MostRecentPartyTurnArchitect.OffHeldObject != null && MostRecentPartyTurnArchitect.OffHeldObject.Type == "shield");
                        }
                    }

                    else if (GameState == "messagereply")
                    {
                        bool mouseClicked = currentMouseState.LeftButton == ButtonState.Pressed && previousMouseState.LeftButton == ButtonState.Released;
                        string Reply = null;

                        if (MostRecentPartyTurnArchitect.MessagesNotRespondedTo.Count() == 0)
                        {
                            GameState = "partyturn";
                            return;
                        }

                        if (MostRecentPartyTurnArchitect.HoldCycles > 0 || MostRecentPartyTurnArchitect.UnconsciousCycles > 0)
                        {
                            // Automatically respond with "does not reply" if the person is unconscious or held
                            MakeObservation($"{MostRecentPartyTurnArchitect.ReferredToNames[0]} does not reply.", Color.Yellow, new EntityList<Entity>() { MostRecentPartyTurnArchitect });
                            MessageWorldEdit(
                                MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Sender,
                                MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Receiver,
                                MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].MessageID,
                                MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Subjects,
                                "",
                                new EntityList<Location>(), new EntityList<Architect>()
                            );
                            MostRecentPartyTurnArchitect.MessagesNotRespondedTo.RemoveAt(0);
                            GameState = "otherturn";
                            return;
                        }




                        // Initialize response options dictionary
                        var responseOptions = new Dictionary<string, (Rectangle, Keys)>();

                        // Helper function to add to the dictionary if the key doesn't already exist
                        void AddResponseOption(string key, Rectangle rectangle, Keys keyBinding)
                        {
                            if (!responseOptions.ContainsKey(key))
                            {
                                responseOptions[key] = (rectangle, keyBinding);
                            }
                        }

                        // Define responses and add them conditionally
                        AddResponseOption(MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].PositiveResponse, Truthful, Keys.T);
                        AddResponseOption(MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].DirectRefusalResponse, DirectRefusal, Keys.M);
                        AddResponseOption(MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].IgnorantResponse, Ignorant, Keys.I);
                        AddResponseOption(MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].DerailingResponse, Derailing, Keys.D);
                        AddResponseOption(MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].FlatteringResponse, Flattering, Keys.F);
                        AddResponseOption("", None, Keys.X); // No reply action


                        // Check for mouse click or key press
                        foreach (var option in responseOptions)
                        {
                            var (rectangle, key) = option.Value;

                            // rectangle is already in virtual resolution space
                            if ((rectangle.Contains(scaledMousePosition) && mouseClicked) ||
                                KeysNewlyPressed.Contains(key))
                            {
                                Reply = option.Key;
                                break;
                            }
                        }



                        // Handle response if chosen
                        if (Reply != null)
                        {
                            if (Reply == "") // Handle "no reply" explicitly
                            {
                                MakeObservation($"{MostRecentPartyTurnArchitect.ReferredToNames[0]} does not reply.", Color.Yellow, new EntityList<Entity>() { MostRecentPartyTurnArchitect });
                                MessageWorldEdit(
                                    MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Sender,
                                    MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Receiver,
                                    MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].MessageID,
                                    MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Subjects,
                                    "",
                                    new EntityList<Location>(), new EntityList<Architect>()
                                );
                            }
                            else
                            {
                                MakeObservation(
                                    $"{MostRecentPartyTurnArchitect.ReferredToNames[0]}: {Reply}",
                                    new Color(0, 255, 0),
                                    new EntityList<Entity>().Union(new[] { MostRecentPartyTurnArchitect }).Union(MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Subjects)
                                );
                                MessageWorldEdit(
                                    MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Sender,
                                    MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Receiver,
                                    MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].MessageID,
                                    MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].Subjects,
                                    Reply,
                                    new EntityList<Location>(), MostRecentPartyTurnArchitect.MessagesNotRespondedTo[0].StoredKnownArchs
                                );
                                MostRecentPartyTurnArchitect.CooldownCycles += (int)Math.Round(30 / MostRecentPartyTurnArchitect.Speed);

                                Game1.SFX.Add(Game1.TalkSounds[MostRecentPartyTurnArchitect.VoiceType]);
                            }

                            MostRecentPartyTurnArchitect.MessagesNotRespondedTo.RemoveAt(0);
                            GameState = "otherturn";
                        }
                    }


                    else if (GameState == "trypickup")
                    {



                        int GetHalfCount(string itemType, EntityList<Material> itemMaterials)
                        {
                            var container = (MostRecentPartyTurnArchitect.Room != null
                                ? MostRecentPartyTurnArchitect.Room.Objects
                                : MostRecentPartyTurnArchitect.Block.Objects);

                            int totalCount = container.Count(
                                item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials));
                            return (int)Math.Ceiling(totalCount / 2.0);
                        }

                        int GetFullCount(string itemType, EntityList<Material> itemMaterials)
                        {
                            var container = (MostRecentPartyTurnArchitect.Room != null
                                ? MostRecentPartyTurnArchitect.Room.Objects
                                : MostRecentPartyTurnArchitect.Block.Objects);

                            return container.Count(
                                item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials));
                        }

                        bool mousePressed = currentMouseState.LeftButton == ButtonState.Pressed;
                        bool previousMousePressed = previousMouseState.LeftButton == ButtonState.Pressed;

                        // Handle the 1 / half / all picks
                        if (KeysNewlyPressed.Contains(Keys.D1) ||
                            (PickUpOneR.Contains(scaledMousePosition) && mousePressed && !previousMousePressed))
                        {
                            PickUpItems(1);
                            MostRecentPartyTurnArchitect.TryPickUpItemType = "";
                            MostRecentPartyTurnArchitect.TryPickUpMaterials = new EntityList<Material>();

                            if (MostRecentPartyTurnArchitect.CooldownCycles > 0)
                            {
                                IncrementAndCycleWorld();
                            }
                            SFX.Add(Leather);
                            GameState = "otherturn";
                        }
                        else if (KeysNewlyPressed.Contains(Keys.D2) ||
                            (PickUpHalfR.Contains(scaledMousePosition) && mousePressed && !previousMousePressed))
                        {
                            int half = GetHalfCount(
                                MostRecentPartyTurnArchitect.TryPickUpItemType,
                                MostRecentPartyTurnArchitect.TryPickUpMaterials);
                            PickUpItems(half);
                            MostRecentPartyTurnArchitect.TryPickUpItemType = "";
                            MostRecentPartyTurnArchitect.TryPickUpMaterials = new EntityList<Material>();

                            if (MostRecentPartyTurnArchitect.CooldownCycles > 0)
