                                IncrementAndCycleWorld();
                            }
                            SFX.Add(Leather);
                            GameState = "otherturn";
                        }
                        else if (KeysNewlyPressed.Contains(Keys.D3) ||
                            (PickUpAllR.Contains(scaledMousePosition) && mousePressed && !previousMousePressed))
                        {
                            int full = GetFullCount(
                                MostRecentPartyTurnArchitect.TryPickUpItemType,
                                MostRecentPartyTurnArchitect.TryPickUpMaterials);
                            PickUpItems(full);
                            MostRecentPartyTurnArchitect.TryPickUpItemType = "";
                            MostRecentPartyTurnArchitect.TryPickUpMaterials = new EntityList<Material>();

                            if (MostRecentPartyTurnArchitect.CooldownCycles > 0)
                            {
                                IncrementAndCycleWorld();
                            }
                            SFX.Add(Leather);
                            GameState = "otherturn";
                        }
                    }

                    else if (GameState == "trydrop")
                    {


                        int GetHalfCount(string itemType, EntityList<Material> itemMaterials)
                        {
                            int totalCount = MostRecentPartyTurnArchitect.Inventory.Count(
                                item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials));
                            return (int)Math.Ceiling(totalCount / 2.0);
                        }

                        int GetFullCount(string itemType, EntityList<Material> itemMaterials)
                        {
                            return MostRecentPartyTurnArchitect.Inventory.Count(
                                item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials));
                        }

                        bool mousePressed = currentMouseState.LeftButton == ButtonState.Pressed;
                        bool previousMousePressed = previousMouseState.LeftButton == ButtonState.Pressed;

                        // Handle 1 / half / all drops
                        if (KeysNewlyPressed.Contains(Keys.D1) ||
                            (DropOneR.Contains(scaledMousePosition) && mousePressed && !previousMousePressed))
                        {
                            DropItems(1);
                            MostRecentPartyTurnArchitect.TryDropItemType = "";
                            MostRecentPartyTurnArchitect.TryDropMaterials = new EntityList<Material>();
                            GameState = "otherturn";
                        }
                        else if (KeysNewlyPressed.Contains(Keys.D2) ||
                            (DropHalfR.Contains(scaledMousePosition) && mousePressed && !previousMousePressed))
                        {
                            int half = GetHalfCount(
                                MostRecentPartyTurnArchitect.TryDropItemType,
                                MostRecentPartyTurnArchitect.TryDropMaterials);
