                            int totalCount = (container.Type == "shadow fountain")
                                ? architect.ShadowStorage.Count(item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials))
                                : container.ContainedObjects.Count(item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials));

                            return (int)Math.Ceiling(totalCount / 2.0);
                        }

                        int GetFullCount(string itemType, EntityList<Material> itemMaterials)
                        {
                            var architect = MostRecentPartyTurnArchitect;
                            var container = architect.SelectedContainer;

                            return (container.Type == "shadow fountain")
                                ? architect.ShadowStorage.Count(item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials))
                                : container.ContainedObjects.Count(item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials));
