                    else if (GameState == "tryplace")
                    {
                        void PlaceItems(int count)
                        {
                            var architect = MostRecentPartyTurnArchitect;
                            var container = architect.SelectedContainerForPlacing;

                            List<Object> itemsToPlace = architect.Inventory
                                .Where(item =>
                                    item.Type == architect.TryPlaceItemType &&
                                    item.Materials.SequenceEqual(architect.TryPlaceMaterials))
                                .Take(count)
                                .ToList();

                            int countActuallyPlaced = itemsToPlace.Count;
                            if (countActuallyPlaced == 0)
                            {
                                MakeObservation("You have no matching items to place.", Color.Yellow, new EntityList<Entity>());
                                return;
                            }

                            bool PlayedSound = false;

                            foreach (var item in itemsToPlace)
                            {
                                architect.Inventory.Remove(item);

                                if (container.Type == "shadow fountain")
                                    architect.ShadowStorage.Add(item);
                                else
                                    container.ContainedObjects.Add(item);

                                if (!PlayedSound)
                                {
                                    item.PlaySound();
                                    PlayedSound = true;
                                }

                                if (architect.Structure != null && architect.Structure.Type == "market")
                                    architect.Structure.MarketDebtToUs += item.Value();
                            }

                            string itemType = Game1.Capitalize(architect.TryPlaceItemType);
                            bool isPlural = countActuallyPlaced != 1;
                            string displayName = isPlural ? itemType.ToLowerInvariant().Pluralize(true) : itemType.ToLowerInvariant();

                            MakeObservation($"You place {countActuallyPlaced} {displayName} into the {container.ReferredToNames[0]}.", Color.Green, new EntityList<Entity>());

                            architect.TryPlaceItemType = "";
                            architect.TryPlaceMaterials = new EntityList<Material>();
                            GameState = "otherturn";
                        }

                        int GetHalfCount(string itemType, EntityList<Material> itemMaterials)
                        {
                            return (int)Math.Ceiling(
                                MostRecentPartyTurnArchitect.Inventory.Count(item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials)) / 2.0
                            );
                        }

                        int GetFullCount(string itemType, EntityList<Material> itemMaterials)
                        {
                            return MostRecentPartyTurnArchitect.Inventory.Count(item => item.Type == itemType && item.Materials.SequenceEqual(itemMaterials));
                        }

                        bool mousePressed = currentMouseState.LeftButton == ButtonState.Pressed;
                        bool previousMousePressed = previousMouseState.LeftButton == ButtonState.Pressed;

                        if (KeysNewlyPressed.Contains(Keys.D1) || (PlaceOneR.Contains(scaledMousePosition) && mousePressed && !previousMousePressed))
                        {
                            PlaceItems(1);
                        }
                        else if (KeysNewlyPressed.Contains(Keys.D2) || (PlaceHalfR.Contains(scaledMousePosition) && mousePressed && !previousMousePressed))
                        {
                            int half = GetHalfCount(MostRecentPartyTurnArchitect.TryPlaceItemType, MostRecentPartyTurnArchitect.TryPlaceMaterials);
                            PlaceItems(half);
                        }
                        else if (KeysNewlyPressed.Contains(Keys.D3) || (PlaceAllR.Contains(scaledMousePosition) && mousePressed && !previousMousePressed))
                        {
                            int full = GetFullCount(MostRecentPartyTurnArchitect.TryPlaceItemType, MostRecentPartyTurnArchitect.TryPlaceMaterials);
                            PlaceItems(full);
                        }
                    }



                    else if (GameState == "travelmenu")
                    {
                        if (StateToSwitchTo == "")
                            Exposition = new List<TextStorage>();

                        if (KeysNewlyPressed.Contains(Keys.A) || HuntUnknownLocations.Clicked())
                        {
                            GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width].DeepExplored = true;

                            if (GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width].Location != null)
                            {
                                GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width].Location.Explored = true;
                            }
                        }


                        if (WaitForPlanActive.Clicked())
                        {
                            int DaysWaited = 0;

                            // Get the region again
                            Region r = GameWorld.WorldMap[
                                GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX +
                                GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width
                            ];

                            while (DaysWaited < 28)
                            {
                                // Before progressing, check if any plan is now active
                                bool anyPlanNowActive = Game1.GameWorld.AllFactions.Any(f =>
                                    f.CurrentPlan != null &&
                                    f.CurrentPlan.PlanLocation == r.Location &&
                                    (r.Location.Explored || (GameState != "travelmenu" && GameState != "ascendant")) &&
                                    r.Location.Districts.Any(d => d.DistrictArchitects.Any(a => f.CurrentPlan.PlanInitiators.Contains(a)))
                                );

                                if (anyPlanNowActive)
                                {
                                    LastTravelActMsg = "Someone suspicious has arrived.";
                                    break; // Stop early if someone shows up
                                }

                                // Otherwise wait one day
                                GameWorld.ProgressDays(1, true);
                                DaysWaited++;

                                if (DaysWaited == 28)
                                {
                                    LastTravelActMsg = "No one suspicious arrived... yet.";
                                }
                            }

                            bool WasVisBefore = WaitForPlanActive.InvisibleLock == false;

                            UpdateTravelButtons();

                            if (WaitForPlanActive.InvisibleLock == true && WasVisBefore && LastTravelActMsg != "Someone suspicious has arrived.")
                            {
                                LastTravelActMsg = "The scaffold has decayed. Perhaps this plan was abandoned.";
                            }
                        }


                        if (WaitOneMonth.Clicked())
                        {
                            for (int i = 0; i < 28; i++)
                            {
                                GameWorld.ProgressDays(1, true);
                            }
                        }

                        if (WaitOneWeek.Clicked())
                        {
                            for (int i = 0; i < 7; i++)
                            {
                                GameWorld.ProgressDays(1, true);
                            }
                        }



                        if (KeysNewlyPressed.Contains(Keys.Tab) || ZoomOut.Clicked())
                        {
                            ZoomOnMap = !ZoomOnMap;
                        }


                        if (AssembleRaft.Clicked())
                        {
                            Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects[0].Inventory.Add(new Object(null, "raft", new EntityList<Material>() { GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width].HarvestableWood }, Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects[0]));
                        }


                        if (SaveAndExitTravel.Clicked())
                        {
                            if (!DontSaveGameBecauseWeJustDid)
                            {
                                GameState = "savinggame";
                                StateToSwitchToAfterSave = "mainscreen";

                            }
                            else
                            {

                                GameWorld.EntityLedger.Remove(GameWorld.ID);
                                Announcements.Clear();

                                Inventory.Text = "Open Menu";
                                Inventory.Hitbox.X = 400;
                                Inventory.Hitbox.Y = 212;

                                SwitchState("mainscreen", true);
                            }
                        }

                        if (MoveTicks == 0)
                        {
                            int DeltaX = 0;
                            int DeltaZ = 0;
                            bool inputDetected = false;

                            if (currentMouseState.LeftButton == ButtonState.Pressed)
                            {
                                // Scale the movement points to match the viewport
                                Point[] MovePoints = new Point[] {
    GoNW, GoNE, GoE, GoW, GoSW, GoSE
};


                                // Find the closest point to the mouse position
                                Point ClosestPoint = MovePoints[0];
                                float MinDistance = Vector2.Distance(
                                    new Vector2(scaledMousePosition.X, scaledMousePosition.Y),
                                    new Vector2(MovePoints[0].X, MovePoints[0].Y)
                                );

                                foreach (Point Point in MovePoints)
                                {
                                    float Distance = Vector2.Distance(
                                        new Vector2(scaledMousePosition.X, scaledMousePosition.Y),
                                        new Vector2(Point.X, Point.Y)
                                    );
                                    if (Distance < MinDistance && Distance <= 60) // Ensure it's within 60-pixel range
                                    {
                                        ClosestPoint = Point;
                                        MinDistance = Distance;
                                    }
                                }

                                // Process the closest movement point
                                if (MinDistance <= 60)
                                {
                                    inputDetected = true;

                                    // Determine direction based on the closest point
                                    if (ClosestPoint == MovePoints[0]) // GoNW
                                    {
                                        DeltaX = (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ % 2 == 0) ? -1 : 0;
                                        DeltaZ = -1;
                                    }
                                    else if (ClosestPoint == MovePoints[1]) // GoNE
                                    {
                                        DeltaX = (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ % 2 == 1) ? 1 : 0;
                                        DeltaZ = -1;
                                    }
                                    else if (ClosestPoint == MovePoints[2]) // GoE
                                    {
                                        DeltaX = 1;
                                    }
                                    else if (ClosestPoint == MovePoints[3]) // GoW
                                    {
                                        DeltaX = -1;
                                    }
                                    else if (ClosestPoint == MovePoints[4]) // GoSW
                                    {
                                        DeltaX = (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ % 2 == 0) ? -1 : 0;
                                        DeltaZ = 1;
                                    }
                                    else if (ClosestPoint == MovePoints[5]) // GoSE
                                    {
                                        DeltaX = (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ % 2 == 1) ? 1 : 0;
                                        DeltaZ = 1;
                                    }
                                }
                            }


                            // --- Keyboard-based movement (RTDGCV or Numpad) ---
                            if (Keyboard.GetState().IsKeyDown(Keys.R) || Keyboard.GetState().IsKeyDown(Keys.T) || Keyboard.GetState().IsKeyDown(Keys.D) ||
                                 Keyboard.GetState().IsKeyDown(Keys.G) || Keyboard.GetState().IsKeyDown(Keys.C) || Keyboard.GetState().IsKeyDown(Keys.V) ||
                                Keyboard.GetState().IsKeyDown(Keys.NumPad7) || Keyboard.GetState().IsKeyDown(Keys.NumPad9) || Keyboard.GetState().IsKeyDown(Keys.NumPad4) ||
                                Keyboard.GetState().IsKeyDown(Keys.NumPad6) || Keyboard.GetState().IsKeyDown(Keys.NumPad1) || Keyboard.GetState().IsKeyDown(Keys.NumPad3))
                            {
                                inputDetected = true;

                                if (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ % 2 == 0)
                                {
                                    // Even row logic
                                    if (Keyboard.GetState().IsKeyDown(Keys.R) || Keyboard.GetState().IsKeyDown(Keys.NumPad7))
                                    {
                                        DeltaX = -1;
                                        DeltaZ = -1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.T) || Keyboard.GetState().IsKeyDown(Keys.NumPad9))
                                    {
                                        DeltaZ = -1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.D) || Keyboard.GetState().IsKeyDown(Keys.NumPad4))
                                    {
                                        DeltaX = -1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.G) || Keyboard.GetState().IsKeyDown(Keys.NumPad6))
                                    {
                                        DeltaX = 1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.C) || Keyboard.GetState().IsKeyDown(Keys.NumPad1))
                                    {
                                        DeltaX = -1;
                                        DeltaZ = 1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.V) || Keyboard.GetState().IsKeyDown(Keys.NumPad3))
                                    {
                                        DeltaZ = 1;
                                    }
                                }
                                else
                                {
                                    // Odd row logic
                                    if (Keyboard.GetState().IsKeyDown(Keys.R) || Keyboard.GetState().IsKeyDown(Keys.NumPad7))
                                    {
                                        DeltaZ = -1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.T) || Keyboard.GetState().IsKeyDown(Keys.NumPad9))
                                    {
                                        DeltaX = 1;
                                        DeltaZ = -1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.D) || Keyboard.GetState().IsKeyDown(Keys.NumPad4))
                                    {
                                        DeltaX = -1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.G) || Keyboard.GetState().IsKeyDown(Keys.NumPad6))
                                    {
                                        DeltaX = 1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.C) || Keyboard.GetState().IsKeyDown(Keys.NumPad1))
                                    {
                                        DeltaZ = 1;
                                    }
                                    else if (Keyboard.GetState().IsKeyDown(Keys.V) || Keyboard.GetState().IsKeyDown(Keys.NumPad3))
                                    {
                                        DeltaX = 1;
                                        DeltaZ = 1;
                                    }
                                }
                            }

                            bool CarriesRaft = Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects.Any(a => a.Inventory.Any(o => o.Type == "raft"));


                            // --- Execute movement if input is detected ---
                            if (inputDetected && GameStateSwitchTicks == 250)
                            {
                                if (!(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX >= GameWorld.Width ||
                                      GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX < 0 ||
                                      GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ >= GameWorld.Length ||
                                      GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ < 0))
                                {
                                    bool isDestinationOcean = GameWorld.WorldMap[(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX) + ((GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ) * GameWorld.Width)].Biome == "ocean";
                                    bool isDestinationVoid = GameWorld.WorldMap[(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX) + ((GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ) * GameWorld.Width)].Biome == "void";
                                    bool isDestinationEthereal = GameWorld.WorldMap[(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX) + ((GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ) * GameWorld.Width)].Biome == "ethereal";
                                    bool isDestinationPort = (!string.IsNullOrEmpty(GameWorld.WorldMap[(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX) + ((GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ) * GameWorld.Width)].PortName)) ||
                                                             (GameWorld.WorldMap[(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX) + ((GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ) * GameWorld.Width)].Location != null &&
                                                             GameWorld.WorldMap[(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + DeltaX) + ((GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ + DeltaZ) * GameWorld.Width)].Location.Type == "cove");
                                    bool isCurrentLocationWater = GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width)].Biome == "ocean";

                                    if (!isDestinationVoid && !isDestinationEthereal &&      
                                        !isCurrentLocationWater &&                         
                                        (!isDestinationOcean || isDestinationPort || CarriesRaft))
                                    {
                                       
                                    }

                                    if(isDestinationOcean && !isDestinationPort && !CarriesRaft && !isCurrentLocationWater)
                                    {
                                        GameWorld.GamePlayerAssociation.ActiveParty.Architects[0].CompanionMessage("rafttravel", "");
                                    }


                                    // Allow movement based on biome and port access logic
                                    if (!isDestinationVoid && !isDestinationEthereal &&
                                        (isCurrentLocationWater || (!isDestinationOcean || isDestinationPort || CarriesRaft)))
                                    {
                                        GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX += DeltaX;
                                        GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ += DeltaZ;

                                        Game1.GameWorld.RevealNearbyTiles(GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX, GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ, RevealAndUnitRad, true);

                                        // Calculate the minimum speed of architects in the party
                                        decimal minArchitectSpeed = (decimal)GameWorld.GamePlayerAssociation.ActiveParty.Architects.Min(architect => architect.Speed);

                                        // Each step is 18000 cycles, and a full day is 864000 cycles, so calculate the fraction of a day this represents
                                        decimal fractionOfDay = (18000 / minArchitectSpeed) / 864000;


                                        //ok but if its a raft thing, we gon explode watch

                                        if (CarriesRaft && isCurrentLocationWater)
                                            fractionOfDay *= 6;


                                        // Progress the game by that small fraction of a day
                                        GameWorld.ProgressDays(fractionOfDay, true);

                                        GameWorld.GamePlayerAssociation.ActiveParty.MapCursorDistrict = 0;

                                        // Handle events in the new tile
                                        if (StoredEvent != null)
                                        {
                                            if (StoredEvent.Region.X != GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX || StoredEvent.Region.Z != GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ)
                                            {
                                                StoredEvent = null;
                                            }
                                        }

                                        var events = GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width].Units;

                                        if (events.Count > 0)
                                        {
                                            StoredEvent = events[Game1.r.Next(events.Count)];
                                        }

                                        LastTravelActMsg = "";

                                        StepSound(1);

                                        // Set MoveTicks to 30 for cooldown
                                        MoveTicks = 15;
                                        UpdateTravelButtons();
                                        DontSaveGameBecauseWeJustDid = false;
                                    }
                                }
                            }
                        }

                        Region currentRegion = GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width];

                        if (currentRegion.Location == null)
                        {
                            Dictionary<string, List<string>> biomeDictionary = new Dictionary<string, List<string>>();

                            biomeDictionary["forest"] = new List<string> { "wood" };
                            biomeDictionary["lightforest"] = new List<string> { "wood" };
                            biomeDictionary["mountain"] = new List<string> { "stone", "ice" };
                            biomeDictionary["snowpeak"] = new List<string> { "stone", "metal", "ice" };
                            biomeDictionary["desert"] = new List<string> { "sand" };
                            biomeDictionary["plains"] = new List<string> { "fiber" };
                            biomeDictionary["tundra"] = new List<string> { "ice" };
                            biomeDictionary["taiga"] = new List<string> { "ice", "wood" };
                            biomeDictionary["void"] = new List<string> { "nothing" };

                            if (currentRegion.Biome == "ocean")
                            {
                                if (currentRegion.PortName != "")
                                {
                                    Exposition.Add(new TextStorage("You can leave this port to start sailing.", Color.LightBlue, new EntityList<Entity>() { }));
                                }
                                else
                                {
                                    Exposition.Add(new TextStorage("You are currently sailing.", Color.LightBlue, new EntityList<Entity>() { }));
                                }
                            }
                            else
                            {
                            }
                        }
                        else
                        {
                            // <<<<< NEW CODE >>>>>

                            // If there *is* a location, check for INACTIVE plans
                            bool foundInactivePlan = Game1.GameWorld.AllFactions.Any(f =>
                                f.CurrentPlan != null &&
                                f.CurrentPlan.PlanLocation == currentRegion.Location &&
                                (currentRegion.Location.Explored || (GameState != "travelmenu" && GameState != "ascendant")) &&
                                !currentRegion.Location.Districts.Any(d => d.DistrictArchitects.Any(a => f.CurrentPlan.PlanInitiators.Contains(a)))
                            );

                            if (foundInactivePlan && StateToSwitchTo == "")
                            {
                                Exposition.Add(new TextStorage(
                                    "There is evidence of tomfoolery at this location. ",
                                    Color.Goldenrod,
                                    new EntityList<Entity>()
                                ));


                                Exposition.Add(new TextStorage(
                                    "You might be able to wait out the perpetrators.",
                                    Color.Goldenrod,
                                    new EntityList<Entity>()
                                ));
                            }
                        }

                        if (StoredEvent != null && StateToSwitchTo == "")
                        {
                            Exposition.Clear();
                            Exposition.Add(new TextStorage(StoredEvent.Intrigue, Color.LimeGreen, new EntityList<Entity>() { }));
                            Exposition.Add(new TextStorage("Approach the Disturbance to explore further.", Color.Red, new EntityList<Entity>() { }));
                        }

                        if (LastTravelActMsg != "")
                        {
                            Exposition.Add(new TextStorage(LastTravelActMsg, Color.Yellow, new EntityList<Entity>() { }));
                        }


                        if ((StopAndGather.Clicked() || (KeysNewlyPressed.Contains(Keys.S) && !Keyboard.GetState().IsKeyDown(Keys.LeftControl))) && GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Width].Location == null)
