                        // Adjust mouse coordinates based on the scale matrix

                        float scaleX = (float)_graphics.PreferredBackBufferWidth / 2560f;
                        float scaleY = (float)_graphics.PreferredBackBufferHeight / 1440f;




                        void SendItem(Object obj, EntityList<Object> sourceList, EntityList<Object> destinationList, int amount)
                        {
                            if (amount <= 0) return;

                            // Identify and remove the exact number of objects from the source list
                            var matchingObjects = sourceList.Where(o => GenerateUniqueKeyForObject(o) == GenerateUniqueKeyForObject(obj)).Take(amount).ToList();

                            foreach (var item in matchingObjects)
                            {
                                sourceList.Remove(item);
                            }

                            // Check if the architect is inside a market
                            bool isMarket = MostRecentPartyTurnArchitect.Structure != null && MostRecentPartyTurnArchitect.Structure.Type == "market";

                            // Move the objects physically to the destination list
                            foreach (var item in matchingObjects)
                            {
                                destinationList.Add(item);

                                // Adjust market debt accordingly
                                if (isMarket)
                                {
                                    if (sourceList == MostRecentPartyTurnArchitect.Room.Objects)
                                    {
                                        // Buying from the market -> Decrease market's debt to player
                                        MostRecentPartyTurnArchitect.Structure.MarketDebtToUs -= item.Value();
                                    }
                                    else
                                    {
                                        // Selling to the market -> Increase market's debt to player
                                        MostRecentPartyTurnArchitect.Structure.MarketDebtToUs += item.Value();
                                    }
                                }
                            }

                            MostRecentPartyTurnArchitect.RunFragmentCheck();
                        }


                        bool leftClick = currentMouseState.LeftButton == ButtonState.Pressed && previousMouseState.LeftButton == ButtonState.Released;
                        bool shiftHeld = Keyboard.GetState().IsKeyDown(Keys.LeftShift) || Keyboard.GetState().IsKeyDown(Keys.RightShift);
                        bool ctrlHeld = Keyboard.GetState().IsKeyDown(Keys.LeftControl) || Keyboard.GetState().IsKeyDown(Keys.RightControl);
                        bool altHeld = Keyboard.GetState().IsKeyDown(Keys.LeftAlt) || Keyboard.GetState().IsKeyDown(Keys.RightAlt);

                        // Shift + '-' = previous ROOM page
                        if ((shiftHeld && KeysNewlyPressed.Contains(Keys.OemMinus)) || TradeLeft.Clicked())
                        {
                            RoomPage = Math.Max(0, RoomPage - 1);
                        }
                        else if ((shiftHeld && (KeysNewlyPressed.Contains(Keys.OemPlus) || KeysNewlyPressed.Contains(Keys.Add))) || TradeRight.Clicked())
                        {
                            RoomPage = Math.Min(RoomPage + 1, RoomMaxPage);
                        }


                        else if ((ctrlHeld && (KeysNewlyPressed.Contains(Keys.OemPlus) || KeysNewlyPressed.Contains(Keys.Add))) || InvRight.Clicked())
                        {
                            InventoryPage = Math.Min(InventoryPage + 1, InventoryMaxPage);
                        }

                        // Ctrl + '-' = previous INVENTORY page
                        else if ((ctrlHeld && (KeysNewlyPressed.Contains(Keys.OemMinus) || KeysNewlyPressed.Contains(Keys.Subtract))) || InvLeft.Clicked())
                        {
                            InventoryPage = Math.Max(0, InventoryPage - 1);
                        }


                        // Process item transfer when clicking on a hitbox
                        if (leftClick)
                        {
                            foreach (var (hitbox, obj, container) in TradeHitboxes)
                            {
                                if (hitbox.Contains(scaledMousePosition))
                                {
                                    bool fromInventory = hitbox.X < 1280; // If X position is before the room column, it's from inventory
                                    EntityList<Object> sourceList = fromInventory ? MostRecentPartyTurnArchitect.Inventory : MostRecentPartyTurnArchitect.Room.Objects;
                                    EntityList<Object> destinationList = fromInventory ? MostRecentPartyTurnArchitect.Room.Objects : MostRecentPartyTurnArchitect.Inventory;

                                    // Count how many identical objects exist in the source list
                                    int totalStackCount = sourceList.Count(o => GenerateUniqueKeyForObject(o) == GenerateUniqueKeyForObject(obj));

                                    int amountToMove = 1; // Default to 1 item
                                    if (ctrlHeld)
                                        amountToMove = totalStackCount; // Move entire stack
                                    else if (altHeld)
                                        amountToMove = 5; // Alt + click: Buy or sell 5 items
                                    else if (shiftHeld)
                                        amountToMove = Math.Max(1, totalStackCount / 2); // Move half the stack (rounded down)

                                    // Call SendItem function
                                    SendItem(obj, sourceList, destinationList, amountToMove);

                                    break; // Stop checking further hitboxes after finding a match
                                }
                            }
                        }


                        if (ReturnTradeButton.Clicked())
                        {
                            SwitchState("partyturn", false);
                        }

                    }

                    else if (GameState == "gathering")
                    {
                        if (KeysNewlyPressed.Contains(Keys.X))
                        {
                            // Transition to the travel menu
                            UpdateTravelButtons();
                            SwitchState("travelmenu", false);
                            GameWorld.GamePlayerAssociation.ActiveParty.ClearSkillData();
                        }

                        // Mapping of biomes to the tools required for gathering
                        var gatheringActions = new Dictionary<string, string> {
        {"forest", "axe"}, {"lightforest", "axe"}, {"taiga", "axe"},
        {"mountain", "pickaxe"}, {"snowpeak", "pickaxe"},
        {"desert", "shovel"},
        {"plains", "scythe or sword"},
        {"tundra", "pickaxe"}, {"ice", "pickaxe"}
    };

                        // Mapping of biomes ttable materials
                        var harvestableMaterials = new Dictionary<string, Material> {
        {"forest", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableWood},
        {"lightforest", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableWood},
        {"taiga", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableWood},
        {"mountain", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableStone},
        {"snowpeak", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableMetal},
        {"desert", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableSand},
        {"plains", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableFiber},
        {"tundra", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableIce},
        {"ice", GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableIce}
    };

                        // Mapping materials to the type of resource they represent
                        Dictionary<Material, string> ResourcetoType = new Dictionary<Material, string>()
    {
        {GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableWood, "log"},
        {GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableStone, "stone"},
        {GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableMetal, "ore"},
        {GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableSand, "pile"},
        {GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableFiber, "bunch"},
        {GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].HarvestableIce, "block"}
    };

                        // Mapping of numeric keys to resource types
                        var resourceKeyMap = new Dictionary<int, string> {
        {1, "wood"},
        {2, "stone"},
        {3, "metal"},
        {4, "sand"},
        {5, "fiber"},
        {6, "ice"}
    };

                        bool HasRequiredTool(Architect architect, string toolRequirements)
                        {
                            if (string.IsNullOrEmpty(toolRequirements))
                            {
                                // If no tool is required, return true
                                return true;
                            }

                            // Define tool aliases for partial matches
                            var toolAliases = new Dictionary<string, string[]>
    {
        { "sword", new[] { "longsword", "shortsword" } },
                                {"axe", new[] { "greataxe", "battle axe", "work axe" } }
    };

                            // Split the tool requirements into an array, as some biomes might allow multiple tools
                            string[] requiredTools = toolRequirements.Split(new[] { ", ", " or " }, StringSplitOptions.RemoveEmptyEntries);

                            // Check each tool in the required tools list to see if the architect has it
                            foreach (string requiredTool in requiredTools)
                            {
                                bool Matches(string itemType)
                                {
                                    return itemType.Equals(requiredTool, StringComparison.OrdinalIgnoreCase) ||
                                           (toolAliases.ContainsKey(requiredTool) &&
                                            toolAliases[requiredTool].Any(alias => itemType.Equals(alias, StringComparison.OrdinalIgnoreCase)));
                                }

                                // Check inventory, MainHeldObject, and OffHeldObject
                                if (architect.Inventory.Any(item => Matches(item.Type)) ||
                                    (architect.MainHeldObject != null && Matches(architect.MainHeldObject.Type)) ||
                                    (architect.OffHeldObject != null && Matches(architect.OffHeldObject.Type)))
                                {
                                    // Return true as soon as one required tool is found
                                    return true;
                                }
                            }

                            // Return false if none of the required tools are found in the architect's inventory
                            return false;
                        }


                        // Get the current biome
                        string currentBiome = GameWorld.WorldMap[GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX + GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ * GameWorld.Length].Biome;

                        // Iterate through each mapped key to resource type
                        foreach (var resourceKey in resourceKeyMap)
                        {
                            if (KeysNewlyPressed.Contains((Keys)Enum.Parse(typeof(Keys), $"D{resourceKey.Key}")))
                            {
                                // Check if the biome has the corresponding resource
                                if (harvestableMaterials.ContainsKey(currentBiome) && harvestableMaterials[currentBiome].Type.Contains(resourceKey.Value))
                                {
                                    Material resourceMaterial = harvestableMaterials[currentBiome];
                                    string resourceType = ResourcetoType[resourceMaterial];
                                    string toolRequired = gatheringActions.ContainsKey(currentBiome) ? gatheringActions[currentBiome] : null;
                                    bool toolNeeded = true;

                                    foreach (var architect in GameWorld.GamePlayerAssociation.ActiveParty.Architects)
                                    {
                                        if (HasRequiredTool(architect, toolRequired))
                                        {
                                            toolNeeded = false;
                                            int count = Game1.r.Next(0, architect.Strength + 1);

                                            // List of break activities for architects when they don't gather resources
                                            List<string> breakActivities = new List<string>()
                                            {
                                                "sleeps for a bit",
                                                "gossips",
                                                "provides emotional support",
                                                "stands by and supervises",
                                                "ponders the meaning of life",
                                                "whistles a cheerful tune",
                                                "checks their equipment",
                                                "looks around cautiously",
                                                "starts a small chat",
                                                "takes a deep breath"
                                            };

                                            // List of break activities for a single architect in the party
                                            List<string> soloBreakActivities = new List<string>()
                                            {
                                                "sleeps for a bit",
                                                "takes a moment to meditate on the current state that is",
                                                "enjoys the solitude",
                                                "practices some skills",
                                                "sketches the surroundings",
                                                "sings quietly to themselves",
                                                "examines the environment",
                                                "reflects on the past",
                                                "stretches and relaxes"
                                            };

                                            // Code inside the harvesting loop
                                            if (count > 0)
                                            {
                                                Exposition.Add(new TextStorage($"{architect.Name} harvested {count} {resourceType}.", Color.LightBlue, new EntityList<Entity>() { }));
                                                for (int i = 0; i < count; i++)
                                                {
                                                    architect.Inventory.Add(new Object(null, resourceType, new EntityList<Material>() { resourceMaterial }, null));
                                                }
                                            }
                                            else
                                            {
                                                // Select a random break activity based on the number of architects in the party
                                                string breakActivity;
                                                if (GameWorld.GamePlayerAssociation.ActiveParty.Architects.Count() == 1)
                                                {
                                                    breakActivity = soloBreakActivities[Game1.r.Next(soloBreakActivities.Count())];
                                                }
                                                else
                                                {
                                                    breakActivity = breakActivities[Game1.r.Next(breakActivities.Count())];
                                                }
                                                Exposition.Add(new TextStorage($"{architect.Name} {breakActivity}.", Color.LightBlue, new EntityList<Entity>() { }));
                                            }
                                        }
                                    }


                                    if (toolNeeded)
                                    {
                                        Exposition.Add(new TextStorage($"You need a {toolRequired} to harvest {resourceMaterial.Type} here.", Color.Yellow, new EntityList<Entity>() { }));
                                    }
                                }
                                else
                                {
                                    Exposition.Add(new TextStorage($"There is no {resourceKey.Value.ToLower().Replace("harvestable", "")} to harvest in this biome.", Color.Red, new EntityList<Entity>() { }));
                                }
                            }
                        }
                    }
                    else if (GameState == "crafting")
                    {
                        if (CraftingPhase == "selectrecipe")
                        {
                            if (KeysNewlyPressed.Contains(Keys.Escape))
                            {
                                SwitchState("partyturn", false);
                                MostRecentPartyTurnArchitect.Crafting = false;
                            }

                            if (KeysNewlyPressed.Contains(Keys.Up) || KeysNewlyPressed.Contains(Keys.NumPad8))
                            {
                                RecipeIndex--;

                                if (RecipeIndex < 0)
                                {
                                    RecipeIndex = Recipes.Count() - 1;
                                }
                            }
                            else if (KeysNewlyPressed.Contains(Keys.Down) || KeysNewlyPressed.Contains(Keys.NumPad2))
                            {
                                RecipeIndex++;

                                if (RecipeIndex > Recipes.Count() - 1)
                                {
                                    RecipeIndex = 0;
                                }
                            }
                            if (KeysNewlyPressed.Contains(Keys.Enter))
                            {
                                CraftingPhase = "selectingredients";
                                InventoryCraftingIndex = 0;
                                IndexesForResources = new List<int>();  // Clear the previous selection
                            }
                        }
                        else if (CraftingPhase == "selectingredients")
                        {
                            if (KeysNewlyPressed.Contains(Keys.Escape))
                            {
                                CraftingPhase = "selectrecipe";
                                IndexesForResources = new List<int>();
                            }

                            Dictionary<string, string> materialToObjectMap = new Dictionary<string, string>
        {
            {"cloth", "roll"},
            {"wood", "log"},
            {"stone", "stone"},
            {"metal", "bar"},
            {"ore", "ore"},
            {"gemstone", "cut gem"},
            {"sand", "pile"},
            {"fiber", "bunch"},
            {"ice", "block"},
            {"glass", "sheet"}
        };

                            var currentRecipe = Recipes[RecipeIndex];
                            var currentRecipeMaterials = currentRecipe.Item2
                                .Distinct()
                                .Select(mat => materialToObjectMap[mat])
                                ;

                            EntityList<Object> relevantItems = MostRecentPartyTurnArchitect.Inventory
                                .Where(obj => currentRecipeMaterials.Contains(obj.Type));

                            if (KeysNewlyPressed.Contains(Keys.Up) || KeysNewlyPressed.Contains(Keys.NumPad8))
                            {
                                InventoryCraftingIndex--;

                                if (InventoryCraftingIndex < 0)
                                {
                                    InventoryCraftingIndex = relevantItems.Count() - 1;
                                }
                            }
                            else if (KeysNewlyPressed.Contains(Keys.Down) || KeysNewlyPressed.Contains(Keys.NumPad2))
                            {
                                InventoryCraftingIndex++;

                                if (InventoryCraftingIndex > relevantItems.Count() - 1)
                                {
                                    InventoryCraftingIndex = 0;
                                }
                            }
                            else if (KeysNewlyPressed.Contains(Keys.Right) || KeysNewlyPressed.Contains(Keys.NumPad6))
                            {
                                if (!IndexesForResources.Contains(InventoryCraftingIndex))
                                {
                                    IndexesForResources.Add(InventoryCraftingIndex);
                                }
                            }

                            if (KeysNewlyPressed.Contains(Keys.Enter))
                            {
                                EntityList<Material> allUsedMaterials = new EntityList<Material>();  // List to store all used materials
                                var requiredItems = currentRecipe.Item2
                                    .GroupBy(x => x)
                                    .ToDictionary(g => g.Key, g => g.Count());

                                bool hasAllIngredients = true;
                                foreach (var requiredItem in requiredItems)
                                {
                                    string requiredType = requiredItem.Key;
                                    int requiredCount = requiredItem.Value;

                                    // Count the selected items of the required type
                                    int selectedCount = IndexesForResources
                                        .Select(index => relevantItems[index])
                                        .Count(obj => obj.Type == materialToObjectMap[requiredType]);

                                    if (selectedCount < requiredCount)
                                    {
                                        hasAllIngredients = false;
                                    }
                                }

                                if (hasAllIngredients)
                                {
                                    // Consume the required items
                                    foreach (var requiredItem in requiredItems)
                                    {
                                        string requiredType = requiredItem.Key;
                                        int requiredCount = requiredItem.Value;
                                        string requiredObject = materialToObjectMap[requiredType];

                                        // Initialize a counter for how many materials have been added
                                        int materialsAdded = 0;

                                        // Collect indices to be removed after the iteration
                                        var indicesToRemove = new List<int>();

                                        // Find and remove the required number of items from selected indexes in inventory
                                        foreach (var index in IndexesForResources.ToList())
                                        {
                                            var item = relevantItems[index];
                                            if (item.Type == requiredObject)
                                            {
                                                foreach (var material in item.Materials)
                                                {
                                                    // Check if a material with the same name already exists in allUsedMaterials
                                                    if (!allUsedMaterials.Any(m => m.Name == material.Name))
                                                    {
                                                        allUsedMaterials.Add(material); // Add the material of the consumed item if it's not already added
                                                    }
                                                    materialsAdded++; // Increment materialsAdded in either case
                                                }

                                                MostRecentPartyTurnArchitect.Inventory.Remove(item);
                                                indicesToRemove.Add(index); // Add the index to the removal list

                                                // Break out of the loop if the required amount of materials has been added
                                                if (materialsAdded >= requiredCount)
                                                    break;
                                            }
                                        }

                                        // Remove the indices from selected resources
                                        foreach (var index in indicesToRemove)
                                        {
                                            IndexesForResources.Remove(index);
                                        }
                                    }

                                    ItemPickupGuiLines.Clear();

                                    // Add the crafted item to the inventory


                                    if (currentRecipe.Item1 == "sheet")
                                    {
                                        allUsedMaterials.Clear();
                                        allUsedMaterials.Add(GameWorld.Glass);
                                    }


                                    Object o = new Object("", currentRecipe.Item1, allUsedMaterials, MostRecentPartyTurnArchitect);
                                    o.Name = GameWorld.GenerateUniqueName("1S" + GameWorld.rnd.Next(2, 5) + "sw", o, Game1.GameWorld.rnd);

                                    if (o.Weight > 6000)
                                    {
                                        (MostRecentPartyTurnArchitect.Room != null ? MostRecentPartyTurnArchitect.Room.Objects : MostRecentPartyTurnArchitect.Block.Objects).Add(o);
                                    }
                                    else
                                    {
                                        MostRecentPartyTurnArchitect.Inventory.Add(o);
                                    }

                                    int CraftRank = ((int)Math.Round((double)((MostRecentPartyTurnArchitect.Level + MostRecentPartyTurnArchitect.Creativity) / 2)));

                                    o.Rarity = GameWorld.GenerateItemRarity(CraftRank);
                                    o.ApplyImbuements(0);

                                    MakeObservation(MostRecentPartyTurnArchitect.Name + " has created " + o.Name + " with a quality rank of " + CraftRank + ".", Color.Coral, new EntityList<Entity>() { MostRecentPartyTurnArchitect, o });


                                    if (o.Imbuements.Count > 0 || o.IsWeapon || o.Name != null)
                                    {
                                        IsInGui = true;

                                        if (o.Name != null)
                                        {
                                            ItemPickupGuiLines.Add(Capitalize(o.Name) + ", " + Capitalize(o.Materials[0].Name) + " " + Capitalize(o.Type));
                                        }
                                        else
                                        {
                                            ItemPickupGuiLines.Add(Capitalize(o.Materials[0].Name) + " " + Capitalize(o.Type));
                                        }

                                        if (o.Imbuements.Count() == 0)
                                        {
                                            ItemPickupGuiLines.Add("This object has no imbuements.");
                                        }
                                        else
                                        {
                                            ItemPickupGuiLines.Add("This object has some intriguing properties:");
                                            foreach (Imbuement i in o.Imbuements)
                                            {
                                                ItemPickupGuiLines.Add(i.GetDescription());
                                            }
                                        }
                                        PickupConfirm.InvisibleLock = false;
                                    }

                                    GameState = "otherturn";


                                    MostRecentPartyTurnArchitect.CooldownCycles += 600;

                                    if (MostRecentPartyTurnArchitect.CooldownCycles > 0)
                                    {
                                        IncrementAndCycleWorld();
                                    }
                                }
                                else
                                {
                                    Exposition.Add(new TextStorage("Not enough materials to craft.", Color.Red, new EntityList<Entity>() { }));
                                    CraftingPhase = "selectrecipe";
                                }
                            }
                        }
                    }

                }
            }


            previousState = Keyboard.GetState();

            previousMouseState = currentMouseState;

            base.Update(gameTime);
        }




        protected override void Draw(GameTime gameTime)
        {
            GraphicsDevice.Clear(Color.Black);



            // Fake Replacement for Resolution Things

            SaveAndExitTravel.Text = DontSaveGameBecauseWeJustDid ? "Return to Title (Game Saved)" : "Save Game And Exit";
            SaveAndExitInMenu.Text = DontSaveGameBecauseWeJustDid ? "Return to Title (Game World Saved)" : "Save Game World and Return to Title";

            EntityHitboxes.Clear();

            float scaleX = (float)_graphics.PreferredBackBufferWidth / 2560f;
            float scaleY = (float)_graphics.PreferredBackBufferHeight / 1440f;

            Matrix scaleMatrix = Matrix.CreateScale(scaleX, scaleY, 1);

            // Calculate offsets for letterboxing/pillarboxing (if any)
            int OffsetX = (Game1.PreferredBackBufferWidth - (int)(2560f * scaleX)) / 2;
            int OffsetY = (Game1.PreferredBackBufferHeight - (int)(1440f * scaleY)) / 2;


            int DrawX = 1400;
            int DrawY = 1100;


            _spriteBatch.Begin(SpriteSortMode.Deferred, BlendState.AlphaBlend, _graphics.PreferredBackBufferHeight >= 1440 ? SamplerState.LinearClamp : SamplerState.PointClamp, null, null, null, scaleMatrix);


            void DrawLine(SpriteBatch spriteBatch, Vector2 start, Vector2 end, Color color)
            {
                Vector2 direction = end - start;
                float rotation = (float)Math.Atan2(direction.Y, direction.X);
                float length = direction.Length();

                spriteBatch.Draw(
                    whiteRect,
                    position: start,
                    sourceRectangle: null,
                    color: color,
                    rotation: rotation,
                    origin: new Vector2(0, 0.5f),
                    scale: new Vector2(length, 1.5f), // Thicker line for clarity
                    effects: SpriteEffects.None,
                    layerDepth: 0
                );
            }



            const int VIRTUAL_WIDTH = 2560;
            const int VIRTUAL_HEIGHT = 1440;

            // Actual window size
            int windowWidth = Window.ClientBounds.Width;
            int windowHeight = Window.ClientBounds.Height;

            // Non-uniform scale
            float ScaleX = (float)windowWidth / VIRTUAL_WIDTH;
            float ScaleY = (float)windowHeight / VIRTUAL_HEIGHT;

            // Black bars (pillarbox or letterbox)
            int offsetX = (int)((windowWidth - VIRTUAL_WIDTH * ScaleX) / 2f);
            int offsetY = (int)((windowHeight - VIRTUAL_HEIGHT * ScaleY) / 2f);

            // Get mouse position relative to *window client area*
            MouseState mouseState = Mouse.GetState();
            int msX = mouseState.X;
            int msY = mouseState.Y;

            // Convert to virtual coordinates using independent scales
            int virtualX = (int)((msX - offsetX) / ScaleX);
            int virtualY = (int)((msY - offsetY) / ScaleY);

            // Optional clamping to virtual bounds
            virtualX = Math.Clamp(virtualX, 0, VIRTUAL_WIDTH);
            virtualY = Math.Clamp(virtualY, 0, VIRTUAL_HEIGHT);

            Point scaledMousePosition = new Point(virtualX, virtualY);







            void DrawWorld(
    int? centerX = null,
    int? centerZ = null,
    int? segmentWidth = null,
    int? segmentHeight = null,
    float tileScale = 1.0f,
    int? tileRadius = null,
    bool isSegment = false
)
            {

                if (GameWorld == null)
                    return;

                // Determine rendering bounds
                int startX, startZ, endX, endZ;
                int cursorX = 0, cursorY = 0, additionalOffset = 0;

                if (isSegment && centerX.HasValue && centerZ.HasValue && segmentWidth.HasValue && segmentHeight.HasValue)
                {
                    // Segment mode: calculate bounds around the center
                    int halfSegmentWidth = segmentWidth.Value / 2;
                    int halfSegmentHeight = segmentHeight.Value / 2;

                    startX = Math.Max(0, centerX.Value - halfSegmentWidth);
                    endX = Math.Min(GameWorld.Width, centerX.Value + halfSegmentWidth);

                    startZ = Math.Max(0, centerZ.Value - halfSegmentHeight);
                    endZ = Math.Min(GameWorld.Length, centerZ.Value + halfSegmentHeight);

                    // Adjust the cursor position to fix the centering
                    cursorX = RegionXMod + (halfSegmentWidth - 2) * (int)(Game1.TileXDistance * tileScale); // Corrected for +2x
                    cursorY = RegionYMod + (halfSegmentHeight - 2) * (int)(Game1.TileZDistance * tileScale); // Corrected for +2z
                    additionalOffset = (centerZ.Value % 2 == 1) ? -(int)(Game1.TileXDistance * tileScale) / 2 : 0;
                }
                else
                {
                    // Global mode: full map
                    startX = 0;
                    endX = GameWorld.Width;
                    startZ = 0;
                    endZ = GameWorld.Length;

                    if (GameState == "travelmenu")
                    {
                        // Get actual cursor tile position
                        int cursorTileX = Game1.GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX;
                        int cursorTileZ = Game1.GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ;

                        // Apply the correct hexagonal staggering
                        cursorX = RegionXMod + (cursorTileX * (int)(Game1.TileXDistance * tileScale));
                        cursorY = RegionYMod + (cursorTileZ * (int)(Game1.TileZDistance * tileScale));

                        // Correct staggered hex offset
                        if (cursorTileZ % 2 == 1)
                        {
                            cursorX += (int)(Game1.TileXDistance * tileScale) / 2; // Shift right instead of left
                        }
                    }

                }

                // Draw the cursor tile in either mode when in travelmenu
                if (GameState == "travelmenu")
                {
                    var cursorRect = new Rectangle(
                        cursorX,
                        cursorY,
                        (int)(Game1.TileSize * tileScale),
                        (int)(Game1.TileSize * tileScale)
                    );

                    _spriteBatch.End();
                    _spriteBatch.Begin(SpriteSortMode.Deferred, BlendState.Additive, !isSegment ? SamplerState.LinearClamp : SamplerState.PointClamp, null, null, null, scaleMatrix);
                    _spriteBatch.Draw(Tiles96, cursorRect, TileRects96["cursor"], Color.White);
                }

                // Phase 1: Render tiles with elevation, time of day, and blight adjustments
                _spriteBatch.End();
                _spriteBatch.Begin(SpriteSortMode.Deferred, BlendState.Additive, !isSegment ? SamplerState.LinearClamp : SamplerState.PointClamp, null, null, null, scaleMatrix);

                for (int x = startX; x < endX; x++)
                {
                    for (int z = startZ; z < endZ; z++)
                    {
                        int index = x + z * GameWorld.Width;

                        // Skip tiles outside radius in segment mode
                        if (isSegment && tileRadius.HasValue && centerX.HasValue && centerZ.HasValue)
                        {
                            int dx = x - centerX.Value;
                            int dz = z - centerZ.Value;
                            if (Math.Sqrt(dx * dx + dz * dz) > tileRadius.Value)
                                continue;
                        }

                        bool isCursorHere =
    (GameState == "travelmenu" || GameState == "triggerrupture") &&
    (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX == x && GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ == z) ||

    (GameState == "ascendant" &&
        ((GameWorld.GamePlayerAssociation.AscendantX == x && GameWorld.GamePlayerAssociation.AscendantZ == z) ||
        (GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location != null &&
         GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location.Region.X == x &&
         GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location.Region.Z == z) ||
        GameWorld.GamePlayerAssociation.Parties
            .Where(p => p != GameWorld.GamePlayerAssociation.ActiveParty && p.Leader.Location != null)
            .Any(p => p.Leader.Location.Region.X == x && p.Leader.Location.Region.Z == z)));


                        // Tile position calculation
                        int tileX, tileY;

                        if (isSegment)
                        {
                            // Calculate relative positions
                            int relativeX = x - centerX.Value;
                            int relativeZ = z - centerZ.Value;

                            tileX = cursorX + relativeX * (int)(Game1.TileXDistance * tileScale)
                                    + ((z % 2 == 1) ? (int)(Game1.TileXDistance * tileScale) / 2 : 0)
                                    + additionalOffset;
                            tileY = cursorY + relativeZ * (int)(Game1.TileZDistance * tileScale);
                        }
                        else
                        {
                            // In full world mode, calculate tile positions normally
                            tileX = RegionXMod + x * (int)(Game1.TileXDistance * tileScale)
                                    + ((z % 2 == 1) ? (int)(Game1.TileXDistance * tileScale) / 2 : 0);
                            tileY = RegionYMod + z * (int)(Game1.TileZDistance * tileScale);
                        }

                        Rectangle tileRect = new Rectangle(tileX, tileY, (int)(Game1.TileSize * tileScale), (int)(Game1.TileSize * tileScale));

                        if (FlashTick > 50)
                        {
                            if (GameWorld.GamePlayerAssociation != null && GameWorld.GamePlayerAssociation.ActiveParty != null && GameWorld.GamePlayerAssociation.ActiveParty.CurrentlyMarkedRegions.Contains(GameWorld.WorldMap[index]))
                            {
                                // Highlight the region if it's currently marked
                                _spriteBatch.Draw(Tiles96, tileRect, TileRects96["cursor"], Color.LimeGreen);
                                continue;
                            }
                        }


                        /*
                        if (Keyboard.GetState().IsKeyDown(Keys.R))
                        {
                            Color c = new Color(
    (int)Math.Round(GameWorld.ElevationNoiseValues[index]),
    (int)Math.Round(GameWorld.ElevationNoiseValues[index]),
    (int)Math.Round(GameWorld.ElevationNoiseValues[index])
);

                            _spriteBatch.Draw(EmptyTileT, tileRect, c);
                            continue;
                        }
                        */

                        // First Phase: Handle Cursors and Flash Logic for Parties
                        if (!isSegment)
                        {
                            int CX = -1, CZ = -1;

                            // Travelmenu logic: Handle cursor drawing directly
                            if (GameState == "travelmenu" || GameState == "triggerrupture")
                            {
                                CX = GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX;
                                CZ = GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ;

                                // Draw the cursor and skip the tile
                                if (CX == x && CZ == z)
                                {
                                    _spriteBatch.Draw(Tiles96, tileRect, TileRects96["cursor"], Color.White);
                                    continue;
                                }
                            }
                        }

                        // Skip tiles where the cursor is drawn
                        if (isSegment && x == centerX.Value && z == centerZ.Value)
                        {
                            if (GameState == "travelmenu" || (GameState == "ascendant" && FlashTick >= 50))
                                continue;
                        }


                        // Skip unexplored tiles if in certain game states
                        if ((GameState == "travelmenu" || GameState == "ascendant" || GameState == "triggerrupture") && !GameWorld.WorldMap[index].Explored)
                            continue;

                        // Elevation adjustment
                        float elevation = GameWorld.ElevationNoiseValues[index];
                        float normalizedElevation = elevation / 256f;
                        float brightness = MathHelper.Lerp(0.0f, 1.55f, normalizedElevation);

                        // Time of day adjustment (only in "travelmenu")
                        if (GameState == "travelmenu")
                        {
                            double totalSeconds = GameWorld.Cycle * 0.1;
                            double hours = (totalSeconds / 3600.0) % 24;

                            float minBrightness = 0.4f; // Brightness at night
                            float maxBrightness = 1.55f; // Brightness during the day

                            if (hours >= 5 && hours < 7)
                            {
                                // Sunrise: scale from min to max brightness
                                float transitionProgress = (float)((hours - 5) / 2.0);
                                brightness = MathHelper.Lerp(minBrightness, maxBrightness, transitionProgress);
                            }
                            else if (hours >= 7 && hours < 17)
                            {
                                // Daytime: maintain max brightness
                                brightness = maxBrightness;
                            }
                            else if (hours >= 17 && hours < 19)
                            {
                                // Sunset: scale from max to min brightness
                                float transitionProgress = (float)((hours - 17) / 2.0);
                                brightness = MathHelper.Lerp(maxBrightness, minBrightness, transitionProgress);
                            }
                            else
                            {
                                // Nighttime: maintain min brightness
                                brightness = minBrightness;
                            }
                        }

                        Color baseColor = new Color(brightness, brightness, brightness);

                        // Blight adjustment
                        if (GameWorld.WorldMap[index].Blight != GameWorld.Purity)
                        {
                            baseColor = Color.Lerp(baseColor, new Color(100, 100, 100), 1.0f);
                        }

                        if(!isCursorHere || !(FlashTick > 50))
                        {
                            if (Keyboard.GetState().IsKeyDown(Keys.LeftControl) && Keyboard.GetState().IsKeyDown(Keys.R))
                                _spriteBatch.Draw(Tiles96, tileRect, TileRects96["cursor"], ColorConverter[GameWorld.WorldMap[index].Hyperregion.Color]);
                            else if (GameWorld.WorldMap[index].Biome != "void")
                                _spriteBatch.Draw(Tiles96, tileRect, TileRects96[GameWorld.WorldMap[index].Biome], baseColor);
                        }

                    }


                }

                _spriteBatch.End();

                // Phase 2: Render overlays, structures, and events
                _spriteBatch.Begin(SpriteSortMode.Deferred, BlendState.AlphaBlend, !isSegment ? SamplerState.LinearClamp : SamplerState.PointClamp, null, null, null, scaleMatrix);

                for (int x = startX; x < endX; x++)
                {
                    for (int z = startZ; z < endZ; z++)
                    {
                        // Tile position calculation (reuse the same logic)
                        int tileX, tileY;

                        if (isSegment)
                        {
                            int relativeX = x - centerX.Value;
                            int relativeZ = z - centerZ.Value;

                            tileX = cursorX + relativeX * (int)(Game1.TileXDistance * tileScale)
                                    + ((z % 2 == 1) ? (int)(Game1.TileXDistance * tileScale) / 2 : 0)
                                    + additionalOffset;
                            tileY = cursorY + relativeZ * (int)(Game1.TileZDistance * tileScale);
                        }
                        else
                        {
                            tileX = RegionXMod + x * (int)(Game1.TileXDistance * tileScale)
                                    + ((z % 2 == 1) ? (int)(Game1.TileXDistance * tileScale) / 2 : 0);
                            tileY = RegionYMod + z * (int)(Game1.TileZDistance * tileScale);
                        }

                        Rectangle tileRect = new Rectangle(tileX, tileY, (int)(Game1.TileSize * tileScale), (int)(Game1.TileSize * tileScale));

                        int index = x + z * GameWorld.Width;

                        if (FlashTick > 50)
                        {
                            if (GameWorld.GamePlayerAssociation != null &&
                                GameWorld.GamePlayerAssociation.ActiveParty != null &&
                                GameWorld.GamePlayerAssociation.ActiveParty.CurrentlyMarkedRegions.Contains(GameWorld.WorldMap[index]))
                            {
                                // Highlight the region if it's currently marked
                                _spriteBatch.Draw(Tiles96, tileRect, TileRects96["cursor"], Color.LimeGreen);
                                continue;
                            }
                        }



                        bool isCursorHere =
    (GameState == "travelmenu" || GameState == "triggerrupture") &&
    (GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX == x && GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ == z) ||

    (GameState == "ascendant" &&
        ((GameWorld.GamePlayerAssociation.AscendantX == x && GameWorld.GamePlayerAssociation.AscendantZ == z) ||
        (GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location != null &&
         GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location.Region.X == x &&
         GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location.Region.Z == z) ||
        GameWorld.GamePlayerAssociation.Parties
            .Where(p => p != GameWorld.GamePlayerAssociation.ActiveParty && p.Leader.Location != null)
            .Any(p => p.Leader.Location.Region.X == x && p.Leader.Location.Region.Z == z)));

                        if (isCursorHere && (FlashTick >= 50 || GameState == "travelmenu"))
                        {
                            continue;
                        }


                        // Skip tiles outside radius in segment mode
                        if (isSegment && tileRadius.HasValue && centerX.HasValue && centerZ.HasValue)
                        {
                            int dx = x - centerX.Value;
                            int dz = z - centerZ.Value;
                            if (Math.Sqrt(dx * dx + dz * dz) > tileRadius.Value)
                                continue;
                        }




                        // Skip tiles where the cursor is drawn
                        // Determine cursor coordinates based on GameState
                        int CX = -1; // Default to an invalid value
                        int CZ = -1; // Default to an invalid value

                        // Set coordinates based on GameState
                        if (GameState == "ascendant")
                        {
                            CX = GameWorld.GamePlayerAssociation.AscendantX;
                            CZ = GameWorld.GamePlayerAssociation.AscendantZ;
                        }
                        else if (GameState == "travelmenu" || GameState == "triggerrupture")
                        {
                            CX = GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX;
                            CZ = GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ;
                        }


                        // Ports

                        if (!string.IsNullOrEmpty(GameWorld.WorldMap[index].PortName) &&
                        ((GameState != "travelmenu" && GameState != "ascendant" && GameState != "triggerrupture") || GameWorld.WorldMap[index].Explored))
                        {
                            _spriteBatch.Draw(Tiles96, tileRect, TileRects96["port"], Color.White);
                        }



                        if (GameWorld.WorldMap[index].Location != null)
                        {
                            var location = GameWorld.WorldMap[index].Location;
                            bool shouldDrawLocation = (GameState != "travelmenu" && GameState != "ascendant" && GameState != "triggerrupture") || location.Explored;

                            if (shouldDrawLocation)
                            {
                                if (GameWorld.ProcgenStructures.Contains(location.Type))
                                {
                                    _spriteBatch.Draw(
                                        Tiles64,
                                        tileRect,
                                        TileRects64[location.Layout],
                                        ColorConverter[location.Color]
                                    );
                                }
                                else
                                {
                                    _spriteBatch.Draw(
                                        Tiles64,
                                        tileRect,
                                        TileRects64[location.PrimaryRace.Name + location.Type],
                                        Color.White
                                    );
                                }
                            }


                            foreach (Faction f in Game1.GameWorld.AllFactions)
                            {
                                if (f.CurrentPlan != null)
                                {
                                    if (f.CurrentPlan.PlanLocation == location && (location.Explored || (GameState != "travelmenu" && GameState != "ascendant")))
                                    {
                                        foreach (District d in location.Districts)
                                        {
                                            if (d.DistrictArchitects.Any(a => f.CurrentPlan.PlanInitiators.Contains(a)))
                                            {
                                                _spriteBatch.Draw(
                                                    Tiles96,
                                                    tileRect,
                                                    TileRects96["outline"],
                                                    Color.Goldenrod
                                                );
                                                break;
                                            }
                                            else
                                            {
                                                _spriteBatch.Draw(
                                                    Tiles96,
                                                    tileRect,
                                                    TileRects96["outline"],
                                                    new Color(255, 100, 0)
                                                );
                                            }

                                        }
                                    }
                                }
                            }
                        }


                        // Ownership highlights
                        if (GameState == "generatehistory" && GameWorld.WorldMap[index].Owner != null)
                        {
                            _spriteBatch.Draw(
                                Tiles96,
                                tileRect,
                                TileRects96["outline"],
                                ColorConverter[GameWorld.WorldMap[index].Owner.EntityColor]
                            );
                        }


                        // Event highlights
                        // Define the IsWithinRadius function for hexagonal grid calculation
                        bool IsWithinRadius(int centerX, int centerZ, int checkX, int checkZ, int radius)
                        {
                            if (!isSegment) // Zoomed-out mode
                            {
                                // Calculate the hexagonal distance for the actual map cursor
                                int cursorX = GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX;
                                int cursorZ = GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ;

                                // Convert axial coordinates to cube coordinates
                                int x1 = cursorX - (cursorZ - (cursorZ & 1)) / 2;
                                int z1 = cursorZ;
                                int y1 = -x1 - z1;

                                int x2 = checkX - (checkZ - (checkZ & 1)) / 2;
                                int z2 = checkZ;
                                int y2 = -x2 - z2;

                                // Calculate the hexagonal distance
                                int distance = (Math.Abs(x1 - x2) + Math.Abs(y1 - y2) + Math.Abs(z1 - z2)) / 2;
                                return distance <= radius;
                            }
                            else
                            {
                                // Original zoomed-in logic (centered on given `centerX` and `centerZ`)
                                int x1 = centerX - (centerZ - (centerZ & 1)) / 2;
                                int z1 = centerZ;
                                int y1 = -x1 - z1;

                                int x2 = checkX - (checkZ - (checkZ & 1)) / 2;
                                int z2 = checkZ;
                                int y2 = -x2 - z2;

                                // Calculate the hexagonal distance
                                int distance = (Math.Abs(x1 - x2) + Math.Abs(y1 - y2) + Math.Abs(z1 - z2)) / 2;
                                return distance <= radius;
                            }
                        }

                        // Event highlights: Only in travelmenu and within the event radius
                        if (GameState == "travelmenu")
                        {
                            int radiusCenterX, radiusCenterZ;

                            if (isSegment)
                            {
                                // Use relative coordinates for segments
                                radiusCenterX = centerX.Value;
                                radiusCenterZ = centerZ.Value;
                            }
                            else
                            {
                                // Use local map cursor coordinates for global mode
                                radiusCenterX = GameWorld.GamePlayerAssociation.ActiveParty.MapCursorX;
                                radiusCenterZ = GameWorld.GamePlayerAssociation.ActiveParty.MapCursorZ;
                            }

                            // Always check within a radius of 3 hexagons
                            if (IsWithinRadius(radiusCenterX, radiusCenterZ, x, z, 2))
                            {
                                bool hasColossal = false, hasTraveler = false, hasAnyEvent = false;

                                foreach (var interactableEvent in GameWorld.WorldMap[index].Units)
                                {
                                    if (interactableEvent != null)
                                    {
                                        hasAnyEvent = true;
                                        if (interactableEvent.Type == "colossal") hasColossal = true;
                                        if (interactableEvent.Type == "traveler") hasTraveler = true;
                                    }
                                }

                                if (hasColossal)
                                {
                                    _spriteBatch.Draw(ExclamationT, tileRect, Color.Red);
                                }
                                else if (hasTraveler)
                                {
                                    _spriteBatch.Draw(ExclamationT, tileRect, Color.Cyan);
                                }
                                else if (hasAnyEvent)
                                {
                                    _spriteBatch.Draw(ExclamationT, tileRect, Color.White);
                                }
                            }
                        }
                        else if (GameState == "ascendant")
                        {
                            foreach (Unit u in GameWorld.WorldMap[index].Units)
                            {
                                if (Game1.GameWorld.GamePlayerAssociation.Associates.Any(a => u.UnitArchitects.Contains(a)))
                                {
                                    _spriteBatch.Draw(ExclamationT, tileRect, Color.Blue);
                                }
                            }
                        }

                    }
                }

                //tragedy points
                /*
                for (int x = startX; x < endX; x++)
                {
                    for (int z = startZ; z < endZ; z++)
                    {
                        int index = x + z * GameWorld.Width;
                        if (GameState == "generatehistory")
                        {
                            foreach ((int, int) TragedyPoint in GameWorld.WorldMap[index].TragedyPoints)
                            {
                                _spriteBatch.Draw(
                                    whiteRect,
                                    new Rectangle(
                                        GameWorld.WorldMap[index].BoundingBox().Center.X + TragedyPoint.Item1 - 1,
                                        GameWorld.WorldMap[index].BoundingBox().Center.Y + TragedyPoint.Item2 - 1,
                                        3, 3),
                                    Color.Red);
                            }
                        }
                    }
                }
                */

                // Second Phase: Handle Outlines for Controlled, Hostile, and Neutral regions
                if (GameState == "ascendant")
                {
                    for (int x = startX; x < endX; x++)
                    {
                        for (int z = startZ; z < endZ; z++)
                        {
                            int index = x + z * GameWorld.Width;


                            //skip outside tilse
                            if (isSegment && tileRadius.HasValue && centerX.HasValue && centerZ.HasValue)
                            {
                                // Convert to cube coords for hex distance
                                int x1 = centerX.Value - (centerZ.Value - (centerZ.Value & 1)) / 2;
                                int z1 = centerZ.Value;
                                int y1 = -x1 - z1;

                                int x2 = x - (z - (z & 1)) / 2;
                                int z2 = z;
                                int y2 = -x2 - z2;

                                int hexDistance = (Math.Abs(x1 - x2) + Math.Abs(y1 - y2) + Math.Abs(z1 - z2)) / 2;

                                if (hexDistance > tileRadius.Value)
                                    continue;
                            }







                            // Calculate the tile position
                            int tileX, tileY;

                            if (isSegment)
                            {
                                int relativeX = x - centerX.Value;
                                int relativeZ = z - centerZ.Value;

                                tileX = cursorX + relativeX * (int)(Game1.TileXDistance * tileScale)
                                        + ((z % 2 == 1) ? (int)(Game1.TileXDistance * tileScale) / 2 : 0)
                                        + additionalOffset;
                                tileY = cursorY + relativeZ * (int)(Game1.TileZDistance * tileScale);
                            }
                            else
                            {
                                tileX = RegionXMod + x * (int)(Game1.TileXDistance * tileScale)
                                        + ((z % 2 == 1) ? (int)(Game1.TileXDistance * tileScale) / 2 : 0);
                                tileY = RegionYMod + z * (int)(Game1.TileZDistance * tileScale);
                            }

                            Rectangle tileRect = new Rectangle(tileX, tileY, (int)(Game1.TileSize * tileScale), (int)(Game1.TileSize * tileScale));


                            // Skip tiles without a location or unexplored locations
                            var location = GameWorld.WorldMap[index].Location;
                            if (location == null || !location.Explored)
                            {

                            }
                            else
                            {

                                // Determine tile color based on location ownership and status
                                Color outlineColor = Color.Transparent;

                                // Controlled (Indigo)
                                if (location.Government != null &&
                                    (GameWorld.GamePlayerAssociation.Parties.Contains(location.Government) ||
                                     GameWorld.GamePlayerAssociation.Associates.Contains(location.Government) ||
                                     GameWorld.GamePlayerAssociation.Associates.Any(a => location.Government is Group g && g.Leader == a)))
                                {
                                    outlineColor = new Color(80, 0, 250);
                                }
                                // Hostile (Red)
                                else if (location.Government != null &&
                                         (GameWorld.GamePlayerAssociation.Associates.Any(a => location.Government.Enemies.Contains(a)) ||
                                          GameWorld.GamePlayerAssociation.Parties.Any(p => location.Government.Enemies.Contains(p))))
                                {
                                    outlineColor = Color.Red;
                                }
                                // Neutral (Yellow)
                                else
                                {
                                    outlineColor = Color.Yellow;
                                }

                                // Draw the outline if a color was assigned
                                if (outlineColor != Color.Transparent)
                                {
                                    _spriteBatch.Draw(
                                        Tiles96,
                                        tileRect,
                                        TileRects96["outline"],
                                        outlineColor
                                    );
                                }

                            }


                            int CX = GameWorld.GamePlayerAssociation.AscendantX;
                            int CZ = GameWorld.GamePlayerAssociation.AscendantZ;

                            if (FlashTick >= 50)
                            {
                                // Determine which elements are on this tile
                                bool isCursor = (CX == x && CZ == z);

                                bool isActiveParty = GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location != null &&
                                                     GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location.Region.X == x &&
                                                     GameWorld.GamePlayerAssociation.ActiveParty.Leader.Location.Region.Z == z;

                                bool isInactiveParty = GameWorld.GamePlayerAssociation.Parties
                                                           .Where(p => p != GameWorld.GamePlayerAssociation.ActiveParty && p.Leader.Location != null)
                                                           .Any(p => p.Leader.Location.Region.X == x &&
                                                                     p.Leader.Location.Region.Z == z);

                                // Total number of flash sources on this tile
                                int totalFlashing = (isCursor ? 1 : 0) +
                                                    (isActiveParty ? 1 : 0) +
                                                    (isInactiveParty ? 1 : 0);

                                if (totalFlashing > 0)
                                {
                                    int ticksPerElement = 50 / totalFlashing; // FlashTick ranges from 50-99
                                    int currentPhase = FlashTick - 50;

                                    // Assign each element a window in the flash cycle
                                    int indexi = 0;

                                    if (isCursor)
                                    {
                                        if (currentPhase >= indexi * ticksPerElement &&
                                            currentPhase < (indexi + 1) * ticksPerElement)
                                        {
                                            _spriteBatch.Draw(Tiles96, tileRect, TileRects96["cursor"], Color.White);
                                            continue;
                                        }
                                        indexi++;
                                    }

                                    if (isActiveParty)
                                    {
                                        if (currentPhase >= indexi * ticksPerElement &&
                                            currentPhase < (indexi + 1) * ticksPerElement)
                                        {
                                            _spriteBatch.Draw(Tiles96, tileRect, TileRects96["cursor"], Color.Magenta);
                                            continue;
                                        }
                                        indexi++;
                                    }

                                    if (isInactiveParty)
                                    {
                                        if (currentPhase >= indexi * ticksPerElement &&
                                            currentPhase < (indexi + 1) * ticksPerElement)
                                        {
                                            _spriteBatch.Draw(Tiles96, tileRect, TileRects96["cursor"], Color.Cyan);
                                            continue;
                                        }
                                        indexi++;
                                    }
                                }
                            }
                        }
                    }
                }

                if (GameState == "generatehistory")
                {
                    foreach (Group g in GameWorld.Groups)
                    {
                        if (g.TradeRoute.Count < 2)
                            continue;

                        List<Vector2> routeCenters = new();

                        foreach (var location in g.TradeRoute)
                        {
                            Rectangle bbox = location.Region.BoundingBox();
                            routeCenters.Add(bbox.Center.ToVector2());
                        }

                        for (int i = 0; i < routeCenters.Count; i++)
                        {
                            Vector2 start = routeCenters[i];
                            Vector2 end = routeCenters[(i + 1) % routeCenters.Count]; // Wrap to form a loop
                            DrawLine(_spriteBatch, start, end, Color.SaddleBrown);
                        }
                    }
                }


                //hehe lol also the cursor clicky thingies

                if (isSegment && centerX.HasValue && centerZ.HasValue && GameState != "ascendant")
                {
                    // Coordinates of the central tile
                    int cx = centerX.Value;
                    int cz = centerZ.Value;

                    // Define adjacent tile offsets based on hex grid
                    int[][] offsets;
                    if (cz % 2 == 0)
                    {
                        // Even row
                        offsets = new int[][]
                        {
            new int[] {-1, -1}, // Northwest
            new int[] {0, -1},  // Northeast
            new int[] {-1, 1},  // Southwest
            new int[] {0, 1},   // Southeast
            new int[] {-1, 0},  // West
            new int[] {1, 0}    // East
                        };
                    }
                    else
                    {
                        // Odd row
                        offsets = new int[][]
                        {
            new int[] {0, -1},  // Northwest
            new int[] {1, -1},  // Northeast
            new int[] {0, 1},   // Southwest
            new int[] {1, 1},   // Southeast
            new int[] {-1, 0},  // West
            new int[] {1, 0}    // East
                        };
                    }

                    // Render CursorT for adjacent tiles
                    foreach (var offset in offsets)
                    {
                        int adjacentX = cx + offset[0];
                        int adjacentZ = cz + offset[1];

                        // Ensure adjacent tile is within bounds
                        if (adjacentX >= 0 && adjacentX < GameWorld.Width && adjacentZ >= 0 && adjacentZ < GameWorld.Length)
                        {
                            // Calculate the screen position of the adjacent tile
                            int tileX = cursorX + (adjacentX - cx) * (int)(Game1.TileXDistance * tileScale)
                                        + ((adjacentZ % 2 == 1) ? (int)(Game1.TileXDistance * tileScale) / 2 : 0)
                                        + additionalOffset;
                            int tileY = cursorY + (adjacentZ - cz) * (int)(Game1.TileZDistance * tileScale);

                            Rectangle adjacentTileRect = new Rectangle(tileX, tileY, (int)(Game1.TileSize * tileScale), (int)(Game1.TileSize * tileScale));

                            // Draw CursorT
                            // Draw Cursor
                            _spriteBatch.Draw(Tiles96, adjacentTileRect, TileRects96["cursor"], Color.White);
                        }
                    }
                }
            }


            void DrawCharacter(Architect a, int x, int y, double Scale, bool Inverted, bool Mirror)
            {
                //decide animation frame

                Texture2D DecidedSheet = null;

                string rKey = a.Race.Name.ToLower();
                if (!CharacterSheetIdle.TryGetValue(rKey, out DecidedSheet))
                    DecidedSheet = CharacterSheetIdle["luminarch"]; // fallback

                _spriteBatch.Draw(whiteRect, new Rectangle(x - 2, y - 2, 5, 5), Color.Red);

                // Cache for transformed textures (raceName -> texture)
                Dictionary<string, Texture2D> AdjustedHairCache = new();


                // Shadow calculation (aligned with 1000x1000 sprite grid)
                if (a.YLevelInFeet > 0 && !Mirror)
                {
                    int shadowSize = (int)(1000 * Scale); // Match sprite cell size
                    int shadowX = x - shadowSize / 2;
                    int shadowY = y - shadowSize; // Draw from feet upward

                    Rectangle shadowRect = new Rectangle(shadowX, shadowY, shadowSize, shadowSize);

                    _spriteBatch.Draw(
                        DecidedSheet,
                        shadowRect,
                        CharacterRects["shadow"],
                        Color.White
                    );

                    // Move character upward based on vertical level
                    y -= (int)(30 * Scale * a.YLevelInFeet);
                }





                int scaledWidth = (int)(1000 * Scale);
                int scaledHeight = (int)(1000 * Scale);

                // Shift by same visual offset used before (18px inside 50px) → scaled
                int visualOffsetX = (int)(18 * Scale);



                // You said (x, y) = top-right of character + mirror

                int mirrorWidth = (int)(500 * Scale);
                int mirrorHeight = (int)(1150 * Scale);

                int characterWidth = (int)(1000 * Scale);
                int characterHeight = (int)(1000 * Scale);
                int visualOffset = (int)(260 * Scale); // The amount you want to shift left

                Rectangle ChosenRect = new Rectangle(
                    x - visualOffset,
                    y,
                    characterWidth,
                    characterHeight
                );


                // Top-right anchor
                int topRightX = x;
                int topRightY = y;

                // Mirror is drawn first — same top-right
                int mirrorLeft = x;
                int mirrorTop = y;
                Rectangle newRect = new Rectangle(mirrorLeft, mirrorTop, mirrorWidth, mirrorHeight);

                Rectangle mirrorRect = new Rectangle(mirrorLeft, mirrorTop, mirrorWidth, mirrorHeight);

                // Character starts at top-right and draws downward
                int characterLeft = topRightX - characterWidth;
                int characterTop = topRightY;
                Rectangle characterRect = new Rectangle(characterLeft, characterTop, characterWidth, characterHeight);

                // Center can be used for old logic if needed
                int centerX = characterLeft + characterWidth / 2;
                int centerY = characterTop + characterHeight; // feet
        
                SpriteEffects fx = Inverted
    ? SpriteEffects.FlipHorizontally
    : SpriteEffects.None;



                if (x == 0 && y == 0)
                    return;

                Architect OriginalArchitect = a;

                a = a.ArchitectILookLike;


                // Handedness
