                        );
                    }

                    // Setup sampler state for smooth scaling if using XNA/MonoGame
                    _spriteBatch.GraphicsDevice.SamplerStates[0] = _graphics.PreferredBackBufferHeight >= 1440 ? SamplerState.LinearClamp : SamplerState.PointClamp;




                    if (!OriginalArchitect.IsAlive)
                    {
