                        }
                    }
                    // Draw character based on their race and sex
                    if (!GameWorld.HumanoidRaces.Contains(a.Race))
                    {
                        if (!a.Invisible)
                        {
                            Texture2D decidedT = null;
                            Rectangle sourceRect;
                            bool Colorchange = false;

                            string UseColor = "white";

                            string raceKey = a.Race.Name.ToLower();
                            if (!Mirror && RacesWithFades.Contains(raceKey))
                                raceKey += "_faded";

                            bool UseYour = false;

                            // Step 1: Try CharacterRectsOther
                            if (CharacterRectsOther.TryGetValue(raceKey, out sourceRect))
                            {
                                decidedT = CharacterSheetOther;
                            }
                            // Step 2: Try CharacterRects (main base sheet)
                            else if (CharacterRects.TryGetValue(raceKey, out sourceRect))
