                            {
                                UseColor = a.ColossalColoring;
                            }
                            else
                            {
                                UseColor = a.Race.Color;
                            }

                            if (a.Race.Name is "isofractal" or "icosidodecahedron")
                            {
                                Colorchange = true;
                            }

                            int ticksPerPhase = 60;
                            int phase = (ColorTick / ticksPerPhase) % 6;
                            float progress = (ColorTick % ticksPerPhase) / (float)ticksPerPhase;

                            int red = 0, green = 0, blue = 0;

                            switch (phase)
                            {
                                case 0: red = 255; green = (int)(progress * 255); blue = 0; break;
                                case 1: red = 255 - (int)(progress * 255); green = 255; blue = 0; break;
                                case 2: red = 0; green = 255; blue = (int)(progress * 255); break;
                                case 3: red = 0; green = 255 - (int)(progress * 255); blue = 255; break;
                                case 4: red = (int)(progress * 255); green = 0; blue = 255; break;
                                case 5: red = 255; green = 0; blue = 255 - (int)(progress * 255); break;
                            }

                            Color drawColor = Colorchange ? new Color(red, green, blue) : Color.White;

                            if (UseColor != "" && !Colorchange)
                            {
