                            {
                                int width = (int)(25 * 16 * Scale);
                                int height = (int)(55 * 16 * Scale);

                                destRect = new Rectangle(
    centerX - width / 2,
    centerY - height / 2,
    width,
    height
);

                            }
                            else
                            {
                                // Standard 1000x1000 sprite, but shift to simulate 300px visible core (350px buffer each side)
                                int width = (int)(1000 * Scale);
                                int height = (int)(1000 * Scale);
                                int horizontalOffset = (int)(350 * Scale);

                                destRect = new Rectangle(
                                    x - horizontalOffset,
                                    y - height,
                                    width,
                                    height
                                );
                            }

                            _spriteBatch.Draw(
                                decidedT,
                                destRect,
                                sourceRect,
                                drawColor,
                                0f,
                                Vector2.Zero,
                                Inverted ? SpriteEffects.FlipHorizontally : SpriteEffects.None,
                                0f
                            );
                            return;
                        }
                        else
