                    string race = a.Race.Name.ToLower();



                    void DrawArchitect(Architect a, Rectangle ChosenRect, bool Inverted)
                    {
                        if (a.Invisible)
                            return;

                        string key = a.Sex == "female" ? "femalebase" : "malebase";
                        Rectangle sourceRect = CharacterRects[key];

                        // No need to tint — the texture is pre-shaded
                        _spriteBatch.Draw(
                            DecidedSheet,
                            ChosenRect,
                            sourceRect,
                            Color.White,
                            0f,
                            Vector2.Zero,
                            Inverted ? SpriteEffects.FlipHorizontally : SpriteEffects.None,
                            0f
                        );

                        DrawHairTexture(a, ChosenRect, Inverted, Color.White, DecidedSheet);

                        if (Game1.GameWorld.HumanoidRaces.Contains(a.Race) && a.Brand != "dormant")
                        {
                            Rectangle brandRect = CharacterRects[a.Brand];
                            Color brandColor = ColorConverter[a.BrandColor];

                            _spriteBatch.Draw(
                                DecidedSheet,
                                ChosenRect,
                                brandRect,
                                brandColor,
                                0f,
                                Vector2.Zero,
                                Inverted ? SpriteEffects.FlipHorizontally : SpriteEffects.None,
                                0f
                            );
                        }

                        string race = a.Race.Name.ToLower();
                        string eyeKey = race switch
                        {
                            "archaix" => "archaixeye",
                            "luminarch" => "luminarcheye",
                            "nightfell" => "nightfelleye",
                            _ => null
                        };

                        if (eyeKey != null && CharacterRects.TryGetValue(eyeKey, out Rectangle eyeRect))
                        {
                            _spriteBatch.Draw(
                                DecidedSheet,
                                ChosenRect,
                                eyeRect,
                                Color.White,
                                0f,
                                Vector2.Zero,
                                Inverted ? SpriteEffects.FlipHorizontally : SpriteEffects.None,
                                0f
                            );
                        }
                    }


                    void DrawHairTexture(Architect a, Rectangle rect, bool inverted, Color tint, Texture2D DecidedSheet)
                    {
                        string[] hairStyles = { "vibrant", "windswept", "diminished", "swirl" };
                        if (a.HairID < 0 || a.HairID >= hairStyles.Length)
                            return;

                        int phaseIndex = Math.Clamp(HairPhase / 15, 0, 3);
                        string key = $"{hairStyles[a.HairID]}{phaseIndex + 1}";

                        if (!CharacterRects.TryGetValue(key, out Rectangle sourceRect))
                            return;

                        _spriteBatch.Draw(
                            DecidedSheet,
                            rect,
                            sourceRect,
                            tint,
                            0f,
                            Vector2.Zero,
                            inverted ? SpriteEffects.FlipHorizontally : SpriteEffects.None,
                            0f
                        );
                    }




                    var drawOrder = new List<string[]>
{
    new string[] { "body" },
    new string[] { "undergarment", "brassiere" },
    new string[] { "flair" },
    new string[] { "pants", "shorts" },
    new string[] { "leggings" },
    new string[] { "otherClothing" },
    new string[] { "armor" },
    new string[] { "skirt", "kilt" },
    new string[] { "left boot", "right boot" },
    new string[] { "robe" },
    new string[] { "chestplate" }
};

                    // Define armor and clothing categories, separating chestplate
                    var armorItems = new HashSet<string> { "helmet", "left boot", "right boot", "left gauntlet", "right gauntlet", };
                    var clothingItems = new HashSet<string> { "undergarment", "brassiere", "robe", "shirt", "pants", "leggings", "skirt", "kilt", "hat", "flair" };

                    // Group items by their type, treating chestplate as a separate category
                    var groupedItems = new Dictionary<string, EntityList<Object>>();
                    foreach (var o in a.Clothing)
                    {
                        string category = "otherClothing";
                        if (o.Type == "chestplate") category = "chestplate";
                        else if (armorItems.Contains(o.Type)) category = "armor";
                        else if (clothingItems.Contains(o.Type)) category = o.Type;

                        if (!groupedItems.ContainsKey(category)) groupedItems[category] = new EntityList<Object>();
                        groupedItems[category].Add(o);
                    }

                    // Draw items in the specified order
                    foreach (var category in drawOrder)
                    {
                        foreach (var subCategory in category)
                        {
                            if (groupedItems.ContainsKey(subCategory))
                            {
                                foreach (var o in groupedItems[subCategory])
                                {
                                    // Invisibility logic: skip rendering based on type and shadow level
                                    if (a.Invisible)
                                    {
                                        if (o.Type == "undergarment" || o.Type == "brassiere")
                                            continue;

                                        if (a.PathOfShadowLevel >= 6)
                                            continue;
                                    }

                                    string s = o.Type;

                                    // Inversion logic for left/right items
                                    if (Inverted)
                                    {
                                        if (s.StartsWith("left"))
                                        {
                                            s = "right" + s.Substring(4); // remove "left" and prepend "right"
                                        }
                                        else if (s.StartsWith("right"))
                                        {
                                            s = "left" + s.Substring(5); // remove "right" and prepend "left"
                                        }
                                    }

                                    if (s.EndsWith("shirt") || s == "robe" || s == "chestplate")
                                    {
                                        s += " " + a.Sex;
                                    }


                                    Color drawColor = o.DyedColor != "none" ? ColorConverter[o.DyedColor] : ColorConverter[o.Materials[0].Color];

                                    if (CharacterRects.ContainsKey(s) && o.ClothingVisible)
                                    {
                                        Rectangle sourceRect = CharacterRects[s];

                                        if (Inverted)
                                        {
                                            _spriteBatch.Draw(DecidedSheet, ChosenRect, sourceRect, drawColor, 0f, Vector2.Zero, SpriteEffects.FlipHorizontally, 0f);
                                        }
                                        else
                                        {
                                            _spriteBatch.Draw(DecidedSheet, ChosenRect, sourceRect, drawColor);
                                        }
                                    }
                                }
                            }
                        }
                    }


                }

                if (!(a.Invisible && a.PathOfShadowLevel >= 6) && frontTex != null && frontSource.HasValue)
                {
                        _spriteBatch.Draw(
                        frontTex,
                        ChosenRect,
                        frontSource.Value, // ← use the rectangle from CharacterRectsWeapons
                        frontColor,
                        0f,
                        Vector2.Zero,
                        fx,
                        0f
                    );
                }




                if (a.CompanionColor != "nocomp" && !a.Invisible)
                {
                    int xOffset = Inverted ? ChosenRect.Width : -ChosenRect.Width;
                    Rectangle recta = new Rectangle(ChosenRect.X + xOffset, ChosenRect.Y, 64, 64);

                    SpriteEffects effects = Inverted ? SpriteEffects.FlipHorizontally : SpriteEffects.None;
                    _spriteBatch.Draw(CuteGuyT, recta, null, ColorConverter[a.CompanionColor], 0f, Vector2.Zero, effects, 0f);
                }


                if (!Mirror && GameState != "charedit" && a.YLevelInFeet == 0 && a.Room == null && a.Block != null && a.Block.Biome == "ocean")
                {
                    _spriteBatch.Draw(WaterOverlayT, newRect, Color.White);
                }

                if (a.Protected)
                {
                    if (CharacterRects.TryGetValue("useyourimagination", out Rectangle sourceRect))
                    {
                        _spriteBatch.Draw(
                            DecidedSheet,
                            ChosenRect,
                            sourceRect,
                            Color.Gray,
                            0f,
                            Vector2.Zero,
                            SpriteEffects.None,
                            0f
                        );
                    }
                }

            }

            void DrawClothingItem(Vector2 position, Object clothingItem, float scale, bool inverted, Architect a, bool Mirror, Texture2D DecidedSheetC)
            {
                if (clothingItem == null)
                    return;

                // Do not draw any clothing if the character is invisible and their PathOfShadowLevel is high enough
                if (a.Invisible)
                {
                    // Always skip undergarments and brassiere when invisible
                    if (clothingItem.Type == "undergarment" || clothingItem.Type == "brassiere")
                        return;

                    // Also skip all other clothing if PathOfShadowLevel is 6 or more
                    if (a.PathOfShadowLevel >= 6)
                        return;
                }


                string[] splitTest = clothingItem.Type.Split(' ');

                if (Mirror == true)
                {
                    if (splitTest[0] == "left")
                    {
                        splitTest[0] = "right";
                    }
                    else if (splitTest[0] == "right")
                    {
                        splitTest[0] = "left";
                    }
                }
                
                string ClothingTypeNew = string.Join(' ', splitTest);


                // Handle gendered clothing types
                if (ClothingTypeNew == "chestplate" || ClothingTypeNew.EndsWith("shirt") || ClothingTypeNew == "robe")
                {
                    ClothingTypeNew += " " + a.Sex; // Append "male" or "female"
                }

                // Check if the clothing sprite exists
                if (!CharacterRects.ContainsKey(ClothingTypeNew))
                    return;

                // Determine the correct color
                Color drawColor = clothingItem.DyedColor != "none"
                    ? ColorConverter[clothingItem.DyedColor]
                    : ColorConverter[clothingItem.Materials[0].Color];

                // Updated scale dimensions based on 1000x1000 source frames
                int scaledWidth = (int)(1000 * scale);
                int scaledHeight = (int)(1000 * scale);

                // Preserve the original offset used for visual alignment (18px)
                int offsetX = (int)(18 * scale);

                // Draw rect is centered and offset like before
                Rectangle drawRect = new Rectangle(
                    (int)position.X - scaledWidth / 2 - offsetX,
                    (int)position.Y - scaledHeight,
                    scaledWidth,
                    scaledHeight
                );

                // Draw base mirror (if used visually as a silhouette or reflection layer)
                SpriteEffects effect = inverted ? SpriteEffects.FlipHorizontally : SpriteEffects.None;
                _spriteBatch.Draw(MirrorT, drawRect, null, Color.White, 0f, Vector2.Zero, effect, 0f);

                // Draw the clothing sprite from the correct rect
                _spriteBatch.Draw(
                    DecidedSheetC,
                    drawRect,
                    CharacterRects[ClothingTypeNew],
                    drawColor,
                    0f,
                    Vector2.Zero,
                    effect,
                    0f
                );

            }


            void DrawBackground()
            {
                // Map biome key to static texture reference
                Dictionary<string, Texture2D> textureMap = new()
    {
        { "plains", Plains },
        { "forest", Forest },
        { "lightforest", Forest },
        { "tundra", Tundra },
        { "snowpeak", Tundra },
        { "taiga", Taiga },
        { "mountain", Taiga },
        { "ocean", Ocean },
        { "desert", Desert }
    };

                // Get screen dimensions
                int screenWidth = _graphics.PreferredBackBufferWidth;
                int screenHeight = _graphics.PreferredBackBufferHeight;

                // Determine current biome
                string biomeKey = MostRecentPartyTurnArchitect.District.Location.Region.Biome.ToLower();

                // Fetch texture
                if (!textureMap.TryGetValue(biomeKey, out Texture2D backgroundTexture))
                    return;

                // Mouse state
                MouseState mouse = Mouse.GetState();

                // Background image dimensions
                int bgWidth = backgroundTexture.Width;
                int bgHeight = backgroundTexture.Height;

                // Overflow beyond screen
                int overflowX = bgWidth - screenWidth;
                int overflowY = bgHeight - screenHeight;

                // Normalize mouse position
                float normMouseX = MathHelper.Clamp((float)mouse.X / screenWidth, 0f, 1f);
                float normMouseY = MathHelper.Clamp((float)mouse.Y / screenHeight, 0f, 1f);

                // Scale the effect to be more subtle
                float motionScale = 0.00f; // 10% motion strength

                float offsetX = normMouseX * overflowX * motionScale;
                float offsetY = normMouseY * overflowY * motionScale;

                // Draw background
                _spriteBatch.Draw(backgroundTexture, new Vector2(-offsetX, -offsetY), Color.White * 0.2f);
            }




            void TutorialLogic()
            {
                if (TutorialPhase != 0 && TutorialActive || TutorialPhase == 40)
                {
                    // Screen dimensions
                    int screenWidth = 2560;
                    int screenHeight = 1440;

                    // Texture dimensions
                    int textureWidth = 979;
                    int textureHeight = 192;

                    // Centered X position for the texture
                    float textureXPosition = (screenWidth - textureWidth) / 2f;

                    // Y position 64 pixels above the bottom
                    float textureYPosition = (screenHeight - textureHeight - 64);

                    // Rectangle for the texture
                    Rectangle textureRect = new Rectangle((int)textureXPosition, (int)textureYPosition, textureWidth, textureHeight);

                    // Draw the texture
                    _spriteBatch.Draw(TutorialT, new Vector2(textureRect.X, textureRect.Y), Color.White);
                    
                    
                    string tutorialText = "";
                    // Get the text from TutorialSteps using TutorialPhase
                    if (TutorialPhase != 40)
                    {
                        tutorialText = TutorialSteps[TutorialPhase].Text.Replace("[DISTRICTNAME]", MostRecentPartyTurnArchitect.District.Name).Replace("[NAME]", LoadedArchitects.First(a => a.Race.Name == "nightfell").Name);

                    }
                    else
                    {
                        tutorialText = TutorialSteps[TutorialPhase].Text;
                    }

                    // Split text into lines of up to 90 characters
                    List<string> lines = new List<string>();
                    while (tutorialText.Length > 90)
                    {
                        int splitIndex = tutorialText.LastIndexOf(' ', 90); // Split at the last space before 90 characters
                        if (splitIndex == -1) splitIndex = 90; // If no space is found, split at 90 characters
                        lines.Add(tutorialText.Substring(0, splitIndex).Trim());
                        tutorialText = tutorialText.Substring(splitIndex).Trim();
                    }
                    lines.Add(tutorialText); // Add the remaining text

                    // Calculate the initial Y position, starting 20 pixels higher
                    float startYPosition = textureRect.Y + (textureHeight - lines.Count * 30) / 2f - 20;

                    // Draw each line, centered and spaced 30 pixels apart
                    for (int i = 0; i < lines.Count; i++)
                    {
                        Vector2 textSize = BabyShibafont.MeasureString(lines[i]);
                        float textXPosition = (screenWidth - textSize.X) / 2f;
                        float textYPosition = (startYPosition + i * 30);
                        _spriteBatch.DrawString(BabyShibafont, lines[i], new Vector2(textXPosition, textYPosition), Color.White);
                    }

                    if (TutorialSteps[TutorialPhase].IsTrue)
                    {
                        TutorialContinue.InvisibleLock = false;
                    }
                    else
                    {
                        TutorialContinue.InvisibleLock = true;
                    }
                }
                else
                {
                    TutorialContinue.InvisibleLock = true;
                }
            }


            // GetCurrentPageList as you've defined

            // DrawList method adjustment to remove count indicator in split mode
            void DrawList(SpriteBatch spriteBatch, List<(string Description, int Count, int IndentationLevel, Color TextColor, Object Obj)> list, Vector2 startCoords, SpriteFont font, int CurrentObjectPage, int itemsPerPage, int selectedIndex)
            {
                int line = 0;

                if (MostRecentPartyTurnArchitect != null && Game1.GameWorld.GameMode == "chronicle" && MostRecentPartyTurnArchitect.BlindCycles > 0)
                {
                    string ind = $"You are currently blind.";
                    Vector2 indpos = new Vector2(startCoords.X, startCoords.Y + line * 25);
                    spriteBatch.DrawString(font, ind, indpos, Color.Yellow);
                }
                else
                {
                    int startIndex = CurrentObjectPage * itemsPerPage;
                    int endIndex = Math.Min(startIndex + itemsPerPage, list.Count);

                    // Draw the page indicator
                    string pageIndicator = $"(page {CurrentObjectPage + 1} of {MaximumObjectPage + 1}, use CTRL + / -)";
                    Vector2 pageIndicatorPosition = new Vector2(startCoords.X, startCoords.Y + line * 25);
                    spriteBatch.DrawString(font, pageIndicator, pageIndicatorPosition, Color.White);
                    line++;

                    if (!InInventory && !Keyboard.GetState().IsKeyDown(Keys.Tab) && GameWorld.GameMode != "ascendant")
                    {
                        pageIndicator = "Click to Pick Up. Shift Click to Pick Up Stack.";
                        pageIndicatorPosition = new Vector2(startCoords.X, startCoords.Y + line * 25);
                        spriteBatch.DrawString(font, pageIndicator, pageIndicatorPosition, Color.White);
                        line++;
                    }

                    if (AscendantState == "giveitems")
                    {
                        pageIndicator = "Press Enter to gift an item to this architect. [X] to cancel.";
                        pageIndicatorPosition = new Vector2(startCoords.X, startCoords.Y + line * 25);
                        spriteBatch.DrawString(font, pageIndicator, pageIndicatorPosition, Color.White);
                        line++;
                    }
                    else if (AscendantState == "takeitems")
                    {
                        pageIndicator = "Press Enter to move an item to your organizational stockpile. [X] to cancel.";
                        pageIndicatorPosition = new Vector2(startCoords.X, startCoords.Y + line * 25);
                        spriteBatch.DrawString(font, pageIndicator, pageIndicatorPosition, Color.White);
                        line++;
                    }

                    if (MostRecentPartyTurnArchitect.Structure != null && !InInventory && !Keyboard.GetState().IsKeyDown(Keys.Tab))
                    {
                        pageIndicator = "[<] denotes a nearby exit. Click Door To Enter.";
                        pageIndicatorPosition = new Vector2(startCoords.X, startCoords.Y + line * 25);
                        spriteBatch.DrawString(font, pageIndicator, pageIndicatorPosition, Color.White);
                        line++;
                    }

                    // Display "The Stockpile is Empty." if GameState is "ascendant" and the list is empty
                    if (GameState == "ascendant" && list.Count == 0)
                    {
                        string emptyMessage = "This storage is empty";
                        Vector2 emptyMessagePosition = new Vector2(startCoords.X, startCoords.Y + line * 25);
                        spriteBatch.DrawString(font, emptyMessage, emptyMessagePosition, Color.White);
                        return; // Stop further processing
                    }

                    // Adjust start coordinates for drawing the actual list
                    startCoords = new Vector2(startCoords.X, startCoords.Y + 20);

                    for (int i = startIndex; i < endIndex; i++)
                    {
                        var (Description, Count, IndentationLevel, TextColor, Obj) = list[i];

                        string MarketVal = (MostRecentPartyTurnArchitect.Structure != null && MostRecentPartyTurnArchitect.Structure.Type == "market") ? $", ({Obj.Value()}* ea.)" : "";

                        string selectionIndicator = selectedIndex == -1 ? "" : (i == selectedIndex ? "[X] " : "[ ] ");

                        string textToDraw = selectionIndicator + (SplitMode ?
                            $"{new string(' ', 4 * IndentationLevel)}{Description}" :
                            $"{new string(' ', 4 * IndentationLevel)}{Description} x{Count}" + MarketVal);

                        Vector2 textPosition = new Vector2(startCoords.X, startCoords.Y + line * 25);
                        spriteBatch.DrawString(font, textToDraw, textPosition, TextColor);

                        Vector2 textSize = font.MeasureString(textToDraw);

                        if(ShowImbuements)
                        {

                            for (int j = 0; j < Obj.Imbuements.Count; j++)
                            {
                                var imb = Obj.Imbuements[j];
                                Color imbColor = imb.IsActive ? Color.White : Color.Gray;

                                // Position: 32px * (j + 1) to the left of text
                                float imbX = textPosition.X - 28 * (j + 1);
                                float imbY = textPosition.Y + (textSize.Y / 2f) - 8; // center vertically for 16x16 icon

                                Rectangle destRect = new Rectangle((int)imbX, (int)imbY, 16, 16);
                                spriteBatch.Draw(ImbuementNode, destRect, imbColor);
                            }

                        }
                        // Add hitbox for the object
                        EntityHitboxes.Add((new Rectangle(textPosition.ToPoint(), font.MeasureString(textToDraw).ToPoint()), Obj));

                        line++;
                    }

                    MaximumObjectPage = (int)Math.Round((decimal)(list.Count / itemsPerPage), 0, MidpointRounding.ToPositiveInfinity);
                }
            }



