            void WorldMouseLogic()
            {
                for (int x = 0; x < GameWorld.Width; x++)
                {
                    for (int z = 0; z < GameWorld.Length; z++)
                    {
                        // Calculate the original bounding box
                        Rectangle originalBoundingBox = new Rectangle(
                            (Game1.RegionXMod + x * Game1.TileXDistance) + ((z % 2 == 1) ? Game1.TileXDistance / 2 : 0),
                            Game1.RegionYMod + z * Game1.TileZDistance,
                            Game1.TileSize,
                            Game1.TileSize
                        );

                        if (originalBoundingBox.Contains(scaledMousePosition))
                        {
                            if (GameWorld.WorldMap[x + z * GameWorld.Width].Location == null)
                            {
                                _spriteBatch.DrawString(BabyShibafont, "No Notable Location, " + GameWorld.WorldMap[x + z * GameWorld.Width].Biome, new Vector2(DrawX, DrawY), Color.White);
                            }
                            else
                            {
                                _spriteBatch.DrawString(BabyShibafont, GameWorld.WorldMap[x + z * GameWorld.Width].Location.Name + ", " + GameWorld.WorldMap[x + z * GameWorld.Width].Biome + " " + GameWorld.WorldMap[x + z * GameWorld.Width].Location.Type + ".", new Vector2(DrawX, DrawY), Color.White);
                                _spriteBatch.DrawString(BabyShibafont,
                                                "Population: " + GameWorld.WorldMap[x + z * GameWorld.Width].Location.TruePopulation() +
                                                (GameWorld.WorldMap[x + z * GameWorld.Width].Location.PrimaryRace != null && GameWorld.WorldMap[x + z * GameWorld.Width].Location.PrimaryRace.Name != "" ?
                                                " (Primarily " + GameWorld.WorldMap[x + z * GameWorld.Width].Location.PrimaryRace.Name + ")" : ""),
                                                new Vector2(DrawX, DrawY + 30),
                                                Color.White);


                                int ArchitectPopulation = 0;
                                int structures = 0;
                                int groups = 0;

                                foreach (Group g in Game1.GameWorld.Groups)
                                {
                                    if (g.Leader.Location == GameWorld.WorldMap[x + z * GameWorld.Width].Location)
                                        groups++;
                                }

                                foreach (District d in GameWorld.WorldMap[x + z * GameWorld.Width].Location.Districts)
                                {
                                    ArchitectPopulation += d.DistrictArchitects.Count();

                                    for (int DistrictX = 0; DistrictX < 7; DistrictX++)
                                    {
                                        for (int DistrictZ = 0; DistrictZ < 7; DistrictZ++)
                                        {
                                            foreach (Structure s in d.DistrictMap[DistrictX + DistrictZ * 7].Structures)
                                            {
                                                structures++;
                                            }
                                        }
                                    }
                                }

                                _spriteBatch.DrawString(BabyShibafont, "Total Architects: " + ArchitectPopulation, new Vector2(DrawX, DrawY + 60), Color.White);

                                if (GameWorld.WorldMap[x + z * GameWorld.Width].Location.Government == null)
                                {
                                    _spriteBatch.DrawString(BabyShibafont, "No Notable Government", new Vector2(DrawX, DrawY + 90), Color.White);
                                }
                                else
                                {
                                    _spriteBatch.DrawString(BabyShibafont, "Government: " + GameWorld.WorldMap[x + z * GameWorld.Width].Location.Government.Name, new Vector2(DrawX, DrawY + 90), Color.White);
                                }

                                _spriteBatch.DrawString(BabyShibafont, "Colonization Desire: " + GameWorld.WorldMap[x + z * GameWorld.Width].Location.ColonizationDesire, new Vector2(DrawX, DrawY + 120), Color.White);
                                _spriteBatch.DrawString(BabyShibafont, "Wealth: " + GameWorld.WorldMap[x + z * GameWorld.Width].Location.Wealth, new Vector2(DrawX, DrawY + 150), Color.White);
                                _spriteBatch.DrawString(BabyShibafont, "Is Saving Up To Settle: " + GameWorld.WorldMap[x + z * GameWorld.Width].Location.IsSavingUpToSettle.ToString(), new Vector2(DrawX, DrawY + 180), Color.White);


                                _spriteBatch.DrawString(BabyShibafont, "Structures: " + structures, new Vector2(DrawX, DrawY + 210), Color.White);
                                _spriteBatch.DrawString(BabyShibafont, "Groups: " + groups, new Vector2(DrawX, DrawY + 240), Color.White);
                                _spriteBatch.DrawString(BabyShibafont, "Districts: " + GameWorld.WorldMap[x + z * GameWorld.Width].Location.Districts.Count(), new Vector2(DrawX, DrawY + 270), Color.White);
                            }
                        }
                    }
                }
            }



            void DrawAnnouncements()
            {
                int MaxLines;
                int yPos;
                int screenHeight = 1440;

                if (GameState == "ascendant")
                    (MaxLines, yPos) = (36, screenHeight - 100);
                else
                    (MaxLines, yPos) = (36, screenHeight - 300);

                int MaxLength = 590;
                int lineHeight = 20;
                int totalLinesDisplayed = 0;

                int totalLinesNeeded = AnnouncementScrollValue + MaxLines;
                List<(string line, Color color, List<(string word, int charIndex, int globalWordIndex)> wordInfo, List<(int globalWordIndex, Entity entity)>)> allLines = new();
                int linesAccumulated = 0;

                for (int i = Announcements.Count - 1; i >= 0 && linesAccumulated < totalLinesNeeded; i--)
                {
                    TextStorage announcement = Announcements[i];
                    var splitLines = new List<(string lineText, List<(string word, int charIndex, int globalWordIndex)> wordInfo)>();
                    var announcementWordInfo = new List<(string word, int globalWordIndex)>();
                    var matchedWords = new List<(int globalWordIndex, Entity entity)>();
                    int globalWordCounter = 0;

                    if (BabyShibafont.MeasureString(announcement.Data).X > MaxLength)
                    {
                        string[] words = announcement.Data.Split(' ');
                        string currentLine = "";
                        List<(string word, int charIndex, int globalWordIndex)> currentWordInfo = new();
                        int charCursor = 0;

                        foreach (var word in words)
                        {
                            string testLine = currentLine + word + " ";
                            if (BabyShibafont.MeasureString(testLine).X > MaxLength)
                            {
                                splitLines.Add((currentLine.TrimEnd(), currentWordInfo));
                                currentLine = word + " ";
                                currentWordInfo = new() { (word, 0, globalWordCounter) };
                                announcementWordInfo.Add((word, globalWordCounter++));
                                charCursor = word.Length + 1;
                            }
                            else
                            {
                                currentWordInfo.Add((word, charCursor, globalWordCounter));
                                announcementWordInfo.Add((word, globalWordCounter++));
                                currentLine += word + " ";
                                charCursor += word.Length + 1;
                            }
                        }

                        if (currentLine.Length > 0)
                            splitLines.Add((currentLine.TrimEnd(), currentWordInfo));
                    }
                    else
                    {
                        string[] words = announcement.Data.Split(' ');
                        List<(string word, int charIndex, int globalWordIndex)> wordInfo = new();
                        int charIndex = 0;
                        foreach (var word in words)
                        {
                            wordInfo.Add((word, charIndex, globalWordCounter));
                            announcementWordInfo.Add((word, globalWordCounter++));
                            charIndex += word.Length + 1;
                        }
                        splitLines.Add((announcement.Data, wordInfo));
                    }

                    // Perform full-announcement name matching
                    foreach (var entity in announcement.Entities)
                    {
                        foreach (var name in entity.ReferredToNames)
                        {
                            var nameParts = name.Split(' ');
                            for (int j = 0; j <= announcementWordInfo.Count - nameParts.Length; j++)
                            {
                                bool matched = true;
                                for (int k = 0; k < nameParts.Length; k++)
                                {
                                    if (!string.Equals(announcementWordInfo[j + k].word.TrimEnd('.', ',', ':', ';', '!', '?', ')', '(', '"', '\''), nameParts[k], StringComparison.OrdinalIgnoreCase))
                                    {
                                        matched = false;
                                        break;
                                    }
                                }

                                if (matched)
                                {
                                    for (int k = 0; k < nameParts.Length; k++)
                                    {
                                        matchedWords.Add((announcementWordInfo[j + k].globalWordIndex, entity));
                                    }
                                    break;
                                }
                            }
                        }
                    }

                    for (int j = splitLines.Count - 1; j >= 0; j--)
                    {
                        allLines.Add((splitLines[j].lineText, announcement.Color, splitLines[j].wordInfo, matchedWords));
                        linesAccumulated++; // ✅ Update here
                        if (linesAccumulated >= totalLinesNeeded)
                            break; // Exit if we've accumulated enough lines
                    }
                }

                // Skip by lines, not announcements
                int linesToSkip = AnnouncementScrollValue;
                
                var visibleLines = allLines.Skip(AnnouncementScrollValue).Take(MaxLines).ToList();


                if (MostRecentPartyTurnArchitect != null &&
                    Game1.GameWorld.GameMode == "chronicle" &&
                    MostRecentPartyTurnArchitect.BlindCycles > 0 &&
                    GameState != "dead")
                {
                    yPos -= lineHeight; DrawAnnouncementLine("on targets your character remembers.", yPos, Color.Yellow, new(), new(), new());
                    yPos -= lineHeight;
                    DrawAnnouncementLine("like \"wait\" to wait out blindness, or initiate attacks", yPos, Color.Yellow, new(), new(), new());
                    yPos -= lineHeight;
                    DrawAnnouncementLine("You are currently blind. You can still use commands.", yPos, Color.Yellow, new(), new(), new());

                }
                else
                {
                    foreach (var (line, color, wordInfo, matchedWords) in visibleLines)
                    {
                        yPos -= lineHeight;
                        DrawAnnouncementLine(line, yPos, color, new(), wordInfo, matchedWords);
                        totalLinesDisplayed++;
                    }
                }

                int scrollHintY = (GameState == "ascendant")
                ? 1360
                : screenHeight - (lineHeight * 38) - 300;

                _spriteBatch.DrawString(BabyShibafont, "Use Scroll Wheel to see Past Announcements", new Vector2(50, scrollHintY), Color.Gray);



                //merge hitboxes


                var grouped = EntityHitboxes
                .GroupBy(h => (h.Item2, h.Item1.Y)) // group by (Entity, Y)
                .SelectMany(group =>
                {
                    var sorted = group.OrderBy(h => h.Item1.X).ToList();
                    List<(Rectangle rect, Entity entity)> mergedGroup = new();

                    Rectangle current = sorted[0].Item1;

                    for (int i = 1; i < sorted.Count; i++)
                    {
                        Rectangle next = sorted[i].Item1;

                        int gap = next.X - (current.X + current.Width);

                        if (gap <= 30)
                        {
                            // Merge horizontally
                            int newX = current.X;
                            int newWidth = (next.X + next.Width) - current.X;
                            current = new Rectangle(newX, current.Y, newWidth, current.Height);
                        }
                        else
                        {
                            // Add the finalized current rectangle before moving on
                            mergedGroup.Add((current, group.Key.Item1));
                            current = next;
                        }
                    }

                    // Add the final merged rectangle
                    mergedGroup.Add((current, group.Key.Item1));
                    return mergedGroup;
                })
                .ToList();

                // Replace original hitboxes with merged results
                EntityHitboxes = grouped.Distinct().ToList();


            }

