                    shibaTextLine3 = "related note, I spent more time on the seed feature than the entire magic system, so treat it less like a toddler toy. I guess I could have modulo 2 billioned the number or something, but this was more fun.";

                    // Measure one line since font size is consistent
                    shibaTextSize = currentFont.MeasureString(shibaTextLine1);
                    shibaTextY = worldSizeTextY + worldSizeTextSize.Y + buttonSpacing; // Position below World Size text

                    // Draw the three lines in BabyShibafont
                    _spriteBatch.DrawString(currentFont, shibaTextLine1, new Vector2(shibaTextX, shibaTextY), Color.Yellow);
                    _spriteBatch.DrawString(currentFont, shibaTextLine2, new Vector2(shibaTextX, shibaTextY + shibaTextSize.Y), Color.Yellow);
