                    _spriteBatch.DrawString(Shibafont, "Click to select a save file", new Vector2(200, 200), Color.White);

                    // Adding three lines of space
                    int startingY = 350;

                    int Number = 0;

                    foreach (string d in saveDirectories)
                    {
                        var directoryName = d.Split('/', '\\').Last();

                        if (directoryName.Equals("crashreports", StringComparison.OrdinalIgnoreCase))
                            continue; // Skip the directory

                        var versionFilePath = Path.Combine(d, "version.txt");
                        Color textColor = Color.White;

                        if (File.Exists(versionFilePath))
                        {
                            string firstLine = File.ReadLines(versionFilePath).FirstOrDefault();
                            if (firstLine == Version)
                            {
                                textColor = Color.White; // Matching version
                            }
                            else
                            {
                                textColor = Color.Gray;
                                directoryName += $" (Version Mismatch: Current: {Version}, Required: {firstLine})";
                            }
                        }
                        else
                        {
                            textColor = Color.Gray;
                            directoryName += " (No Version File, Game Save Incomplete)";
                        }

                        if (directoryName.StartsWith("The Continent") && Number == LoadGameCursor && File.Exists(versionFilePath))
                        {
                            _spriteBatch.DrawString(Shibafont, "This save file was created after your previous death.", new Vector2(200, 230), Color.White);
                            _spriteBatch.DrawString(Shibafont, "If you would like to start a new game with this world, click Play.", new Vector2(200, 260), Color.White);
                        }

