                            // Define stretch scale factors// Function to animate console colors
                            Color GetConsoleColorAnimation(int colorTick)
                            {
                                int ticksPerPhase = 60;
                                int phase = (colorTick / ticksPerPhase) % 6;
                                float progress = (colorTick % ticksPerPhase) / (float)ticksPerPhase;

                                return phase switch
                                {
                                    0 => new Color(255, (int)(progress * 255), 0), // Red → Yellow
                                    1 => new Color(255 - (int)(progress * 255), 255, 0), // Yellow → Green
                                    2 => new Color(0, 255, (int)(progress * 255)), // Green → Cyan
                                    3 => new Color(0, 255 - (int)(progress * 255), 255), // Cyan → Blue
                                    4 => new Color((int)(progress * 255), 0, 255), // Blue → Purple
                                    5 => new Color(255, 0, 255 - (int)(progress * 255)), // Purple → Red
                                    _ => Color.White
                                };
                            }


