                                string GetAppendageLabel(Object appendage, bool isMain, Entity heldObject, bool otherHandEmpty)
                                {
                                    if (heldObject != null && heldObject is Object o && o.IsTwoHanded)
                                    {
                                        if (otherHandEmpty)
                                        {
                                            return "TH: ";
                                        }
                                    }

                                    if (appendage.Type == "left hand")
                                        return "LH: ";
                                    else if (appendage.Type == "right hand")
                                        return "RH: ";

                                    return isMain ? "M: " : "O: ";
                                }

                                string GetAppendageText(Object appendage, Entity heldObject, bool isMain, bool otherHandEmpty)
                                {
                                    // Multigrasp handling is in the label logic
                                    string appendageText = heldObject != null
                                        ? GetAppendageLabel(appendage, isMain, heldObject, otherHandEmpty) + heldObject.ReferredToNames[0]
                                        : GetAppendageLabel(appendage, isMain, heldObject, otherHandEmpty) + "(empty)";

                                    if (appendageText.Length > 17)
                                        appendageText = appendageText.Substring(0, 18) + "...";

                                    return appendageText;
                                }

                                void DrawAppendageText(Object appendage, Entity heldObject, bool isMain, Vector2 position, bool otherHandEmpty)
                                {
                                    bool isEmpty = heldObject == null;

                                    // If holding a multigrasp weapon and other hand is empty, only draw TH label on this hand
                                    if (heldObject != null && heldObject is Object o && o.IsTwoHanded)
                                    {
                                        if (!otherHandEmpty) return; // Skip drawing on the other empty hand

                                        string appendageText = GetAppendageText(appendage, heldObject, isMain, true);
                                        _spriteBatch.DrawString(Shibafont, appendageText, position, Color.White);
                                        Entity appendageEntity = heldObject != null ? heldObject : appendage;
                                        EntityHitboxes.Add((new Rectangle(position.ToPoint(), Shibafont.MeasureString(appendageText).ToPoint()), appendageEntity));
                                        return;
                                    }

                                    // Handle dropped case
                                    bool oopsDropped = isEmpty && appendage is Object obj && obj.OopsIDroppedIt == true;
                                    string label = GetAppendageLabel(appendage, isMain, heldObject, false);
                                    string text = oopsDropped ? label + "[Dropped]" : GetAppendageText(appendage, heldObject, isMain, false);

                                    Color textColor = oopsDropped ? new Color(255, 255, 0) : Color.White;

                                    _spriteBatch.DrawString(Shibafont, text, position, textColor);
                                    Entity appendageEnt = heldObject != null ? heldObject : appendage;
                                    EntityHitboxes.Add((new Rectangle(position.ToPoint(), Shibafont.MeasureString(text).ToPoint()), appendageEnt));
                                }


                                if (MostRecentPartyTurnArchitect.CarryingEntity == null)
                                {
                                    bool isMainHandEmpty = MostRecentPartyTurnArchitect.MainHeldObject == null;
                                    bool isOffHandEmpty = MostRecentPartyTurnArchitect.OffHeldObject == null;

                                    bool mainHasTwoHanded = MostRecentPartyTurnArchitect.MainHeldObject is Object o1 && o1.IsTwoHanded;
                                    bool offHasTwoHanded = MostRecentPartyTurnArchitect.OffHeldObject is Object o2 && o2.IsTwoHanded;

                                    // Main hand
                                    bool skipOffHand = false;
                                    bool skipMainHand = false;

                                    // If main hand is holding a two-handed item and offhand is empty, skip offhand draw
                                    if (mainHasTwoHanded && isOffHandEmpty)
                                    {
                                        skipOffHand = true;
                                    }

                                    // If offhand is holding a two-handed item and main is empty, skip main hand draw
                                    if (offHasTwoHanded && isMainHandEmpty)
                                    {
                                        skipMainHand = true;
                                    }

                                    // Main hand
                                    if (!skipMainHand)
                                    {
                                        DrawAppendageText(
                                            MostRecentPartyTurnArchitect.MainInteractionAppendage,
                                            MostRecentPartyTurnArchitect.MainHeldObject,
                                            true,
                                            new Vector2(60, 220),
                                            isOffHandEmpty && mainHasTwoHanded
                                        );
                                    }

                                    // Off hand
                                    if (!skipOffHand)
                                    {
                                        DrawAppendageText(
                                            MostRecentPartyTurnArchitect.OffInteractionAppendage,
                                            MostRecentPartyTurnArchitect.OffHeldObject,
                                            false,
                                            new Vector2(60, 250),
                                            isMainHandEmpty && offHasTwoHanded
                                        );
                                    }

                                }
                                else
                                {
                                    _spriteBatch.DrawString(Shibafont, "Haul: " + MostRecentPartyTurnArchitect.CarryingEntity.ReferredToNames[0], new Vector2(60, 220), Color.White);
                                }


