                            int line = 0;

                            TutorialLogic();

                            var sourceObjects = MostRecentPartyTurnArchitect.Inventory;
                            var structuredList = CondenseAndStructureList(sourceObjects, SplitMode);
                            DrawList(_spriteBatch, structuredList, new Vector2(2100, 100), BabyShibafont, CurrentObjectPage, ItemsPerPage, -1);

                            line = 0;
                            if (MostRecentPartyTurnArchitect.Clothing.Count() == 0)
                            {
                                DrawCenteredTextAtPosition(_spriteBatch, "You have no clothing. Please put some on.", 1625, 425, BabyShibafont, Color.White);
                            }
                            else
                            {
                                foreach (Object o in MostRecentPartyTurnArchitect.Clothing)
                                {
                                    float centerY = 425 + 20 * line;
                                    string text = o.ReferredToNames[0];

                                    // Measure the size of the text
                                    Vector2 textSize = BabyShibafont.MeasureString(text);

                                    // Calculate the position to start drawing the text so that it is centered on (1625, centerY)
                                    float xPosition = 1625 - (textSize.X / 2);
                                    float yPosition = centerY - (textSize.Y / 2);

                                    // Draw the text centered
                                    DrawCenteredTextAtPosition(_spriteBatch, text, 1625, centerY, BabyShibafont, Color.White);

                                    if(ShowImbuements)
                                    {
                                        // Draw Imbuement Nodes if applicable
                                        if (o.Imbuements != null)
                                        {
                                            for (int j = 0; j < o.Imbuements.Count; j++)
                                            {
                                                var imb = o.Imbuements[j];
                                                Color imbColor = imb.IsActive ? Color.White : Color.Gray;

                                                // Position: 32px * (j + 1) to the left of the LEFT EDGE of the text
                                                float imbX = xPosition - 24 * (j + 1);
                                                float imbY = centerY - 8; // center vertically (assuming 16x16 icons)

                                                Rectangle destRect = new Rectangle((int)imbX, (int)imbY, 16, 16);
                                                _spriteBatch.Draw(ImbuementNode, destRect, imbColor);
                                            }
                                        }

                                    }

                                    // Create a Rectangle for the hitbox
                                    Rectangle hitbox = new Rectangle((int)xPosition, (int)yPosition, (int)textSize.X, (int)textSize.Y);
                                    EntityHitboxes.Add((hitbox, o));

                                    line++;
                                }
                            }


                            line = 0;

                            var intrigues = GameWorld.GamePlayerAssociation.ActiveParty.Intrigue;
                            var filteredIntrigues = intrigues
                                .Where((intrigue, index) =>
                                {
                                    bool prevSame = index > 0 && intrigues[index - 1].Data == intrigue.Data;
                                    bool nextSame = index < intrigues.Count - 1 && intrigues[index + 1].Data == intrigue.Data;
                                    return !prevSame && !nextSame;
                                })
                                .ToList();
                            List<(string Line, Color Color, EntityList<Entity> Entities)> wrappedLines = new();

                            float maxLineWidth = 600f;

                            foreach (var intrigue in filteredIntrigues)
                            {
                                string data = intrigue.Data;
                                string[] words = data.Split(' ');
                                int i = 0;

                                while (i < words.Length)
                                {
                                    string wrappedLine = "";
                                    while (i < words.Length)
                                    {
                                        string testLine = (wrappedLine.Length > 0 ? wrappedLine + " " : "") + words[i];
                                        float width = BabyShibafont.MeasureString(testLine).X;

                                        if (width > maxLineWidth)
                                            break;

                                        wrappedLine = testLine;
                                        i++;
                                    }

                                    // Handle very long word
                                    if (wrappedLine == "" && i < words.Length)
                                    {
                                        wrappedLine = words[i];
                                        i++;
                                    }

                                    wrappedLines.Add((wrappedLine, intrigue.Color, intrigue.Entities));
                                }
                            }







                            // Show only the last 10 wrapped lines
                            var linesToDraw = wrappedLines.Skip(Math.Max(0, wrappedLines.Count - 10));

                            if (!linesToDraw.Any())
                            {
                                DrawCenteredTextAtPosition(_spriteBatch, "Nothing is here yet...", 1625, 1150, BabyShibafont, Color.White);
                            }
                            else
                            {
                                foreach (var (text, color, entities) in linesToDraw)
                                {
                                    Vector2 textPosition = new Vector2(1640, 1150 + 20 * line);
                                    DrawCenteredTextAtPosition(_spriteBatch, text, (int)textPosition.X, (int)textPosition.Y, BabyShibafont, color);

                                    Vector2 textSize = Shibafont.MeasureString(text);
                                    Rectangle hitbox = new Rectangle(textPosition.ToPoint(), textSize.ToPoint());

                                    foreach (var entity in entities)
                                    {
                                        if (entity != null)
                                        {
                                            EntityHitboxes.Add((hitbox, entity));
                                        }
                                    }

                                    line++;
                                }
