                            line = 0;









                            // Buff name mappings
                            var BuffMappings = new Dictionary<string, string>
{
    { "+attack", "attack power" },
    { "+shield", "shield effectiveness" },
    { "+dodge", "roll chance" },
    { "+weaponreaction", "redirection chance" },
    { "+bashpierce", "bashing and piercing resistance" },
    { "+slashthrash", "slashing and thrashing resistance" },
    { "+stealth", "stealth" },
    { "+regen", "energy regeneration" }
};

                            string ReplaceBuffNames(string input)
                            {
                                foreach (var mapping in BuffMappings)
                                    input = input.Replace(mapping.Key, mapping.Value);
                                return input;
                            }

                            // Melded Shibas
                            if (MostRecentPartyTurnArchitect.MeldedShibas.Count > 0)
                            {
                                string meldedShibasText = MostRecentPartyTurnArchitect.MeldedShibas.Count == 1 ?
                                    "1 shiba has melded with your face, applying unstable buffs." :
                                    $"{MostRecentPartyTurnArchitect.MeldedShibas.Count} shibas have melded with your face, applying unstable buffs.";

                                DrawCenteredTextAtPosition(_spriteBatch, meldedShibasText, 950, 425 + 20 * line, BabyShibafont, Color.White);
                                line++;
                            }

                            // New imbuement processing
                            var imbuementData = new Dictionary<(string Key, bool IsActive, bool IsTrigger), (int Count, int CombinedSecondPower, Imbuement Imbuement, int Contributors, Color Color)>();

                            foreach (Imbuement i in MostRecentPartyTurnArchitect.AllImbuements)
                            {
                                string descriptionKey = i.IsTrigger
                                    ? ReplaceBuffNames(i.GetDescription())  // Use full description for triggers
                                    : $"{i.GetConditionDescription()}::{i.BuffOrResult}";


                                var key = (descriptionKey, i.IsActive, i.IsTrigger);

                                Color color = i.IsTrigger ? Color.Goldenrod : (i.IsSatisfied ? Color.Lime : Color.White);
                                if (!i.IsActive) color *= 0.5f;

                                if (imbuementData.TryGetValue(key, out var existing))
                                {
                                    int newSecondPower = existing.Imbuement.SecondPower + i.SecondPower;
                                    imbuementData[key] = (
                                        existing.Count + 1,
                                        newSecondPower,
                                        i,
                                        existing.Contributors + 1,
                                        color
                                    );
                                }
                                else
                                {
                                    imbuementData[key] = (1, i.SecondPower, i, 1, color);
                                }
                            }

                            var activeImbuements = imbuementData.Where(e => e.Key.IsActive).ToList();
                            var inactiveImbuements = imbuementData.Where(e => !e.Key.IsActive).ToList();

                            int totalLines = 0;
                            const int maxVisibleLines = 30;
                            int processedImbuements = 0;

                            bool CanAddLines(int additionalLines) => (totalLines + additionalLines) <= maxVisibleLines;
                            
                            void DrawImbuementGroup(
    string header,
    List<KeyValuePair<(string Key, bool IsActive, bool IsTrigger), (int Count, int CombinedSecondPower, Imbuement Imbuement, int Contributors, Color Color)>> imbuements,
    Color headerColor,
    float alpha = 1f)
                            {
                                if (imbuements.Count == 0 || !CanAddLines(1)) return;

                                DrawCenteredTextAtPosition(_spriteBatch, header, 950, 425 + 20 * line, BabyShibafont, headerColor * alpha);
                                line++;
                                totalLines++;

                                foreach (var entry in imbuements)
                                {
                                    var key = entry.Key;
                                    var value = entry.Value;

                                    string description;

                                    // Handle trigger imbuements and stealth (xN)
                                    if (key.IsTrigger || value.Imbuement.BuffOrResult == "+stealth")
                                    {
                                        description = ReplaceBuffNames(value.Imbuement.GetDescription());
                                        if (value.Count > 1)
                                            description += $" (x{value.Count})";
                                    }
                                    else if (value.Imbuement.BuffOrResult == "+regen")
                                    {
                                        // Special case: regenerate N energy per second
                                        string cond = value.Imbuement.GetConditionDescription();
                                        int totalPower = value.CombinedSecondPower;
                                        description = $"{cond}regenerate {totalPower} energy per second";
                                        if (value.Contributors > 1)
                                            description += $" ({value.Contributors} Contributing)";
                                    }
                                    else
                                    {
                                        // Default: add percentages
                                        string cond = value.Imbuement.GetConditionDescription();
                                        string buff = value.Imbuement.BuffOrResult;
                                        int totalPower = value.CombinedSecondPower;
                                        description = $"{cond}increase {buff} by {totalPower}%";
                                        description = ReplaceBuffNames(description);
                                        if (value.Contributors > 1)
                                            description += $" ({value.Contributors} Contributing)";
                                    }

                                    // Word wrap
                                    var splitLines = new List<string>();
                                    while (description.Length > 60)
                                    {
                                        int splitIndex = description.Substring(0, 40).LastIndexOf(' ');
                                        if (splitIndex == -1) splitIndex = 60;

                                        splitLines.Add(description.Substring(0, splitIndex));
                                        description = description.Substring(splitIndex).Trim();
                                    }
                                    splitLines.Add(description);

                                    if (!CanAddLines(splitLines.Count)) break;

                                    foreach (var textLine in splitLines)
                                    {
                                        DrawCenteredTextAtPosition(_spriteBatch, textLine, 950, 425 + 20 * line, BabyShibafont, value.Color * alpha);
                                        line++;
                                        totalLines++;
                                    }

                                    processedImbuements++;
                                }

                                line++;
                                totalLines++;
                            }
                            // Draw
                            DrawImbuementGroup("[Active]", activeImbuements, Color.White);
                            DrawImbuementGroup("[Inactive]", inactiveImbuements, Color.Gray, 0.5f);

                            if (imbuementData.Count == 0 && MostRecentPartyTurnArchitect.MeldedShibas.Count == 0)
                            {
                                DrawCenteredTextAtPosition(_spriteBatch, "No active imbuements.", 950, 425, BabyShibafont, Color.White);
                            }

                            int hiddenImbuements = (activeImbuements.Count + inactiveImbuements.Count) - processedImbuements;
                            if (totalLines >= maxVisibleLines && hiddenImbuements > 0)
                            {
                                DrawCenteredTextAtPosition(_spriteBatch, $"And {hiddenImbuements} more...", 950, 425 + 20 * (line + 1), BabyShibafont, Color.Gray * 0.5f);
                            }














                            // XPValues processing remains unchanged as you already have a check for no entries.

                            int ProfAndTipsX = 303;

                            line = 0;

                            Vector2 txtsize = BabyShibafont.MeasureString("Test"); // You can measure any typical line
                            int lineHeight = (int)txtsize.Y;
                            int totalHeight = Math.Max(1, MostRecentPartyTurnArchitect.Proficiencies.Count) * lineHeight;

                            Rectangle proficienciesArea = new Rectangle(
                                ProfAndTipsX - 200, // Assuming centered, so adjust X width
                                100,
                                400,                // Example width (you could measure widest text if you want)
                                totalHeight
                            );

                            ProficiencyRects.Clear(); // Reset each frame

                            Color[] debugColors = new Color[]
                            {
    Color.Red, Color.Orange, Color.Yellow, Color.Green, Color.Blue,
    Color.Indigo, Color.Violet, Color.Cyan, Color.Magenta, Color.Lime
                            };

                            int profIndex = 0;
                            foreach ((string name, int xp) in MostRecentPartyTurnArchitect.Proficiencies)
                            {
                                int Y = 100 + lineHeight * line;
                                string text = $"{name}: {ConvertNumberToProficiency(MostRecentPartyTurnArchitect.GetProficiency(name))}, {MostRecentPartyTurnArchitect.GetXP(name)} XP";
                                DrawCenteredTextAtPosition(_spriteBatch, text, ProfAndTipsX, Y, BabyShibafont, Color.White);

                                Vector2 textSize = BabyShibafont.MeasureString(text);

                                // Optional: shrink height for more accurate hitbox
                                int rectHeight = (int)(lineHeight * 0.75f);
                                int yOffset = Y + (lineHeight - rectHeight) / 2 - 12; // Shift upward by 25px

                                Rectangle clickable = new Rectangle(
                                    ProfAndTipsX - (int)(textSize.X / 2),
                                    yOffset,
                                    (int)textSize.X,
                                    rectHeight
                                );
                                ProficiencyRects[clickable] = name;

                                // Draw outline for visual debugging
                                Color outlineColor = debugColors[profIndex % debugColors.Length];
                                //_spriteBatch.Draw(whiteRect, new Rectangle(clickable.X, clickable.Y, clickable.Width, 1), outlineColor); // Top
                                //_spriteBatch.Draw(whiteRect, new Rectangle(clickable.X, clickable.Y + clickable.Height - 1, clickable.Width, 1), outlineColor); // Bottom
                                //_spriteBatch.Draw(whiteRect, new Rectangle(clickable.X, clickable.Y, 1, clickable.Height), outlineColor); // Left
                                //_spriteBatch.Draw(whiteRect, new Rectangle(clickable.X + clickable.Width - 1, clickable.Y, 1, clickable.Height), outlineColor); // Right

                                line++;
                                profIndex++;
                            }


                            if (line == 0)
                            {
                                DrawCenteredTextAtPosition(_spriteBatch, "No proficiencies...?", ProfAndTipsX, 120, BabyShibafont, Color.White);
                            }


                            //shortcuts or whatever
                            line = 0;

                            if(SplitMode)
                            {
                                DrawCenteredTextAtPosition(_spriteBatch, "Disable Split Mode to use Shortcuts", ProfAndTipsX, 560 + 20 * line, BabyShibafont, Color.White); line++;
                                DrawCenteredTextAtPosition(_spriteBatch, "(Press F3)", ProfAndTipsX, 560 + 20 * line, BabyShibafont, Color.White); line++;
                            }
                            else
                            {
                                DrawCenteredTextAtPosition(_spriteBatch, "[Main Screen]", ProfAndTipsX, 560 + 20 * line, BabyShibafont, Color.White); line++;
                                DrawCenteredTextAtPosition(_spriteBatch, "Click a door or distinct structure name to enter it.", ProfAndTipsX, 560 + 20 * line, BabyShibafont, Color.White); line++;
                                DrawCenteredTextAtPosition(_spriteBatch, "Click an object name on the ground to pick it up.", ProfAndTipsX, 560 + 20 * line, BabyShibafont, Color.White); line++;
                                DrawCenteredTextAtPosition(_spriteBatch, "Shift click an object to pick up all objects like it.", ProfAndTipsX, 560 + 20 * line, BabyShibafont, Color.White); line++;
                                DrawCenteredTextAtPosition(_spriteBatch, "Shift click an architect to approach or attack.", ProfAndTipsX, 560 + 20 * line, BabyShibafont, Color.White); line++;
