                        void DrawAbilities(SpriteBatch spriteBatch, List<string> abilities, Vector2 startCoords, SpriteFont font, int indentSize)
                        {
                            int line = 0;

                            foreach (var ability in abilities)
                            {
                                string textToDraw = ability;
                                Vector2 indentCoords = new Vector2(startCoords.X, startCoords.Y + line * indentSize);
                                spriteBatch.DrawString(font, textToDraw, indentCoords, Color.LightCyan);
                                line++;
                            }
                        }


