                    float scale = 0.15f; // Use consistent scale for all clothing
                    int textureSize = 1000; // Your new base frame size
                    int scaledWidth = (int)(textureSize * scale);
                    int scaledHeight = (int)(textureSize * scale);

                    int boxSize = 30; // Button size for hide/dye

                    // --- Base position for this item ---
                    int baseX = (int)Position.X;
                    int baseY = (int)Position.Y + scaledHeight + 10; // Buttons below the sprite

                    // --- 1. Hide Button ---
                    Rectangle hideButton = new Rectangle(baseX, baseY, boxSize, boxSize);

                    // --- 2. Dye Buttons ---
                    List<Rectangle> dyeButtons = new List<Rectangle>();

                    baseY += boxSize; // Skip one row after hide button

