                void DrawRectangleOutline(SpriteBatch spriteBatch, Rectangle rect, Color color)
                {
                    spriteBatch.Draw(whiteRect, new Rectangle(rect.X, rect.Y, rect.Width, 1), color); // Top
                    spriteBatch.Draw(whiteRect, new Rectangle(rect.X, rect.Y + rect.Height - 1, rect.Width, 1), color); // Bottom
                    spriteBatch.Draw(whiteRect, new Rectangle(rect.X, rect.Y, 1, rect.Height), color); // Left
                    spriteBatch.Draw(whiteRect, new Rectangle(rect.X + rect.Width - 1, rect.Y, 1, rect.Height), color); // Right
                }

                ArchitectRects.Clear();

                // Correct X positions where columns meet
                int[] columnX = { 620, 1280, 1940 };
                int columnCount = 3; // Number of columns
                int[] columnY = { 360, 360, 360 };
                int currentColumn = 0;

                foreach (Architect a in Game1.GameWorld.GamePlayerAssociation.ActiveParty.Architects)
                {
                    string description = a.Name + (a.PartyActive ? " (Active)" : " (Inactive)");
                    Vector2 textSize = BabyShibafont.MeasureString(description);
                    int textHeight = (int)textSize.Y + 5;

                    bool TryingToExpunge = Keyboard.GetState().IsKeyDown(Keys.LeftShift) && Keyboard.GetState().IsKeyDown(Keys.LeftControl);

                    Rectangle? mergedRectangle = null;
                    Color baseColor = TryingToExpunge ? Color.Red : (a.PartyActive ? Color.White : Color.White * 0.5f);

                    if (textSize.X > 650)
                    {
                        List<string> lines = new List<string>();
                        string[] words = description.Split(' ');
                        string currentLine = "";

                        foreach (string word in words)
                        {
                            string testLine = currentLine.Length == 0 ? word : currentLine + " " + word;
                            if (BabyShibafont.MeasureString(testLine).X > 650)
                            {
                                lines.Add(currentLine);
                                currentLine = word;
                            }
                            else
                            {
                                currentLine = testLine;
                            }
                        }
                        if (currentLine.Length > 0) lines.Add(currentLine);

                        foreach (string line in lines)
                        {
                            Rectangle newRect = DrawCenteredTextAtPosition(_spriteBatch, line, columnX[currentColumn], columnY[currentColumn], BabyShibafont, baseColor);

                            if (mergedRectangle.HasValue)
                                mergedRectangle = Rectangle.Union(mergedRectangle.Value, newRect);
                            else
                                mergedRectangle = newRect;

                            columnY[currentColumn] += textHeight;
                        }
                    }
                    else
                    {
                        Rectangle newRect = DrawCenteredTextAtPosition(_spriteBatch, description, columnX[currentColumn], columnY[currentColumn], BabyShibafont, baseColor);
                        mergedRectangle = newRect;
                        columnY[currentColumn] += textHeight;
                    }

                    if (mergedRectangle.HasValue)
                    {
                        ArchitectRects.Add((mergedRectangle.Value, a, baseColor));
                    }

                    currentColumn = (currentColumn + 1) % columnCount;
                }

                foreach (var (rect, architect, color) in ArchitectRects)
                {
                    Color outline = architect.PartyActive ? Color.White : Color.White * 0.5f;
                    Color inner = architect.PartyActive ? Color.Gray : Color.Gray * 0.5f;

                    DrawRectangleOutline(_spriteBatch, new Rectangle(rect.X - 1, rect.Y - 1, rect.Width + 2, rect.Height + 2), inner);
                    DrawRectangleOutline(_spriteBatch, rect, outline);
                    DrawRectangleOutline(_spriteBatch, new Rectangle(rect.X + 1, rect.Y + 1, rect.Width - 2, rect.Height - 2), inner);
                }

                DrawCenteredText(_spriteBatch, "Click a party member to temporarily activate or deactivate them. They will wait patiently until reactivated.", 1110, Shibafont, Color.White);
                DrawCenteredText(_spriteBatch, "Ctrl+Shift+Click a party member to expel them from the party.", 1170, Shibafont, Color.White);
