                    var sortedImbuements = MostRecentPartyTurnArchitect.AllImbuements
                        .OrderBy(i => i.FirstPower) // Sort by FirstPower
                        .ThenBy(i => i.ConditionOrTrigger) // Then by ConditionOrTrigger alphabetically
                        .ToList();

                    foreach (Imbuement i in sortedImbuements)
