                        Color baseColor = i.IsTrigger ? Color.Goldenrod :
                                         (i.IsSatisfied ? Color.Lime : Color.White);

                        // Darken if inactive
                        if (!i.IsActive)
                        {
                            baseColor *= 0.5f;
                        }

                        // Outline color stays consistent with active status
                        Color outlineColor = i.IsActive ? Color.Gray : Color.Gray * 0.5f;


                        if (textSize.X > 650) // If text exceeds 650px width, split into multiple lines
                        {
                            List<string> lines = new List<string>();
