                                _spriteBatch.DrawString(BabyShibafont, "Total Architects: " + ArchitectPopulation, new Vector2(DrawX + 500, DrawY + 60), Color.White);

                                if (GameWorld.WorldMap[x + z * GameWorld.Width].Location.Government == null)
