            if (CompanionMessages.Count > 0 && !CompanionVoidGameStates.Contains(GameState))
            {
                OKCompanion.InvisibleLock = false;
                // Draw the background box
                Rectangle messageBox = new Rectangle(1913, 1180, 615, 137);
                _spriteBatch.Draw(CompGUIT, messageBox, Color.White);

                // Get center of the box
                float centerX = messageBox.Left + messageBox.Width / 2f;
                float centerY = messageBox.Top + messageBox.Height / 2f;

                string message = CompanionMessages[0];
                float buffer = 40f; // Horizontal padding buffer
                float maxLineWidth = messageBox.Width - buffer;

                List<string> lines = new List<string>();
                Vector2 fullSize = BabyShibafont.MeasureString(message);

                if (fullSize.X <= maxLineWidth)
                {
                    // Message fits in one line
                    lines.Add(message);
                }
                else
                {
                    // Split into multiple lines
                    string[] words = message.Split(' ');
                    string currentLine = "";

                    foreach (string word in words)
                    {
                        string testLine = string.IsNullOrEmpty(currentLine) ? word : currentLine + " " + word;
                        if (BabyShibafont.MeasureString(testLine).X <= maxLineWidth)
                        {
                            currentLine = testLine;
                        }
                        else
                        {
                            lines.Add(currentLine);
                            currentLine = word;
                        }
                    }

                    if (!string.IsNullOrEmpty(currentLine))
                        lines.Add(currentLine);
                }

                // Vertical spacing and centering
                float spacing = 20f;
                int lineCount = lines.Count;
                float totalOffset = (lineCount - 1) * spacing;
                float startY = centerY - totalOffset / 2f;

                for (int i = 0; i < lineCount; i++)
                {
                    float lineY = startY + i * spacing;
                    DrawCenteredTextAtPosition(_spriteBatch, lines[i], centerX, lineY, BabyShibafont, Color.White);
                }

                _spriteBatch.Draw(CuteGuyT, cuteguybox, MostRecentPartyTurnArchitect.CompanionColor != "nocomp" ? ColorConverter[MostRecentPartyTurnArchitect.CompanionColor] : Color.White);

